                                                                <!-- Tags -->
                                                                <div
                                                                    class="data-card"
                                                                >
                                                                    <div
                                                                        class="data-label"
                                                                    >
                                                                        Tags
                                                                    </div>
                                                                    <div
                                                                        class="data-value"
                                                                    >
                                                                        <!-- Display mode -->
                                                                        <template
                                                                            v-if="
                                                                                !isEditing
                                                                            "
                                                                        >
                                                                            <span
                                                                                v-if="
                                                                                    member.tags &&
                                                                                    member
                                                                                        .tags
                                                                                        .length >
                                                                                        0
                                                                                "
                                                                            >
                                                                                <span
                                                                                    v-for="tag in member.tags"
                                                                                    :key="
                                                                                        tag
                                                                                    "
                                                                                    class="tag-item-display"
                                                                                >
                                                                                    {{
                                                                                        tag
                                                                                    }}
                                                                                </span>
                                                                            </span>
                                                                            <span
                                                                                v-else
                                                                                >-</span
                                                                            >
                                                                        </template>

                                                                        <!-- Edit mode -->
                                                                        <template
                                                                            v-else
                                                                        >
                                                                            <div
                                                                                class="tags-input-container"
                                                                            >
                                                                                <div
                                                                                    class="tags-search"
                                                                                >
                                                                                    <input
                                                                                        v-model="
                                                                                            tagSearch
                                                                                        "
                                                                                        type="text"
                                                                                        class="tags-input"
                                                                                        placeholder="Type to search or create a tag"
                                                                                        @input="
                                                                                            filterTagSuggestions
                                                                                        "
                                                                                        @focus="
                                                                                            onTagInputFocus
                                                                                        "
                                                                                        @blur="
                                                                                            hideTagSuggestions
                                                                                        "
                                                                                        @keyup.enter="
                                                                                            handleTagEnter
                                                                                        "
                                                                                    />
                                                                                    <div
                                                                                        v-if="
                                                                                            showTagSuggestions &&
                                                                                            (filteredTagSuggestions.length >
                                                                                                0 ||
                                                                                                tagSearch.trim())
                                                                                        "
                                                                                        class="tag-suggestions-dropdown"
                                                                                    >
                                                                                        <!-- Existing tags from database -->
                                                                                        <div
                                                                                            v-for="(
                                                                                                tag,
                                                                                                index
                                                                                            ) in filteredTagSuggestions"
                                                                                            :key="
                                                                                                tag
                                                                                            "
                                                                                            :class="[
                                                                                                'tag-suggestion',
                                                                                                {
                                                                                                    highlighted:
                                                                                                        highlightedIndex ===
                                                                                                        index,
                                                                                                },
                                                                                            ]"
                                                                                            @click="
                                                                                                addTag(
                                                                                                    tag
                                                                                                )
                                                                                            "
                                                                                            @mouseenter="
                                                                                                highlightedIndex =
                                                                                                    index
                                                                                            "
                                                                                        >
                                                                                            <i
                                                                                                class="fas fa-tag"
                                                                                            ></i>
                                                                                            <span
                                                                                                >{{
                                                                                                    tag
                                                                                                }}</span
                                                                                            >
                                                                                        </div>

                                                                                        <!-- Option to create new tag if not found -->
                                                                                        <div
                                                                                            v-if="
                                                                                                tagSearch.trim() &&
                                                                                                !filteredTagSuggestions.includes(
                                                                                                    tagSearch.trim()
                                                                                                ) &&
                                                                                                (!member.tags ||
                                                                                                    !member.tags.includes(
                                                                                                        tagSearch.trim()
                                                                                                    ))
                                                                                            "
                                                                                            :class="[
                                                                                                'tag-suggestion',
                                                                                                'create-new',
                                                                                                {
                                                                                                    highlighted:
                                                                                                        highlightedIndex ===
                                                                                                        filteredTagSuggestions.length,
                                                                                                },
                                                                                            ]"
                                                                                            @click="
                                                                                                addTag()
                                                                                            "
                                                                                            @mouseenter="
                                                                                                highlightedIndex =
                                                                                                    filteredTagSuggestions.length
                                                                                            "
                                                                                        >
                                                                                            <i
                                                                                                class="fas fa-plus"
                                                                                            ></i>
                                                                                            <span
                                                                                                >Create
                                                                                                "{{
                                                                                                    tagSearch.trim()
                                                                                                }}"</span
                                                                                            >
                                                                                        </div>

                                                                                        <!-- Show message if no suggestions and no input -->
                                                                                        <div
                                                                                            v-if="
                                                                                                !tagSearch.trim() &&
                                                                                                filteredTagSuggestions.length ===
                                                                                                    0 &&
                                                                                                availableTags.length ===
                                                                                                    0
                                                                                            "
                                                                                            class="tag-suggestion no-tags"
                                                                                        >
                                                                                            <span
                                                                                                >No
                                                                                                tags
                                                                                                available.
                                                                                                Type
                                                                                                to
                                                                                                create
                                                                                                a
                                                                                                new
                                                                                                tag.</span
                                                                                            >
                                                                                        </div>
                                                                                    </div>
                                                                                </div>
                                                                                <div
                                                                                    v-if="
                                                                                        member.tags &&
                                                                                        member
                                                                                            .tags
                                                                                            .length >
                                                                                            0
                                                                                    "
                                                                                    class="tags-list"
                                                                                >
                                                                                    <span
                                                                                        v-for="tag in member.tags"
                                                                                        :key="
                                                                                            tag
                                                                                        "
                                                                                        class="tag-item"
                                                                                    >
                                                                                        {{
                                                                                            tag
                                                                                        }}
                                                                                        <i
                                                                                            class="fas fa-times remove-tag"
                                                                                            @click="
                                                                                                removeTag(
                                                                                                    tag
                                                                                                )
                                                                                            "
                                                                                        ></i>
                                                                                    </span>
                                                                                </div>
                                                                            </div>
                                                                        </template>
                                                                        <i
                                                                            class="fas fa-info-circle info-icon"
                                                                            title="Add tags to categorize this member"
                                                                        ></i>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>

