                                                                                }}</span
                                                                            >
                                                                            <button
                                                                                class="btn btn-link p-0 text-primary"
                                                                                @click="
                                                                                    toggleTextInput(
                                                                                        'emergency-contact',
                                                                                        coachingProfile.emergency_contact
                                                                                    )
                                                                                "
                                                                            >
                                                                                <i
                                                                                    class="fas fa-pencil-alt"
                                                                                ></i>
                                                                            </button>
                                                                        </div>
                                                                    </template>
                                                                    <button
                                                                        v-else
                                                                        class="btn btn-link p-0 text-primary d-flex align-items-center"
                                                                        @click="
                                                                            toggleTextInput(
                                                                                'emergency-contact'
                                                                            )
                                                                        "
                                                                    >
                                                                        <span
                                                                            class="mr-2 text-muted"
                                                                            >Click
                                                                            to
                                                                            add</span
                                                                        >
                                                                        <i
                                                                            class="fas fa-pencil-alt"
                                                                        ></i>
                                                                    </button>
                                                                </div>
                                                                <div
                                                                    v-if="
                                                                        showTextInputs[
                                                                            'emergency-contact'
                                                                        ]
                                                                    "
