                                                                                cancelTextInput(
                                                                                    'emergency-contact'
                                                                                )
                                                                            "
                                                                        >
                                                                            Cancel
                                                                        </button>
                                                                        <button
                                                                            class="btn btn-sm btn-primary"
                                                                            @click="
                                                                                saveTextInput(
                                                                                    'emergency-contact'
                                                                                )
                                                                            "
                                                                        >
                                                                            Save
                                                                        </button>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>

                                                    <!-- Emergency Phone Row -->
                                                    <div
