                                                                >Emergency
                                                                Phone</label
                                                            >
                                                            <div
                                                                class="d-flex align-items-center"
                                                            >
                                                                <div
                                                                    v-if="
                                                                        !showTextInputs[
                                                                            'emergency-phone'
                                                                        ]
                                                                    "
