                                                                >Start
                                                                date</label
                                                            >
                                                            <span class="mb-0"
                                                                >-</span
                                                            >
                                                        </div>
                                                    </div>

                                                    <!-- End date (Training Plan) Row (with grey background) -->
                                                    <div
                                                        class="form-group mb-3"
                                                    >
                                                        <div
                                                            class="bg-light rounded p-3 d-flex align-items-center justify-content-between"
                                                        >
                                                            <label
