                                                            >
                                                            <span class="mb-0"
                                                                >-</span
                                                            >
                                                        </div>
                                                    </div>

                                                    <!-- Nutrition Plan Row (white background) -->
                                                    <div
                                                        class="form-group mb-3"
                                                    >
                                                        <div
                                                            class="d-flex align-items-center justify-content-between"
                                                        >
                                                            <label
                                                                class="mb-0 font-weight-medium"
                                                                >Nutrition
