                                                                    Manager
                                                                </option>
                                                                <option
                                                                    v-for="manager in availableAccountManagers"
                                                                    :key="
                                                                        manager.id
                                                                    "
                                                                    :value="
                                                                        manager.id
                                                                    "
                                                                >
                                                                    {{
                                                                        manager.name
                                                                    }}
                                                                </option>
                                                            </select>
