                                                                        "
                                                                        :class="{
                                                                            'opacity-50':
                                                                                isRemovingCoach ===
                                                                                coach.id,
                                                                        }"
                                                                    ></i>
                                                                </span>
                                                                <button
                                                                    v-if="assignedCoaches.length === 0"
                                                                    class="btn btn-link p-0 text-primary"
                                                                    @click="
                                                                        showCoachModal = true
                                                                    "
                                                                    :disabled="
                                                                        isSavingCoach
                                                                    "
                                                                >
                                                                    <i
                                                                        class="fas fa-plus"
                                                                    ></i>
                                                                </button>
                                                            </div>
                                                        </div>
                                                        <p
                                                            v-if="
                                                                assignedCoaches.length ===
                                                                0
                                                            "
                                                            class="text-muted small mt-2 mb-0"
                                                        >
                                                            No coach assigned.
                                                            Click + to assign a
                                                            coach.
                                                        </p>
                                                    </div>
                                                </div>
                                            </div>

                                            <!-- Coach Selection Modal -->
                                            <div
                                                v-if="showCoachModal"
                                                class="modal-overlay"
                                                @click="showCoachModal = false"
                                            >
                                                <div
                                                    class="modal-content"
                                                    @click.stop
                                                >
                                                    <div class="modal-header">
                                                        <h4
                                                            class="d-flex align-items-center"
                                                        >
                                                            <i
                                                                class="fas fa-user-tie mr-2 text-primary"
                                                            ></i>
                                                            Select Coach
                                                        </h4>
                                                        <button
                                                            class="modal-close"
                                                            @click="
                                                                showCoachModal = false
                                                            "
                                                        >
                                                            <i
                                                                class="fas fa-times"
                                                            ></i>
                                                        </button>
                                                    </div>
                                                    <div class="modal-body">
                                                        <div
                                                            class="coach-search"
                                                        >
                                                            <input
                                                                type="text"
                                                                v-model="
                                                                    coachSearchQuery
                                                                "
                                                                placeholder="Search coaches..."
                                                                class="form-control"
                                                            />
                                                        </div>
                                                        <div
                                                            class="coach-list"
                                                            v-if="
                                                                filteredAvailableCoaches.length >
                                                                0
                                                            "
                                                        >
                                                            <div
                                                                v-for="coach in filteredAvailableCoaches"
                                                                :key="coach.id"
                                                                class="coach-item"
                                                                @click="
                                                                    assignCoach(
                                                                        coach
                                                                    )
                                                                "
                                                            >
                                                                <div
                                                                    class="coach-info"
                                                                >
                                                                    <strong>{{
                                                                        coach.name
                                                                    }}</strong>
                                                                    <span
                                                                        v-if="
                                                                            coach.specialization
                                                                        "
                                                                        class="coach-spec"
                                                                        >{{
                                                                            coach.specialization
                                                                        }}</span
                                                                    >
                                                                </div>
                                                                <i
                                                                    class="fas fa-plus"
                                                                ></i>
                                                            </div>
                                                        </div>
                                                        <p
                                                            v-else
                                                            class="no-coaches-text"
                                                        >
                                                            No coaches available
                                                        </p>
                                                    </div>
                                                </div>
