                                            <!-- Last Visits Section -->
                                            <div class="coaching-section mb-4">
                                                <div class="section-header">
                                                    <h3
                                                        class="section-title d-flex align-items-center"
                                                    >
                                                        <i
                                                            class="fas fa-history mr-2 text-primary"
                                                        ></i>
                                                        Last visits
                                                    </h3>
                                                </div>
                                                <div class="table-responsive">
                                                    <table
                                                        class="table table-hover mb-0"
                                                    >
                                                        <thead>
                                                            <tr>
                                                                <th
                                                                    class="font-weight-bold"
                                                                >
                                                                    Checked In
                                                                </th>
                                                                <th
                                                                    class="font-weight-bold"
                                                                >
                                                                    Check Out
                                                                </th>
                                                                <th
                                                                    class="font-weight-bold"
                                                                >
                                                                    Location
                                                                </th>
                                                                <th
                                                                    class="font-weight-bold"
                                                                >
                                                                    Message
                                                                </th>
                                                            </tr>
                                                        </thead>
                                                        <tbody>
                                                            <tr
                                                                v-if="
                                                                    isLoadingCheckIns
                                                                "
                                                            >
                                                                <td
                                                                    colspan="4"
                                                                    class="text-center py-4"
                                                                >
                                                                    <i
                                                                        class="fas fa-spinner fa-spin mr-2"
                                                                    ></i>
                                                                    Loading
                                                                    check-ins...
                                                                </td>
                                                            </tr>
                                                            <tr
                                                                v-else-if="
                                                                    checkIns.length >
                                                                    0
                                                                "
                                                                v-for="(
                                                                    checkIn,
                                                                    index
                                                                ) in checkIns"
                                                                :key="
                                                                    checkIn.id
                                                                "
                                                                :class="{
                                                                    'table-light':
                                                                        index %
                                                                            2 ===
                                                                        0,
                                                                }"
                                                            >
                                                                <td>
                                                                    {{
                                                                        formatCheckInTime(
                                                                            checkIn.check_in_time
                                                                        )
                                                                    }}
                                                                </td>
                                                                <td>
                                                                    {{
                                                                        checkIn.check_out_time
                                                                            ? formatCheckInTime(
                                                                                  checkIn.check_out_time
                                                                              )
                                                                            : "-"
                                                                    }}
                                                                </td>
                                                                <td>
                                                                    {{
                                                                        checkIn.location ||
                                                                        "-"
                                                                    }}
                                                                </td>
                                                                <td>
                                                                    {{
