                                                                                        .first_name ||
                                                                                    ""
                                                                                }}
                                                                                {{
                                                                                    assignment
                                                                                        .assigned_by
                                                                                        .lastname ||
                                                                                    assignment
                                                                                        .assigned_by
                                                                                        .last_name ||
                                                                                    ""
                                                                                }}</span
                                                                            >
                                                                        </div>
                                                                        <div
