                                                <div
                                                    v-if="isLoadingChallenges"
                                                    class="text-center py-4"
                                                >
                                                    <div
                                                        class="spinner-border text-primary"
                                                        role="status"
                                                    >
                                                        <span class="sr-only"
                                                            >Loading
                                                            challenges...</span
                                                        >
                                                    </div>
                                                    <p class="mt-2 text-muted">
                                                        Loading challenges...
                                                    </p>
                                                </div>

                                                <!-- No Challenges -->
                                                <div
                                                    v-else-if="
                                                        challenges.length === 0
                                                    "
                                                    class="no-challenges"
                                                >
                                                    <div
                                                        class="text-center py-5"
                                                    >
                                                        <i
                                                            class="fas fa-trophy text-muted"
                                                            style="
                                                                font-size: 3rem;
                                                            "
                                                        ></i>
                                                        <h5
                                                            class="mt-3 text-muted"
                                                        >
                                                            No Challenges Found
                                                        </h5>
                                                        <p class="text-muted">
                                                            This member hasn't
                                                            participated in any
                                                            challenges yet.
                                                        </p>
                                                    </div>
                                                </div>

                                                <!-- Challenges List -->
                                                <div
                                                    v-else
                                                    class="challenges-list"
