                                                        :key="challenge.id"
                                                    >
                                                        <div
                                                            class="challenge-card"
                                                        >
                                                            <div
                                                                class="challenge-header"
                                                            >
                                                                <div
                                                                    class="challenge-title"
                                                                >
                                                                    <i
                                                                        class="fas fa-trophy"
                                                                    ></i>
                                                                    <span>{{
                                                                        challenge.challenge_name
                                                                    }}</span>
                                                                </div>
                                                                <div
                                                                    class="challenge-status"
                                                                    :class="
                                                                        'status-' +
                                                                        challenge.status
                                                                    "
                                                                >
                                                                    {{
                                                                        challenge.status
                                                                    }}
                                                                </div>
                                                            </div>
                                                            <div
                                                                class="challenge-body"
                                                            >
                                                                <div
                                                                    class="challenge-description"
                                                                >
                                                                    <i
                                                                        class="fas fa-info-circle"
                                                                    ></i>
                                                                    <span>{{
                                                                        challenge.challenge_description
                                                                    }}</span>
                                                                </div>
                                                                <div
                                                                    class="challenge-goal"
                                                                >
                                                                    <i
                                                                        class="fas fa-target"
                                                                    ></i>
                                                                    <span>{{
