                                                                >
                                                                    <i
                                                                        class="fas fa-calendar"
                                                                    ></i>
                                                                    <span
                                                                        >{{
                                                                            formatDate(
                                                                                challenge.start_date
                                                                            )
                                                                        }}
                                                                        -
                                                                        {{
                                                                            formatDate(
                                                                                challenge.end_date
                                                                            )
                                                                        }}</span
                                                                    >
                                                                </div>
                                                                <div
                                                                    class="challenge-progress"
                                                                >
                                                                    <i
                                                                        class="fas fa-chart-line"
                                                                    ></i>
                                                                    <span
                                                                        >Progress:
                                                                        {{
                                                                            challenge.progress ||
                                                                            0
                                                                        }}%</span
                                                                    >
