                                                                            class="progress-fill"
                                                                            :style="{
                                                                                width:
                                                                                    (challenge.progress ||
                                                                                        0) +
                                                                                    '%',
                                                                            }"
                                                                        ></div>
                                                                    </div>
                                                                </div>
                                                                <div
                                                                    class="challenge-reward"
                                                                >
                                                                    <i
                                                                        class="fas fa-gift"
                                                                    ></i>
                                                                    <span>{{
                                                                        challenge.reward_name
                                                                    }}</span>
                                                                </div>
                                                                <div
                                                                    v-if="
                                                                        challenge.last_activity
                                                                    "
                                                                    class="challenge-activity"
                                                                >
                                                                    <i
                                                                        class="fas fa-clock"
                                                                    ></i>
                                                                    <span
                                                                        >Last
                                                                        activity:
                                                                        {{
                                                                            formatDate(
                                                                                challenge.last_activity
                                                                            )
                                                                        }}</span
                                                                    >
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <!-- Send Message Content -->
        <div v-if="activeAction === 'sendMessage'" class="message-content">
            <div class="message-header">
                <button
                    @click="activeView = 'compose'"
                    class="new-message-btn"
                    v-if="activeView === 'inbox'"
                >
                    <i class="fas fa-plus"></i>
                    New Message
                </button>
            </div>

            <div v-if="activeView === 'compose'" class="compose-form">
                <form @submit.prevent="sendMessage" class="message-form">
                    <div class="form-group">
                        <label class="form-label">Recipients</label>
                        <input
                            type="text"
                            v-model="newMessage.recipients"
                            placeholder="Enter recipients"
                            class="form-control"
                        />
                    </div>
                    <div class="form-group">
                        <label class="form-label">Subject</label>
                        <input
                            type="text"
                            v-model="newMessage.subject"
                            placeholder="Enter subject"
                            class="form-control"
                        />
                    </div>
                    <div class="form-group">
                        <label class="form-label">Message</label>
                        <textarea
                            v-model="newMessage.body"
                            placeholder="Write your message here..."
                            class="form-control"
                            rows="5"
                        ></textarea>
                    </div>
                    <div class="form-actions">
                        <button
                            type="button"
                            @click="activeView = 'inbox'"
                            class="cancel-btn"
                        >
                            Cancel
                        </button>
                        <button type="submit" class="submit-btn">
                            <i class="fas fa-paper-plane"></i>
                            Send Message
                        </button>
                    </div>
                </form>
            </div>
        </div>

        <!-- Assign to Trainer Content -->
        <div
            v-if="activeAction === 'assignTrainer'"
            class="assign-trainer-content"
        >
            <div class="alert alert-info mb-4">
                <i class="fas fa-info-circle"></i>
                <span v-if="hasExistingTrainerAssignment">
                    <strong>Existing Assignment:</strong>
                    This member already has a trainer assigned. You can update
                    the assignment details below.
                </span>
                <span v-else>
                    Assign this member to a personal trainer for personalized
                    fitness guidance.
                </span>
            </div>

            <form @submit.prevent="assignTrainer" class="assign-trainer-form">
                <div class="row g-4">
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label">Select Trainer</label>
                            <select
                                v-model="trainerData.trainerId"
                                class="form-control"
                                required
                                :disabled="isLoadingTrainers"
                            >
                                <option value="">
                                    {{
                                        isLoadingTrainers
                                            ? "Loading trainers..."
                                            : "Select a Trainer"
                                    }}
                                </option>
                                <option
                                    v-for="trainer in availableTrainers"
                                    :key="trainer.id"
                                    :value="trainer.id"
                                >
                                    {{ trainer.name }}
                                    -
                                    {{ trainer.specialization }}
                                </option>
                            </select>
                            <div
                                v-if="isLoadingTrainers"
                                class="loading-indicator"
                            >
                                <small class="text-muted">
                                    <i class="fas fa-spinner fa-spin"></i>
                                    Loading trainers...
                                </small>
                            </div>
                            <div
                                v-else-if="availableTrainers.length === 0"
                                class="no-trainers"
                            >
                                <small class="text-muted">
                                    <i class="fas fa-exclamation-triangle"></i>
                                    No trainers available
                                </small>
                            </div>
                        </div>
                    </div>
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label">Assignment Date</label>
                            <input
                                v-model="trainerData.assigned_date"
                                type="date"
                                class="form-control"
                                required
                            />
                        </div>
                    </div>
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label">Session Frequency</label>
                            <select
                                v-model="trainerData.sessionFrequency"
                                class="form-control"
                                required
                            >
                                <option value="">Select Frequency</option>
                                <option value="weekly-1">
                                    1 session per week
                                </option>
                                <option value="weekly-2">
                                    2 sessions per week
                                </option>
                                <option value="weekly-3">
                                    3 sessions per week
                                </option>
                                <option value="weekly-4">
                                    4+ sessions per week
                                </option>
                            </select>
                        </div>
                    </div>
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label">Session Duration</label>
                            <select
                                v-model="trainerData.sessionDuration"
                                class="form-control"
                                required
                            >
                                <option value="">Select Duration</option>
                                <option value="30">30 minutes</option>
                                <option value="45">45 minutes</option>
                                <option value="60">60 minutes</option>
                                <option value="90">90 minutes</option>
                            </select>
                        </div>
                    </div>
                    <div class="col-12">
                        <div class="form-group">
                            <label class="form-label">Fitness Goals</label>
                            <textarea
                                v-model="trainerData.goals"
                                class="form-control"
                                rows="4"
                                placeholder="Describe the member's fitness goals and objectives"
                                required
                            ></textarea>
                        </div>
                    </div>
                    <div class="col-12">
                        <div class="form-group">
                            <label class="form-label"
                                >Special Requirements</label
                            >
                            <textarea
                                v-model="trainerData.specialRequirements"
                                class="form-control"
                                rows="3"
                                placeholder="Any special requirements, injuries, or considerations"
                            ></textarea>
                        </div>
                    </div>
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label">Start Date</label>
                            <input
                                v-model="trainerData.startDate"
                                type="date"
                                class="form-control"
                                required
                            />
                        </div>
                    </div>
                    <div class="col-md-6">
                        <div class="form-group">
                            <label class="form-label"
                                >End Date (Optional)</label
                            >
                            <input
                                v-model="trainerData.endDate"
                                type="date"
                                class="form-control"
                            />
                        </div>
                    </div>
                </div>
                <div class="form-actions">
                    <button
                        type="button"
                        @click="cancelTrainerAssignment"
                        class="cancel-btn"
                    >
                        Cancel
                    </button>
                    <button type="submit" class="submit-btn">
                        <i class="fas fa-user-plus"></i>
                        {{
                            hasExistingTrainerAssignment
                                ? "Update Assignment"
                                : "Assign Trainer"
                        }}
                    </button>
                </div>
            </form>
        </div>

        <!-- Unsubscribe Modal -->
        <div
            v-if="activeAction === 'unSubscribe'"
            class="modal-overlay"
            @click="closeUnsubscribeModal"
        >
            <div class="modal-content unsubscribe-modal" @click.stop>
                <div class="modal-header">
                    <h3 class="modal-title">
                        <i class="fas fa-user-times"></i>
                        Unsubscribe Member
                    </h3>
                    <button class="close-btn" @click="closeUnsubscribeModal">
                        <i class="fas fa-times"></i>
                    </button>
                </div>

                <div class="modal-body">
                    <!-- Unsubscribe Status Alert -->
                    <div v-if="isUnsubscribed" class="alert alert-info mb-4">
                        <i class="fas fa-info-circle"></i>
                        <strong>Member Status:</strong> This member is currently
                        unsubscribed.
                        <button
                            @click="toggleUnsubscribeEdit"
                            class="btn btn-sm btn-outline-primary ms-3"
                        >
                            <i class="fas fa-edit"></i>
                            {{
                                isEditingUnsubscribe
                                    ? "Cancel Edit"
                                    : "Edit/Resubscribe"
                            }}
                        </button>
                    </div>

                    <div v-else class="alert alert-warning mb-4">
                        <i class="fas fa-exclamation-triangle"></i>
                        <strong>Warning:</strong> This action will unsubscribe
                        the member from all services.
                    </div>

                    <!-- Unsubscribe History Display -->
                    <div
                        v-if="
                            isUnsubscribed &&
                            !isEditingUnsubscribe &&
                            unsubscribeHistory
                        "
                        class="unsubscribe-history mb-4"
                    >
                        <div class="card">
                            <div class="card-header">
                                <h6 class="mb-0">
                                    <i class="fas fa-history"></i>
                                    Unsubscribe Details
                                </h6>
                            </div>
                            <div class="card-body">
                                <div class="row">
                                    <div class="col-md-6">
                                        <div class="info-group">
                                            <label class="info-label"
                                                >Unsubscribe Type</label
                                            >
                                            <div class="info-value">
                                                {{ unsubscribeHistory.type }}
                                            </div>
                                        </div>
                                    </div>
                                    <div class="col-md-6">
                                        <div class="info-group">
                                            <label class="info-label"
                                                >Effective Date</label
                                            >
                                            <div class="info-value">
                                                {{
                                                    formatDate(
                                                        unsubscribeHistory.effectiveDate
                                                    )
                                                }}
                                            </div>
                                        </div>
                                    </div>
                                    <div class="col-md-6">
                                        <div class="info-group">
                                            <label class="info-label"
                                                >Reason</label
                                            >
                                            <div class="info-value">
                                                {{ unsubscribeHistory.reason }}
                                            </div>
                                        </div>
                                    </div>
                                    <div class="col-md-6">
                                        <div class="info-group">
                                            <label class="info-label"
                                                >Refund Option</label
                                            >
                                            <div class="info-value">
                                                {{
                                                    unsubscribeHistory.refundOption
                                                }}
                                            </div>
                                        </div>
                                    </div>
                                    <div
                                        class="col-12"
                                        v-if="unsubscribeHistory.comments"
                                    >
                                        <div class="info-group">
                                            <label class="info-label"
                                                >Comments</label
                                            >
                                            <div class="info-value">
                                                {{
                                                    unsubscribeHistory.comments
                                                }}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <!-- Unsubscribe Form - Show when not unsubscribed or when editing -->
                    <form
                        v-if="!isUnsubscribed || isEditingUnsubscribe"
                        @submit.prevent=""
                        class="unsubscribe-form"
                    >
                        <div class="row g-4">
                            <div class="col-md-6">
                                <div class="form-group">
                                    <label class="form-label"
                                        >Unsubscribe Type</label
                                    >
                                    <select
                                        v-model="unsubscribeData.type"
                                        class="form-control"
                                        required
                                    >
                                        <option value="">Select Type</option>
                                        <option value="immediate">
                                            Immediate
                                        </option>
                                        <option value="end-of-period">
                                            End of Current Period
                                        </option>
                                        <option value="specific-date">
                                            Specific Date
                                        </option>
                                    </select>
                                </div>
                            </div>
                            <div
                                class="col-md-6"
                                v-if="unsubscribeData.type === 'specific-date'"
                            >
                                <div class="form-group">
                                    <label class="form-label"
                                        >Effective Date</label
                                    >
                                    <input
                                        v-model="unsubscribeData.effectiveDate"
                                        type="date"
                                        class="form-control"
                                        required
                                    />
                                </div>
                            </div>
                            <div class="col-12">
                                <div class="form-group">
                                    <label class="form-label"
                                        >Reason for Unsubscribing</label
                                    >
                                    <select
                                        v-model="unsubscribeData.reason"
                                        class="form-control"
                                        required
                                    >
                                        <option value="">Select Reason</option>
                                        <option value="financial">
                                            Financial Reasons
                                        </option>
                                        <option value="relocation">
                                            Relocation
                                        </option>
                                        <option value="health">
                                            Health Issues
                                        </option>
                                        <option value="dissatisfaction">
                                            Dissatisfaction with Service
                                        </option>
                                        <option value="personal">
                                            Personal Reasons
                                        </option>
                                        <option value="other">Other</option>
                                    </select>
                                </div>
                            </div>
                            <div class="col-12">
                                <div class="form-group">
                                    <label class="form-label"
                                        >Additional Comments</label
                                    >
                                    <textarea
                                        v-model="unsubscribeData.comments"
                                        class="form-control"
                                        rows="4"
                                        placeholder="Any additional comments or feedback"
                                    ></textarea>
                                </div>
                            </div>
                            <div class="col-12">
                                <div class="form-group">
                                    <label class="form-label"
                                        >Refund Options</label
                                    >
                                    <select
                                        v-model="unsubscribeData.refundOption"
                                        class="form-control"
                                        required
                                    >
                                        <option value="">
                                            Select Refund Option
                                        </option>
                                        <option value="full-refund">
                                            Full Refund
                                        </option>
                                        <option value="partial-refund">
                                            Partial Refund (Pro-rated)
                                        </option>
                                        <option value="credit">
                                            Credit for Future Services
                                        </option>
                                        <option value="no-refund">
                                            No Refund
                                        </option>
                                    </select>
                                </div>
                            </div>
                        </div>
                        <div class="form-actions">
                            <button
                                type="button"
                                @click="closeUnsubscribeModal"
                                class="btn btn-secondary cancel-btn"
                            >
                                Cancel
                            </button>
                            <button
                                v-if="!isUnsubscribed"
                                type="button"
                                @click="processUnsubscribe"
                                class="btn btn-primary"
                                :disabled="
                                    !unsubscribeData.type ||
                                    !unsubscribeData.reason ||
                                    !unsubscribeData.refundOption
                                "
                            >
                                <i class="fas fa-user-times"></i>
                                Unsubscribe Member
                            </button>
                            <template v-else>
                                <button
                                    v-if="isEditingUnsubscribe"
                                    type="button"
                                    @click="updateUnsubscribe"
                                    class="btn btn-primary"
                                    :disabled="
                                        !unsubscribeData.type ||
                                        !unsubscribeData.reason ||
                                        !unsubscribeData.refundOption
                                    "
                                >
                                    <i class="fas fa-save"></i>
                                    Update Unsubscribe
                                </button>
                                <button
                                    v-if="isEditingUnsubscribe"
                                    type="button"
                                    @click="resubscribeMember"
                                    class="btn btn-success"
                                >
                                    <i class="fas fa-user-check"></i>
                                    Resubscribe Member
                                </button>
                            </template>
                        </div>
                    </form>
                </div>
            </div>
        </div>

        <!-- Convert to Coach Modal -->
        <div
            v-if="showConvertToCoachModal"
            class="modal-overlay"
            @click="closeConvertToCoachModal"
        >
            <div class="modal-content convert-coach-modal" @click.stop>
                <div class="modal-header">
                    <h3 class="modal-title">
                        <i class="fas fa-user-tie"></i>
                        Convert Member to Coach
                    </h3>
                    <button class="close-btn" @click="closeConvertToCoachModal">
                        <i class="fas fa-times"></i>
                    </button>
                </div>

                <div class="modal-body">
                    <div class="alert alert-info mb-4">
                        <i class="fas fa-info-circle"></i>
                        <strong>Convert Member to Coach:</strong> This will
                        convert the member to a coach role and they will appear
                        in the coach list.
                    </div>

                    <form
                        @submit.prevent="convertToCoach"
                        class="convert-coach-form"
                    >
                        <div class="form-grid">
                            <!-- Left Column -->
                            <div class="form-column">
                                <div class="form-section compact">
                                    <div class="section-header compact">
                                        <h5 class="section-title compact">
                                            Coach Information
                                        </h5>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Coach Type *</label
                                        >
                                        <div class="input-container">
                                            <select
                                                v-model="
                                                    coachConversionData.coach_type
                                                "
                                                class="form-select"
                                                required
                                            >
                                                <option value="">
                                                    Select Coach Type
                                                </option>
                                                <option
                                                    value="Personal Trainer"
                                                >
                                                    Personal Trainer
                                                </option>
                                                <option
                                                    value="Group Fitness Instructor"
                                                >
                                                    Group Fitness Instructor
                                                </option>
                                                <option value="Yoga Instructor">
                                                    Yoga Instructor
                                                </option>
                                                <option
                                                    value="Pilates Instructor"
                                                >
                                                    Pilates Instructor
                                                </option>
                                                <option value="Nutrition Coach">
                                                    Nutrition Coach
                                                </option>
                                                <option value="Strength Coach">
                                                    Strength Coach
                                                </option>
                                                <option value="Cardio Coach">
                                                    Cardio Coach
                                                </option>
                                            </select>
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Select the type of coach this member will become"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Experience Level *</label
                                        >
                                        <div class="input-container">
                                            <select
                                                v-model="
                                                    coachConversionData.coach_experience
                                                "
                                                class="form-select"
                                                required
                                            >
                                                <option value="">
                                                    Select Experience Level
                                                </option>
                                                <option value="Beginner">
                                                    Beginner (0-1 years)
                                                </option>
                                                <option value="Intermediate">
                                                    Intermediate (2-5 years)
                                                </option>
                                                <option value="Advanced">
                                                    Advanced (6-10 years)
                                                </option>
                                                <option value="Expert">
                                                    Expert (10+ years)
                                                </option>
                                            </select>
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Select the experience level of the coach"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Years of Experience *</label
                                        >
                                        <div class="input-container">
                                            <input
                                                v-model="
                                                    coachConversionData.years_of_experience
                                                "
                                                type="number"
                                                class="form-input"
                                                placeholder="Enter years of experience"
                                                min="0"
                                                max="50"
                                                required
                                            />
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Enter the number of years of coaching experience"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Certifications</label
                                        >
                                        <div class="input-container">
                                            <textarea
                                                v-model="
                                                    coachConversionData.coach_certifications
                                                "
                                                class="form-textarea"
                                                placeholder="Enter certifications (e.g., NASM-CPT, ACE-CPT)"
                                                rows="3"
                                            ></textarea>
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="List any professional certifications or credentials"
                                            ></i>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <!-- Right Column -->
                            <div class="form-column">
                                <div class="form-section compact">
                                    <div class="section-header compact">
                                        <h5 class="section-title compact">
                                            Availability & Settings
                                        </h5>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Weekly Availability *</label
                                        >
                                        <div class="input-container">
                                            <select
                                                v-model="
                                                    coachConversionData.weekly_availability
                                                "
                                                class="form-select"
                                                required
                                            >
                                                <option value="">
                                                    Select Availability
                                                </option>
                                                <option value="Monday-Friday">
                                                    Monday-Friday
                                                </option>
                                                <option value="Weekends Only">
                                                    Weekends Only
                                                </option>
                                                <option value="Monday-Sunday">
                                                    Monday-Sunday
                                                </option>
                                                <option value="Flexible">
                                                    Flexible
                                                </option>
                                            </select>
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Select the coach's weekly availability schedule"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Session Duration (minutes) *</label
                                        >
                                        <div class="input-container">
                                            <input
                                                v-model="
                                                    coachConversionData.session_duration
                                                "
                                                type="number"
                                                class="form-input"
                                                placeholder="60"
                                                min="30"
                                                max="180"
                                                step="15"
                                                required
                                            />
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Set the duration of coaching sessions in minutes"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label"
                                            >Max members Per Day *</label
                                        >
                                        <div class="input-container">
                                            <input
                                                v-model="
                                                    coachConversionData.max_members_per_day
                                                "
                                                type="number"
                                                class="form-input"
                                                placeholder="8"
                                                min="1"
                                                max="20"
                                                required
                                            />
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Set the maximum number of members the coach can handle per day"
                                            ></i>
                                        </div>
                                    </div>

                                    <div class="form-group">
                                        <label class="form-label">Bio</label>
                                        <div class="input-container">
                                            <textarea
                                                v-model="
                                                    coachConversionData.bio
                                                "
                                                class="form-textarea"
                                                placeholder="Enter coach bio and background"
                                                rows="4"
                                            ></textarea>
                                            <i
                                                class="fas fa-info-circle info-icon"
                                                title="Enter a brief bio and background information about the coach"
                                            ></i>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </form>
                </div>

                <div class="modal-footer">
                    <button
                        type="button"
                        @click="closeConvertToCoachModal"
                        class="cancel-btn"
                    >
                        <!-- <i class="fas fa-times"></i> -->
                        Cancel
                    </button>
                    <button
                        type="button"
                        @click="convertToCoach"
                        class="submit-btn"
                        :disabled="isConverting"
                    >
                        <i class="fas fa-user-tie"></i>
                        {{
                            isConverting ? "Converting..." : "Convert to Coach"
                        }}
                    </button>
                </div>
            </div>
        </div>

        <!-- Appointment Modal -->
        <div
            v-if="showAppointmentModal"
            class="appointment-modal-backdrop"
            @click="handleModalBackdropClick"
        >
            <div class="appointment-modal-box" @click.stop>
                <div class="appointment-modal-header">
                    <h3 class="appointment-modal-title">
                        {{
                            isEditingAppointment
                                ? "Edit Gym Appointment"
                                : "Set Gym Appointment"
                        }}
                    </h3>
                </div>
                <form
                    @submit.prevent="saveAppointment"
                    class="appointment-modal-form"
                >
                    <!-- Date -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Date:</label>
                        <input
                            type="date"
                            v-model="appointmentDate"
                            class="form-control"
                            required
                        />
                    </div>

                    <!-- Start Time -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold"
                            >Start Time:</label
                        >
                        <input
                            type="time"
                            v-model="appointmentStartTime"
                            class="form-control"
                            required
                        />
                    </div>

                    <!-- End Time -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold">End Time:</label>
                        <input
                            type="time"
                            v-model="appointmentEndTime"
                            class="form-control"
                            required
                        />
                    </div>

                    <!-- Staff -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Coach:</label>
                        <select
                            v-model="selectedStaffId"
                            class="form-control"
                            required
                        >
                            <option value="" disabled>Select staff</option>
                            <option
                                v-for="member in appointmentStaff"
                                :key="member.id"
                                :value="member.id"
                            >
                                {{ member.name }}
                            </option>
                        </select>
                    </div>

                    <!-- Client (pre-filled with current member) -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Member:</label>
                        <select
                            v-model="selectedClientId"
                            class="form-control"
                            required
                        >
                            <option :value="member.id">
                                {{ member.first_name }} {{ member.last_name }}
                            </option>
                        </select>
                    </div>

                    <!-- Workout Type -->
                    <div class="mb-3">
                        <label class="form-label fw-semibold"
                            >Workout Type:</label
                        >
                        <select
                            v-model="workoutType"
                            class="form-control"
                            required
                        >
                            <option value="" disabled>
                                Select Workout Type
                            </option>
                            <option
                                v-for="type in appointmentWorkouts"
                                :key="type.id"
                                :value="type.id"
                            >
                                {{ type.label }}
                            </option>
                        </select>
                    </div>

                    <!-- Buttons -->
                    <div class="appointment-modal-actions d-flex gap-2">
                        <button
                            type="submit"
                            class="btn btn-primary flex-fill"
                            :disabled="savingAppointment"
                        >
                            <span v-if="savingAppointment">
                                <i class="fas fa-spinner fa-spin me-2"></i>
                                {{
                                    isEditingAppointment
                                        ? "Updating..."
                                        : "Saving..."
                                }}
                            </span>
                            <span v-else>{{
                                isEditingAppointment ? "Update" : "Save"
                            }}</span>
                        </button>
                        <button
                            type="button"
                            class="btn btn-secondary flex-fill"
                            @click="closeAppointmentModal"
                            :disabled="savingAppointment"
                        >
                            Cancel
                        </button>
                    </div>
                </form>
            </div>
        </div>

        <!-- New Task Modal -->
        <div v-if="activeAction === 'newTask'" class="new-task-modal">
            <div class="modal-overlay" @click="closeNewTaskModal"></div>
            <div class="modal-content" @click.stop>
                <div class="modal-header">
                    <h3 class="modal-title">
                        {{
                            newTask.task && newTask.task.trim()
                                ? newTask.task.trim()
                                : "New task"
                        }}
                        - Concerns {{ member.first_name }}
                        {{ member.last_name }}
                    </h3>
                    <button class="close-btn" @click="closeNewTaskModal">
                        <i class="fas fa-times"></i>
                    </button>
                </div>

                <div class="modal-body">
                    <div class="form-group">
                        <label class="form-label"
                            >Task Name
                            <span class="required-asterisk">*</span></label
                        >
                        <div class="input-container">
                            <input
                                v-model="newTask.task"
                                type="text"
                                class="form-input"
                                :class="{ 'is-invalid': taskFieldErrors.task }"
                                placeholder="Enter task name (e.g., Follow up with member, Schedule assessment)"
                                required
                                @input="
                                    taskFieldErrors.task &&
                                        delete taskFieldErrors.task
                                "
                            />
                            <i
                                class="fas fa-info-circle info-icon"
                                title="Enter a brief description of the task"
                            ></i>
                        </div>
                        <div
                            v-if="taskFieldErrors.task"
                            class="task-field-error"
                        >
                            {{ taskFieldErrors.task }}
                        </div>
                    </div>

                    <div class="form-group">
                        <label class="form-label"
                            >Category
                            <span class="required-asterisk">*</span></label
                        >
                        <div class="input-container">
                            <select
                                v-model="newTask.category"
                                class="form-select"
                                :class="{
                                    'is-invalid': taskFieldErrors.category,
                                }"
                                required
                                @change="
                                    taskFieldErrors.category &&
                                        delete taskFieldErrors.category
                                "
                            >
                                <option value="">Select Category</option>
                                <option value="Personal">Personal</option>
                                <option value="Training">Training</option>
                                <option value="Client Management">
                                    Client Management
                                </option>
                                <option value="Administrative">
                                    Administrative
                                </option>
                                <option value="Maintenance">Maintenance</option>
                                <option value="Professional Development">
                                    Professional Development
                                </option>
                                <option value="Coaching">Coaching</option>
                                <option value="Follow-up">Follow-up</option>
                                <option value="Assessment">Assessment</option>
                                <option value="Nutrition">Nutrition</option>
                                <option value="Wellness">Wellness</option>
                                <option value="Billing">Billing</option>
                                <option value="Communication">
                                    Communication
                                </option>
                                <option value="Other">Other</option>
                            </select>
                            <i
                                class="fas fa-info-circle info-icon"
                                title="Select the category that best fits this task"
                            ></i>
                        </div>
                        <div
                            v-if="taskFieldErrors.category"
                            class="task-field-error"
                        >
                            {{ taskFieldErrors.category }}
                        </div>
                    </div>

                    <div class="form-group">
                        <label class="form-label"
                            >Priority
                            <span class="required-asterisk">*</span></label
                        >
                        <div class="input-container">
                            <select
                                v-model="newTask.priority"
                                class="form-select"
                                :class="{
                                    'is-invalid': taskFieldErrors.priority,
                                }"
                                required
                                @change="
                                    taskFieldErrors.priority &&
                                        delete taskFieldErrors.priority
                                "
                            >
                                <option value="">Select Priority</option>
                                <option value="urgent">Urgent</option>
                                <option value="high">High</option>
                                <option value="medium">Medium</option>
                                <option value="low">Low</option>
                            </select>
                            <i
                                class="fas fa-info-circle info-icon"
                                title="Select the priority level for this task"
                            ></i>
                        </div>
                        <div
                            v-if="taskFieldErrors.priority"
                            class="task-field-error"
                        >
                            {{ taskFieldErrors.priority }}
                        </div>
                    </div>

                    <div class="form-group">
                        <label class="form-label">Due Date:</label>
                        <div
                            class="input-container date-input-container"
                            @click="openDatePicker"
                        >
                            <input
                                ref="dueDateInput"
                                v-model="newTask.dueDate"
                                type="date"
                                class="form-input date-input"
                                :class="{
                                    'is-invalid': taskFieldErrors.dueDate,
                                }"
                                required
                                @click.stop="openDatePicker"
                                @change="
                                    taskFieldErrors.dueDate &&
                                        delete taskFieldErrors.dueDate
                                "
                            />
                            <i
                                class="fas fa-info-circle info-icon date-info-icon"
                                title="Set the due date for this task"
                            ></i>
                        </div>
                        <div
                            v-if="taskFieldErrors.dueDate"
                            class="task-field-error"
                        >
                            {{ taskFieldErrors.dueDate }}
                        </div>
                    </div>

                    <!-- Detailed Form Fields (shown when showTaskDetails is true) -->
                    <div v-if="showTaskDetails" class="detailed-form">
                        <div class="form-group">
                            <label class="form-label">Details</label>
                            <div class="input-container">
                                <textarea
                                    v-model="newTask.details"
                                    class="form-textarea"
                                    placeholder="Enter task details..."
                                    rows="4"
                                ></textarea>
                                <i
                                    class="fas fa-info-circle info-icon"
                                    title="Provide detailed information about the task"
                                ></i>
                            </div>
                        </div>

                        <!-- Concerns field - Commented out (not in database)
                        <div class="form-group">
                            <label class="form-label">Concerns</label>
                            <div class="input-container">
                                <div class="user-input-container">
                                    <i class="fas fa-user user-icon"></i>
                                    <input
                                        v-model="newTask.concerns"
                                        type="text"
                                        class="form-input user-input"
                                        :placeholder="
                                            member.first_name +
                                            ' ' +
                                            member.last_name
                                        "
                                    />
                                </div>
                                <i class="fas fa-info-circle info-icon" title="Enter any specific concerns or notes about the task"></i>
                            </div>
                        </div>
                        -->

                        <div class="form-group checkbox-group">
                            <div class="checkbox-container">
                                <input
                                    v-model="newTask.isComplete"
                                    type="checkbox"
                                    id="taskComplete"
                                    class="form-checkbox"
                                />
                                <label for="taskComplete" class="checkbox-label"
                                    >Task is complete</label
                                >
                                <i
                                    class="fas fa-info-circle info-icon"
                                    title="Check this box if the task is already completed"
                                ></i>
                            </div>
                        </div>

                        <div class="form-group">
                            <label class="form-label">Time</label>
                            <div class="input-container">
                                <div class="time-select-row">
                                    <select
                                        v-model="newTask.due_hour"
                                        class="form-select time-select"
                                    >
                                        <option :value="null">Hour</option>
                                        <option
                                            v-for="hour in hourOptions"
                                            :key="hour.value"
                                            :value="hour.value"
                                        >
                                            {{ hour.text }}
                                        </option>
