    computed: {
        /**
         * Computed property for profile image source to prevent continuous requests
         */
        profileImageSrc() {
            const imageUrl = this.getProfileImageUrl(this.member.profile_image);
            // Cache the URL to prevent unnecessary recalculations
            if (!this._cachedImageUrl || this._cachedImageUrl !== imageUrl) {
                this._cachedImageUrl = imageUrl;
            }
            return this._cachedImageUrl;
        },
        filteredNotes() {
            if (this.selectedCategory === "All") return this.notes;
            return this.notes.filter(
                (note) => note.category === this.selectedCategory
            );
        },
        /**
         * Get a displayable creator name for a note
         */
        // eslint-disable-next-line vue/return-in-computed-property
        getNoteCreatorName() {
            return (note) => {
                if (!note) return "Unknown";
                // New normalized fields from API
                if (note.creator_name) {
                    return note.creator_name;
                }
                // Legacy creator/user objects with username/name
                if (note.creator) {
                    if (note.creator.username) {
                        return note.creator.username;
                    }
                    if (note.creator.name) {
                        return note.creator.name;
                    }
                }
                if (note.user) {
                    if (note.user.username) {
                        return note.user.username;
                    }
                    if (note.user.name) {
                        return note.user.name;
                    }
                }
                // Coach relation from current notes API
                if (note.coach) {
                    const first = note.coach.first_name || "";
                    const last = note.coach.last_name || "";
                    const fullName = `${first} ${last}`.trim();
                    if (fullName) {
                        return fullName;
                    }
                }
                // Fallback string fields that might exist
                if (note.created_by_name) {
                    return note.created_by_name;
                }
                if (note.created_by) {
                    return note.created_by;
                }
                return "Unknown";
            };
        },
        /**
         * Get the current subscription plan name for display
         */
        currentPlanName() {
            // Get plan ID from subscription_plan_id first, then fallback to plan field
            const planId = this.member.subscription_plan_id || this.member.plan;

            // If no plan ID, check if plan name exists directly
            if (!planId) {
                // If member.plan is a string (plan name), return it
                if (
                    this.member.plan &&
                    typeof this.member.plan === "string" &&
                    this.member.plan !== "0" &&
                    isNaN(parseInt(this.member.plan))
                ) {
                    return this.member.plan;
                }
                return "No Plan Selected";
            }

            // Convert to number for comparison since API returns numeric IDs
            const planIdNum = parseInt(planId);
            if (isNaN(planIdNum) || planIdNum === 0) {
                // If planId is a string name, return it
                if (typeof planId === "string" && isNaN(parseInt(planId))) {
                    return planId;
                }
                return "No Plan Selected";
            }

            if (!this.plans || this.plans.length === 0) {
                return "Loading plans...";
            }

            // Try to find plan by ID (handle both string and number comparisons)
            const plan = this.plans.find((p) => {
                const pId = parseInt(p.id);
                return (
                    pId === planIdNum || p.id == planIdNum || p.id === planIdNum
                );
            });

            if (!plan) {
                // If plan not found but we have a plan name in member.plan, use that
                if (
                    this.member.plan &&
                    typeof this.member.plan === "string" &&
                    this.member.plan !== "0"
                ) {
                    return this.member.plan;
                }
                // Otherwise return the plan ID as fallback
                return `Plan ID: ${planIdNum}`;
            }

            // Handle both monthly_price (from subscription_plans) and price (from plans table)
            const planPrice = plan.monthly_price || plan.price || 0;
            return plan
                ? `${plan.name} - $${planPrice}/month`
                : "Plan Not Found";
        },

        /**
         * Get the current subscription plan details
         */
        currentPlanDetails() {
            const planId = this.member.subscription_plan_id || this.member.plan;
            if (!planId) return null;

            // Convert to number for comparison since API returns numeric IDs
            const planIdNum = parseInt(planId);
            return this.plans.find((p) => p.id === planIdNum);
        },

        /**
         * Check if all bank detail fields are empty
         */
        hasBankDetails() {
            const bankFields = [
                this.member.bank_account_number,
                this.member.routing_number,
                this.member.bank_account_holder_name,
                this.member.bank_name,
                this.member.mandate_id,
                this.member.bank_account_type,
            ];

            return bankFields.some((field) => {
                if (!field) return false;
                const value = String(field).trim();
                // Check if it's not empty and not encrypted
                return value !== "" && !value.startsWith("eyJ");
            });
        },

        /**
         * Get active financial members
         */
        activeFinancialmembers() {
            return this.financialmembers.filter(
                (member) => member.status === "active"
            );
        },

        /**
         * Progress chart options for ECharts
         */
        progressChartOptions() {
            const series = [];
            const dates = [];
            const allDates = new Set();

            // Collect all dates from visible metrics
            if (this.leftMetricVisible && this.selectedLeftMetric) {
                const data =
                    this.progressGraphData[this.selectedLeftMetric] || [];
                if (data && data.length > 0) {
                    data.forEach((item) => {
                        if (item && item.date) {
                            allDates.add(item.date);
                        }
                    });
                }
            }
            if (this.rightMetricVisible && this.selectedRightMetric) {
                const data =
                    this.progressGraphData[this.selectedRightMetric] || [];
                if (data && data.length > 0) {
                    data.forEach((item) => {
                        if (item && item.date) {
                            allDates.add(item.date);
                        }
                    });
                }
            }

            // Sort dates
            dates.push(...Array.from(allDates).sort());

            // Add left metric series
            if (this.leftMetricVisible && this.selectedLeftMetric) {
                const data =
                    this.progressGraphData[this.selectedLeftMetric] || [];
                const values = dates.map((date) => {
                    const item = data.find((d) => d.date === date);
                    return item ? item.value : null;
                });

                series.push({
                    name: this.getMetricLabel(this.selectedLeftMetric),
                    type: "line",
                    smooth: true,
                    data: values,
                    itemStyle: {
                        color: "#007bff",
                    },
                    areaStyle: {
                        color: {
                            type: "linear",
                            x: 0,
                            y: 0,
                            x2: 0,
                            y2: 1,
                            colorStops: [
                                { offset: 0, color: "rgba(0, 123, 255, 0.3)" },
                                { offset: 1, color: "rgba(0, 123, 255, 0.05)" },
                            ],
                        },
                    },
                    symbol: "circle",
                    symbolSize: 6,
                });
            }

            // Add right metric series
            if (this.rightMetricVisible && this.selectedRightMetric) {
                const data =
                    this.progressGraphData[this.selectedRightMetric] || [];
                const values = dates.map((date) => {
                    const item = data.find((d) => d.date === date);
                    return item ? item.value : null;
                });

                series.push({
                    name: this.getMetricLabel(this.selectedRightMetric),
                    type: "line",
                    smooth: true,
                    data: values,
                    itemStyle: {
                        color: "#ff6b35",
                    },
                    areaStyle: {
                        color: {
                            type: "linear",
                            x: 0,
                            y: 0,
                            x2: 0,
                            y2: 1,
                            colorStops: [
                                { offset: 0, color: "rgba(255, 107, 53, 0.3)" },
                                {
                                    offset: 1,
                                    color: "rgba(255, 107, 53, 0.05)",
                                },
                            ],
                        },
                    },
                    symbol: "circle",
                    symbolSize: 6,
                });
            }

            // Format dates for display
            const formattedDates = dates.map((date) => {
                const d = new Date(date);
                return `${String(d.getMonth() + 1).padStart(2, "0")}/${String(
                    d.getDate()
                ).padStart(2, "0")}/${d.getFullYear()}`;
            });

            // If no data available, show empty state
            if (series.length === 0 || dates.length === 0) {
                return {
                    tooltip: {
                        trigger: "axis",
                    },
                    grid: {
                        left: "3%",
                        right: "4%",
                        bottom: "3%",
                        containLabel: true,
                    },
                    xAxis: {
                        type: "category",
                        boundaryGap: false,
                        data: [],
                        axisLine: {
                            lineStyle: {
                                color: "#e0e0e0",
                            },
                        },
                    },
                    yAxis: {
                        type: "value",
                        axisLine: {
                            lineStyle: {
                                color: "#e0e0e0",
                            },
                        },
                        splitLine: {
                            lineStyle: {
                                color: "#f0f0f0",
                            },
                        },
                    },
                    series: [],
                    graphic: [
                        {
                            type: "text",
                            left: "center",
                            top: "middle",
                            style: {
                                text: "No data available. Add metrics to see progress graph.",
                                fontSize: 14,
                                fill: "#999",
                                textAlign: "center",
                            },
                        },
                    ],
                };
            }

            return {
                tooltip: {
                    trigger: "axis",
                    formatter: (params) => {
                        if (!params || params.length === 0) return "";
                        const date = params[0].axisValue;
                        let result = `<div style="margin-bottom: 4px;">${date}</div>`;
                        params.forEach((param, index) => {
                            const metricKey =
                                index === 0 && this.leftMetricVisible
                                    ? this.selectedLeftMetric
                                    : index === 1 && this.rightMetricVisible
                                    ? this.selectedRightMetric
                                    : "";
                            const unit = this.getMetricUnit(metricKey);
                            const icon =
                                param.seriesName === "Weight" ? "⚖️" : "•";
                            result += `<div>${icon} ${param.seriesName}: ${
                                param.value
                            }${unit ? " " + unit : ""}</div>`;
                        });
                        return result;
                    },
                },
                grid: {
                    left: "3%",
                    right: "4%",
                    bottom: "3%",
                    containLabel: true,
                },
                xAxis: {
                    type: "category",
                    boundaryGap: false,
                    data: formattedDates,
                    axisLine: {
                        lineStyle: {
                            color: "#e0e0e0",
                        },
                    },
                },
                yAxis: {
                    type: "value",
                    axisLine: {
                        lineStyle: {
                            color: "#e0e0e0",
                        },
                    },
                    splitLine: {
                        lineStyle: {
                            color: "#f0f0f0",
                        },
                    },
                },
                series: series,
            };
        },

        /**
         * Get inactive financial members
         */
        inactiveFinancialmembers() {
            return this.financialmembers.filter(
                (member) => member.status === "inactive"
            );
        },

        /**
         * Get filtered financial members based on current filter
         */
        filteredFinancialmembers() {
            if (this.financialmemberFilter === "active") {
                return this.activeFinancialmembers;
            } else {
                return this.inactiveFinancialmembers;
            }
        },

        /**
         * Get filtered appointments based on current filter
         */
        filteredBookings() {
            let filtered = [...this.memberAppointments];

            if (this.bookingFilter === "upcoming") {
                // Filter for future appointments
                filtered = filtered.filter((appointment) => {
                    const appointmentDate = new Date(
                        appointment.appointment_date || appointment.date
                    );
                    const today = new Date();
                    today.setHours(0, 0, 0, 0);
                    return appointmentDate >= today;
                });
            } else if (this.bookingFilter === "past") {
                // Filter for past appointments
                filtered = filtered.filter((appointment) => {
                    const appointmentDate = new Date(
                        appointment.appointment_date || appointment.date
                    );
                    const today = new Date();
                    today.setHours(0, 0, 0, 0);
                    return appointmentDate < today;
                });
            }
            // If "all", keep all appointments

            // Apply status filter
            if (this.bookingStatusFilter !== "all") {
                filtered = filtered.filter((appointment) => {
                    const status = (appointment.status || "").toLowerCase();
                    const filterStatus = this.bookingStatusFilter.toLowerCase();
                    return (
                        status === filterStatus ||
                        (filterStatus === "booked" &&
                            (status === "booked" || status === "scheduled"))
                    );
                });
            }

            // Apply date range filter
            if (this.bookingDateRangeFilter !== "all") {
                const today = new Date();
                today.setHours(0, 0, 0, 0);

                filtered = filtered.filter((appointment) => {
                    const appointmentDate = new Date(
                        appointment.appointment_date || appointment.date
                    );
                    appointmentDate.setHours(0, 0, 0, 0);

                    switch (this.bookingDateRangeFilter) {
                        case "today":
                            return (
                                appointmentDate.getTime() === today.getTime()
                            );

                        case "this-week": {
                            const startOfWeek = new Date(today);
                            startOfWeek.setDate(
                                today.getDate() - today.getDay()
                            );
                            const endOfWeek = new Date(startOfWeek);
                            endOfWeek.setDate(startOfWeek.getDate() + 6);
                            return (
                                appointmentDate >= startOfWeek &&
                                appointmentDate <= endOfWeek
                            );
                        }

                        case "next-week": {
                            const startOfWeek = new Date(today);
                            startOfWeek.setDate(
                                today.getDate() - today.getDay() + 7
                            );
                            const endOfWeek = new Date(startOfWeek);
                            endOfWeek.setDate(startOfWeek.getDate() + 6);
                            return (
                                appointmentDate >= startOfWeek &&
                                appointmentDate <= endOfWeek
                            );
                        }

                        case "this-month": {
                            const startOfMonth = new Date(
                                today.getFullYear(),
                                today.getMonth(),
                                1
                            );
                            const endOfMonth = new Date(
                                today.getFullYear(),
                                today.getMonth() + 1,
                                0
                            );
                            return (
                                appointmentDate >= startOfMonth &&
                                appointmentDate <= endOfMonth
                            );
                        }

                        case "next-month": {
                            const startOfMonth = new Date(
                                today.getFullYear(),
                                today.getMonth() + 1,
                                1
                            );
                            const endOfMonth = new Date(
                                today.getFullYear(),
                                today.getMonth() + 2,
                                0
                            );
                            return (
                                appointmentDate >= startOfMonth &&
                                appointmentDate <= endOfMonth
                            );
                        }

                        case "last-30-days": {
                            const thirtyDaysAgo = new Date(today);
                            thirtyDaysAgo.setDate(today.getDate() - 30);
                            return (
                                appointmentDate >= thirtyDaysAgo &&
                                appointmentDate <= today
                            );
                        }

                        default:
                            return true;
                    }
                });
            }

            filtered.sort((a, b) => {
                const dateA = new Date(a.appointment_date || a.date);
                const dateB = new Date(b.appointment_date || b.date);
                const today = new Date();
                today.setHours(0, 0, 0, 0);

                const aIsUpcoming = dateA >= today;
                const bIsUpcoming = dateB >= today;

                // Upcoming appointments first
                if (aIsUpcoming && !bIsUpcoming) return -1;
                if (!aIsUpcoming && bIsUpcoming) return 1;

                if (aIsUpcoming && bIsUpcoming) {
                    return dateA - dateB; // Upcoming: earliest first
                } else {
                    return dateB - dateA; // Past: most recent first
                }
            });

            return filtered;
        },

        /**
         * Filter available coaches based on search query
         */
        filteredAvailableCoaches() {
            if (!this.coachSearchQuery) {
                return this.availableCoaches.filter(
                    (coach) =>
                        !this.assignedCoaches.find((ac) => ac.id === coach.id)
                );
            }
            const query = this.coachSearchQuery.toLowerCase();
            return this.availableCoaches.filter(
                (coach) =>
                    !this.assignedCoaches.find((ac) => ac.id === coach.id) &&
                    (coach.name.toLowerCase().includes(query) ||
                        (coach.specialization &&
                            coach.specialization.toLowerCase().includes(query)))
            );
        },

        /**
         * Get member's full name for display
         */
        memberFullName() {
            if (!this.member) {
                return "Member Profile";
            }
            const firstName =
                this.member.firstname || this.member.first_name || "";
            const lastName =
                this.member.lastname || this.member.last_name || "";
            const fullName = `${firstName} ${lastName}`.trim();
            return fullName || "Member Profile";
        },

        /**
         * Get Pro membership display text
         */
        proMembershipDisplayText() {
            if (!this.member.pro_membership || !this.member.pro_start_date) {
                return "No PRO membership";
            }
            const startDate = this.formatDate(this.member.pro_start_date);
            if (this.member.pro_end_date) {
                const endDate = this.formatDate(this.member.pro_end_date);
                return `Active from ${startDate} To ${endDate}`;
            }
            return `Active from ${startDate}`;
        },
    },
    methods: {
        /**
         * Prevent body scrolling when filter dropdown is opened
         */
        preventBodyScroll() {
            document.body.style.overflow = "hidden";
        },

        /**
         * Restore body scrolling when filter dropdown is closed
         */
        restoreBodyScroll() {
            document.body.style.overflow = "";
        },

        openDatePicker() {
            // Make the entire input field clickable to open calendar
            if (this.$refs.dueDateInput) {
                this.$refs.dueDateInput.showPicker?.();
                // Fallback: focus and click for browsers that don't support showPicker
                if (!this.$refs.dueDateInput.showPicker) {
                    this.$refs.dueDateInput.focus();
                    this.$refs.dueDateInput.click();
                }
            }
        },

        switchTab(tabKey) {
            this.activeTab = tabKey;

            // Load appointments when appointments tab is selected
            if (tabKey === "bookings") {
                this.loadMemberAppointments();
            }

            // Load coach data when coaching tab is selected
            if (tabKey === "coaching") {
                this.loadCoachingProfile();
                this.loadAvailableCoaches();
                this.fetchCoachAssignment();
                this.fetchQuestionnaires();
                this.fetchCheckIns();
            }
        },

        /**
         * Simple test method to check if button clicks are working
         */
        testButtonClick() {
            this.makeToast("info", "Button click is working!", "Info");
        },

        /**
         * Check if a value is encrypted (starts with 'eyJ' which is base64 encoded JSON)
         * Returns the original value if valid, or '-' if encrypted/empty
         */
        formatBankValue(value) {
            // Handle null, undefined, or empty values
            if (!value || value === null || value === undefined) {
                return "-";
            }

            // Convert to string if not already
            const stringValue = String(value).trim();

            // Return '-' for empty strings
            if (stringValue === "") {
                return "-";
            }

            // Check if value looks like encrypted data (Laravel encrypted strings start with 'eyJ')
            if (stringValue.startsWith("eyJ")) {
                return "-";
            }

            return stringValue;
        },

        /**
         * Check if a value is protected/encrypted
         */
        isProtectedValue(value) {
            if (!value || value === null || value === undefined) {
                return false;
            }
            const stringValue = String(value).trim();
            return stringValue !== "" && stringValue.startsWith("eyJ");
        },

        /**
         * Handle edit button click - ensures all fields are populated before entering edit mode
         */
        handleEditClick() {
            // Show a toast notification to confirm the button is working
            this.makeToast("info", "Edit button clicked! Processing...", "Info");

            // Simple approach - just enable edit mode
            this.isEditing = true;

            // Force Vue to update
            this.$forceUpdate();
        },

        /**
         * Manually populate all form fields with current member data
         * This method is called when entering edit mode to ensure all fields are populated
         */
        populateAllFields() {
            // Get data from query parameters if member is empty
            if (
                !this.member ||
                !this.member.id ||
                Object.keys(this.member).length === 0
            ) {
                this.getmemberFromQueryParams();
            }
        },

        setFormFieldsDirectly() {},

        formatDate(date) {
            if (!date) return "N/A";
            return new Date(date).toLocaleDateString();
        },

        handleNoteSubmit() {
            this.makeToast("info", "Vue method called!", "Info");

            // Get description from textarea
            const textarea = document.querySelector(
                'textarea[name="note_description"]'
            );
            const text = textarea ? textarea.value : "";

            if (!text.trim()) {
                this.makeToast("warning", "Please enter some text for the note", "Warning");
                return;
            }

            this.makeToast("info", "Text found: " + text, "Info");

            axios
                .post("/notes", {
                    member_id: this.member.id,
                    description: text.trim(),
                    category: "General",
                    is_shared: false, // Default to false for this legacy form
                }, {
                    baseURL: '', // Use web routes (same as GET request)
                })
                .then((response) => {
                    this.makeToast("success", "Note saved successfully!", "Success");
                    if (
                        this.loadMemberNotes &&
                        typeof this.loadMemberNotes === "function"
                    ) {
                        this.loadMemberNotes();
                    }
                    textarea.value = "";
                })
                .catch((error) => {
                    this.makeToast("danger", "Error saving note: " + error.message, "Error");
                });
        },

        async saveNote() {
            if (!this.newNote.description || !this.newNote.description.trim()) {
                this.showError("Note text cannot be empty");
                return;
            }

            const memberId =
                this.member && this.member.id
                    ? this.member.id
                    : this.$route.params.id;
            if (!memberId) {
                this.showError("Missing member ID");
                return;
            }

            this.isSavingNote = true;
            try {
                const noteData = {
                    member_id: memberId,
                    description: this.newNote.description.trim(),
                    category: this.newNote.category || "General",
                    is_shared: this.newNote.is_shared || false,
                };

                let response;
                if (this.editingNote && this.editingNote.id) {
                    response = await axios.put(
                        `/notes/${this.editingNote.id}`,
                        noteData,
                        {
                            baseURL: '', // Use web routes (same as GET request)
                        }
                    );
                } else {
                    response = await axios.post(`/notes`, noteData, {
                        baseURL: '', // Use web routes (same as GET request)
                    });
                }

                const data = response && response.data ? response.data : {};
                const ok =
                    data.success === true ||
                    data.status === "success" ||
                    !!(
                        data.id ||
                        (data.data && (data.data.id || data.data.note)) ||
                        data.note
                    );
                const saved = data.data && (data.data.note || data.data);
                const savedNote =
                    saved && saved.id
                        ? saved
                        : data.note && data.note.id
                        ? data.note
                        : data;

                if (ok) {
                    this.showSuccess("Note saved successfully");
                    if (savedNote && savedNote.id) {
                        const normalized = {
                            id: savedNote.id,
                            description:
                                savedNote.description ||
                                savedNote.text ||
                                savedNote.content ||
                                this.newNote.description.trim(),
                            category:
                                savedNote.category ||
                                this.newNote.category ||
                                "General",
                            created_at:
                                savedNote.created_at ||
                                new Date().toISOString(),
                            // Preserve various possible relationships so we can
                            // reliably display "Created By" in the UI
                            creator:
                                savedNote.creator || savedNote.user || null,
                            coach: savedNote.coach || null,
                        };
                        if (this.editingNote) {
                            this.notes = this.notes.map((n) =>
                                n.id === this.editingNote.id ? normalized : n
                            );
                        } else {
                            this.notes = [normalized, ...this.notes];
                        }
                    } else {
                        if (
                            this.loadMemberNotes &&
                            typeof this.loadMemberNotes === "function"
                        ) {
                            await this.loadMemberNotes();
                        }
                    }
                    this.resetNoteForm();
                } else {
                    const serverMsg =
                        data && (data.message || data.error || data.errors);
                    this.showError(serverMsg || "Failed to save note");
                }
            } catch (error) {
                const status = error && error.response && error.response.status;
                const msg =
                    (error &&
                        error.response &&
                        error.response.data &&
                        (error.response.data.message ||
                            JSON.stringify(error.response.data))) ||
                    error.message ||
                    "Failed to save note";
                this.showError(
                    `Save failed${status ? " (" + status + ")" : ""}: ${msg}`
                );
            } finally {
                this.isSavingNote = false;
            }
        },

        editNote(note) {
            this.newNote.description = note.description || note.text || "";
            this.newNote.category = note.category || "General";
            this.newNote.is_shared = note.is_shared || false;
            this.editingNote = note;
        },

        async deleteNote(noteId) {
            try {
                const result = await this.$swal({
                    title: "Delete note?",
                    text: "Are you sure you want to delete this note?",
                    icon: "warning",
                    showCancelButton: true,
                    confirmButtonText: "Yes, delete",
                    cancelButtonText: "Cancel",
                    reverseButtons: true,
                });

                if (!result.isConfirmed) {
                    return;
                }

                const response = await axios.delete(`/notes/${noteId}`, {
                    baseURL: '', // Use web routes (same as GET request)
                });
                if (response.data && response.data.success) {
                    this.showSuccess("Note deleted successfully");
                    if (
                        this.loadMemberNotes &&
                        typeof this.loadMemberNotes === "function"
                    ) {
                        await this.loadMemberNotes(); // Reload notes
                    }
                } else {
                    this.showError("Failed to delete note");
                }
            } catch (error) {
                this.showError("Failed to delete note");
            }
        },

        resetNoteForm() {
            this.newNote.description = "";
            this.newNote.category = "General";
            this.newNote.is_shared = false;
            this.editingNote = null;
        },

        getFilteredNotes() {
            if (this.selectedCategory === "All") {
                return this.notes;
            }
            return this.notes.filter(
                (note) => note.category === this.selectedCategory
            );
        },

        formatCurrency(amount) {
            return parseFloat(amount).toFixed(2);
        },

        async loadMemberAppointments() {
            if (!this.member || !this.member.id) {
                return;
            }

            this.isLoadingAppointments = true;

            try {
                const url = `appointments/member/${this.member.id}`;
                const response = await axios.get(url);

                // Store appointments in both variables for compatibility
                this.memberAppointments = response.data.data || [];
                this.appointments = response.data.data || [];
            } catch (error) {
                this.memberAppointments = [];
                this.appointments = [];

                // Show error message to user
                this.showError(
                    "Failed to load appointments: " +
                        (error.response?.data?.message || error.message)
                );
            } finally {
                this.isLoadingAppointments = false;
            }
        },

        /**
         * Open appointment modal and load necessary data
         */
        async openAppointmentModal() {
            this.showAppointmentModal = true;
            this.isEditingAppointment = false;
            this.editingAppointmentId = null;

            // Pre-fill client with current member
            if (this.member && this.member.id) {
                this.selectedClientId = this.member.id;
            }

            // Set default date to today
            const today = new Date();
            this.appointmentDate =
                today.getFullYear() +
                "-" +
                String(today.getMonth() + 1).padStart(2, "0") +
                "-" +
                String(today.getDate()).padStart(2, "0");

            // Set default time (next hour)
            const nextHour = today.getHours() + 1;
            this.appointmentStartTime = `${nextHour
                .toString()
                .padStart(2, "0")}:00`;
            this.appointmentEndTime = `${(nextHour + 1)
                .toString()
                .padStart(2, "0")}:00`;

            // Reset other fields
            this.selectedStaffId = "";
            this.workoutType = "";

            // Load staff and clients if not already loaded
            await this.loadAppointmentStaff();
        },

        /**
         * Handle modal backdrop click
         */
        handleModalBackdropClick(event) {
            // Only close if clicking directly on the backdrop, not on the modal box
            if (event.target === event.currentTarget) {
                this.closeAppointmentModal();
            }
        },

        /**
         * Close appointment modal and reset form
         */
        closeAppointmentModal() {
            this.showAppointmentModal = false;
            this.isEditingAppointment = false;
            this.editingAppointmentId = null;
            this.appointmentDate = "";
            this.appointmentStartTime = "";
            this.appointmentEndTime = "";
            this.selectedStaffId = "";
            this.selectedClientId = "";
            this.workoutType = "";
        },

        /**
         * Load staff for appointment form
         */
        async loadAppointmentStaff() {
            try {
                const response = await axios.get("/appointments/staff");
                if (response.data.success) {
                    this.appointmentStaff = response.data.data;
                }
            } catch (error) {
                this.$bvToast.toast("Failed to load staff members", {
                    title: "Error",
                    variant: "danger",
                    solid: true,
                    toaster: "b-toaster-top-right",
                    autoHideDelay: 1000,
                });
            }
        },

        /**
         * Save appointment (create or update)
         */
        async saveAppointment() {
            try {
                // Set saving state to prevent multiple submissions
                this.savingAppointment = true;

                // Validate required fields
                if (
                    !this.appointmentDate ||
                    !this.appointmentStartTime ||
                    !this.appointmentEndTime ||
                    !this.selectedStaffId ||
                    !this.selectedClientId ||
                    !this.workoutType
                ) {
                    this.$bvToast.toast("Please fill in all required fields", {
                        title: "Validation Error",
                        variant: "warning",
                        solid: true,
                        toaster: "b-toaster-top-right",
                        autoHideDelay: 1000,
                    });
                    this.savingAppointment = false;
                    return;
                }

                // Convert to integers and validate
                const staffId = parseInt(this.selectedStaffId, 10);
                const clientId = parseInt(this.selectedClientId, 10);
                const workoutId = parseInt(this.workoutType, 10);

                // Check if conversions resulted in valid numbers
                if (isNaN(staffId) || isNaN(clientId) || isNaN(workoutId)) {
                    this.$bvToast.toast(
                        "Invalid selection. Please select valid options.",
                        {
                            title: "Validation Error",
                            variant: "warning",
                            solid: true,
                            toaster: "b-toaster-top-right",
                            autoHideDelay: 1000,
                        }
                    );
                    this.savingAppointment = false;
                    return;
                }

                const appointmentData = {
                    date: this.appointmentDate,
                    start_time: this.appointmentStartTime,
                    end_time: this.appointmentEndTime,
                    staff_id: staffId,
                    client_id: clientId,
                    workout_id: workoutId,
                };

                let response;
                if (this.isEditingAppointment && this.editingAppointmentId) {
                    // Update existing appointment
                    response = await axios.put(
                        `/appointments/${this.editingAppointmentId}`,
                        appointmentData
                    );
                } else {
                    // Create new appointment
                    response = await axios.post(
                        "/appointments",
                        appointmentData
                    );
                }

                if (response.data.success) {
                    // Reload appointments
                    await this.loadMemberAppointments();

                    this.$bvToast.toast(
                        `Appointment ${
                            this.isEditingAppointment ? "updated" : "saved"
                        } successfully!`,
                        {
                            title: "Success",
                            variant: "success",
                            solid: true,
                            toaster: "b-toaster-top-right",
                            autoHideDelay: 1000,
                        }
                    );
                    this.closeAppointmentModal();
                } else {
                    this.$bvToast.toast(
                        `Backend error: ${
                            response.data.message || "Unknown error"
                        }`,
                        {
                            title: "Error",
                            variant: "danger",
                            solid: true,
                            toaster: "b-toaster-top-right",
                            autoHideDelay: 1000,
                        }
                    );
                }
            } catch (error) {
                // Provide more specific error messages
                let errorMessage = "Unknown error occurred";
                if (error.response) {
                    // Server responded with error status
                    if (error.response.status === 422) {
                        // Validation error - show detailed validation errors
                        const validationErrors = error.response.data?.errors;
                        if (validationErrors) {
                            const errorList = Object.keys(validationErrors)
                                .map((key) => {
                                    return validationErrors[key].join(", ");
                                })
                                .join("; ");
                            errorMessage = `Validation error: ${errorList}`;
                        } else if (error.response.data?.message) {
                            errorMessage = error.response.data.message;
                        } else {
                            errorMessage =
                                "Validation error: Please check your input";
                        }
                    } else if (
                        error.response.data &&
                        error.response.data.message
                    ) {
                        errorMessage = error.response.data.message;
                    } else if (error.response.status === 500) {
                        errorMessage = "Server error: Please try again later";
                    } else {
                        errorMessage = `Server error (${error.response.status})`;
                    }
                } else if (error.request) {
                    // Request was made but no response received
                    errorMessage =
                        "Network error: Please check your connection";
                } else {
                    // Something else happened
                    errorMessage = error.message || "Unknown error occurred";
                }

                this.$bvToast.toast(
                    `Failed to ${
                        this.isEditingAppointment ? "update" : "save"
                    } appointment: ${errorMessage}`,
                    {
                        title: "Error",
                        variant: "danger",
                        solid: true,
                        toaster: "b-toaster-top-right",
                        autoHideDelay: 1000,
                    }
                );
            } finally {
                // Always reset saving state
                this.savingAppointment = false;
            }
        },

        getWorkoutTypeName(workoutId) {
            if (!workoutId) return null;
            const workoutTypes = {
                1: "Cardio",
                2: "Strength",
                3: "Yoga",
                4: "HIIT",
                5: "Pilates",
                6: "Crossfit",
            };
            return workoutTypes[workoutId] || "General Workout";
        },

        /**
         * Get coach/trainer name from appointment
         */
        getCoachNameFromAppointment(appointment) {
            if (!appointment) return "Trainer";

            if (appointment.coach) {
                const coach = appointment.coach;

                // If coach has a name property
                if (coach.name) {
                    return coach.name;
                }

                // If coach has first_name and last_name
                if (coach.first_name || coach.last_name) {
                    const firstName = coach.first_name || "";
                    const lastName = coach.last_name || "";
                    const fullName = `${firstName} ${lastName}`.trim();
                    if (fullName) {
                        return fullName;
                    }
                }

                if (coach.firstname || coach.lastname) {
                    const firstName = coach.firstname || "";
                    const lastName = coach.lastname || "";
                    const fullName = `${firstName} ${lastName}`.trim();
                    if (fullName) {
                        return fullName;
                    }
                }
            }

            // Check for direct name fields
            if (appointment.trainer_name) {
                return appointment.trainer_name;
            }

            if (appointment.coach_name) {
                return appointment.coach_name;
            }

            if (appointment.trainer) {
                const trainer = appointment.trainer;
                if (trainer.name) {
                    return trainer.name;
                }
                if (trainer.first_name || trainer.last_name) {
                    const firstName = trainer.first_name || "";
                    const lastName = trainer.last_name || "";
                    const fullName = `${firstName} ${lastName}`.trim();
                    if (fullName) {
                        return fullName;
                    }
                }
            }

            // Fallback
            return "Trainer";
        },

        /**
         * Get assigner name (admin or coach) who assigned the appointment
         */
        getAssignerName(appointment) {
            if (!appointment) return null;

            if (appointment.assigned_by) {
                const assigner = appointment.assigned_by;
                if (typeof assigner === "object") {
                    const firstName =
                        assigner.firstname || assigner.first_name || "";
                    const lastName =
                        assigner.lastname || assigner.last_name || "";
                    if (firstName || lastName) {
                        return `${firstName} ${lastName}`.trim();
                    }
                }
                // If assigned_by is a string
                if (typeof assigner === "string") {
                    return assigner;
                }
            }

            // Check for created_by object
            if (appointment.created_by) {
                const creator = appointment.created_by;
                if (typeof creator === "object") {
                    const firstName =
                        creator.firstname || creator.first_name || "";
                    const lastName =
                        creator.lastname || creator.last_name || "";
                    if (firstName || lastName) {
                        return `${firstName} ${lastName}`.trim();
                    }
                }
                if (typeof creator === "string") {
                    return creator;
                }
            }

            // Check for direct name fields
            if (appointment.assigned_by_name) {
                return appointment.assigned_by_name;
            }
            if (appointment.created_by_name) {
                return appointment.created_by_name;
            }
            if (appointment.admin_name) {
                return appointment.admin_name;
            }
            if (appointment.assigner_name) {
                return appointment.assigner_name;
            }

            return null;
        },

        /**
         * Format appointment date for display
         */
        formatAppointmentDate(dateString) {
            if (!dateString) return "Date not set";

            const date = new Date(dateString);
            return date.toLocaleDateString("en-US", {
                weekday: "long",
                year: "numeric",
                month: "2-digit",
                day: "2-digit",
                hour: "2-digit",
                minute: "2-digit",
            });
        },

        /**
         * Get CSS class for appointment status badge
         */
        getAppointmentStatusClass(status) {
            if (!status) return "status-default";

            switch (status.toLowerCase()) {
                case "scheduled":
                case "booked":
                    return "status-booked";
                case "completed":
                case "finished":
                    return "status-confirmed";
                case "cancelled":
                case "canceled":
                    return "status-cancelled";
                case "no-show":
                    return "status-unconfirmed";
                default:
                    return "status-default";
            }
        },

        // Text input functionality for coachings
        toggleTextInput(fieldName, initialValue = "") {
            this.$set(this.showTextInputs, fieldName, true);
            this.$set(this.textInputs, fieldName, initialValue);
        },

        cancelTextInput(fieldName) {
            this.$set(this.showTextInputs, fieldName, false);
            this.$set(this.textInputs, fieldName, "");
        },

        async saveTextInput(fieldName) {
            try {
                const memberId = this.$route.params.id;
                const value = this.textInputs[fieldName] || "";

                // Map UI field keys to API payload keys on MemberCoachingProfile
                const fieldMap = {
                    "intake-more-info": "intake_more_info",
                    injuries: "injuries",
                    "medical-more-info": "medical_more_info",
                    "chronic-diseases": "chronic_diseases",
                    "medical-more-info-2": "medical_more_info_2",
                    "emergency-contact": "emergency_contact",
                    "emergency-phone": "emergency_phone",
                };

                const payloadKey = fieldMap[fieldName];
                if (!payloadKey) {
                    // Fallback: ignore unknown fields silently
                    this.$set(this.showTextInputs, fieldName, false);
                    return;
                }

                const payload = { [payloadKey]: value };
                const response = await axios.put(
                    `members/${memberId}/coaching`,
                    payload
                );

                if (response && response.data && response.data.success) {
                    // Update the specific field in local state
                    this.$set(this.coachingProfile, payloadKey, value);

                    // Also update the full profile from response
                    const profile = response.data.data || {};
                    this.coachingProfile = {
                        ...this.coachingProfile,
                        ...profile,
                    };

                    // Close the input after saving
                    this.$set(this.showTextInputs, fieldName, false);

                    this.makeToast(
                        "success",
                        "Information saved successfully!",
                        "Success"
                    );
                } else {
                    this.makeToast(
                        "error",
                        "Failed to save information.",
                        "Error"
                    );
                }
            } catch (error) {
                const message =
                    (error &&
                        error.response &&
                        error.response.data &&
                        error.response.data.message) ||
                    "Failed to save information.";
                this.makeToast("error", message, "Error");
            }
        },

        /**
         * Get profile image URL with proper handling for different formats
         */
        getProfileImageUrl(profileImage) {
            // Return default image if no profile image
            if (!profileImage) {
                return "/images/default-profile.jpg";
            }

            // Check if it's a base64 data URL (legacy support)
            if (profileImage.startsWith("data:image/")) {
                return profileImage;
            }

            // If it's already a full path (starts with / or http)
            if (
                profileImage.startsWith("/") ||
                profileImage.startsWith("http")
            ) {
                return profileImage;
            }

            // If it's just a filename, assume it's in the avatar directory
            return "/images/avatar/" + profileImage;
        },

        /**
         * Get plan name by ID
         */
        getPlanName(planId) {
            if (!planId || !this.plans) return "";
            const plan = this.plans.find((p) => p.id == planId);
            return plan ? `${plan.name} - $${plan.monthly_price}/month` : "";
        },

        /**
         * Open Pro membership modal/form
         */
        openProMembershipModal() {
            // Set today's date as default start date
            const today = new Date();
            const todayStr = today.toISOString().split("T")[0];

            this.proMembershipForm.start_date = this.member.pro_start_date
                ? this.formatDateForInput(this.member.pro_start_date)
                : todayStr;
            this.proMembershipForm.end_date = this.member.pro_end_date
                ? this.formatDateForInput(this.member.pro_end_date)
                : "";

            this.isEditingProMembership = true;
        },

        /**
         * Cancel Pro membership edit
         */
        cancelProMembershipEdit() {
            this.isEditingProMembership = false;
            this.proMembershipForm.start_date = "";
            this.proMembershipForm.end_date = "";
        },

        /**
         * Save Pro membership
         */
        async saveProMembership() {
            if (!this.proMembershipForm.start_date) {
                this.$bvToast.toast("Start date is required", {
                    title: "Validation Error",
                    variant: "danger",
                    solid: true,
                    autoHideDelay: 3000,
                    toaster: "b-toaster-top-right",
                });
                return;
            }

            this.isSavingProMembership = true;

            try {
                // Save to backend
                const response = await axios.put(`members/${this.member.id}`, {
                    pro_membership: true,
                    pro_start_date: this.proMembershipForm.start_date,
                    pro_end_date: this.proMembershipForm.end_date || null,
                });

                if (response.data && response.data.success) {
                    // Refresh member data from backend to get updated Pro membership info
                    try {
                        const memberResponse = await axios.get(`members/${this.member.id}`);
                        if (memberResponse.data && memberResponse.data.success && memberResponse.data.client) {
                            // Update member object with fresh data from backend
                            this.$set(this.member, 'pro_membership', memberResponse.data.client.pro_membership || false);
                            this.$set(this.member, 'pro_start_date', memberResponse.data.client.pro_start_date || null);
                            this.$set(this.member, 'pro_end_date', memberResponse.data.client.pro_end_date || null);
                        }
                    } catch (refreshError) {
                        // If refresh fails, update locally
                        this.$set(this.member, 'pro_membership', true);
                        this.$set(this.member, 'pro_start_date', this.proMembershipForm.start_date);
                        this.$set(this.member, 'pro_end_date', this.proMembershipForm.end_date || null);
                    }
                    
                    this.$bvToast.toast("Pro membership saved successfully!", {
                        title: "Success",
                        variant: "success",
                        solid: true,
                        autoHideDelay: 3000,
                        toaster: "b-toaster-top-right",
                    });
                    this.isEditingProMembership = false;
                } else {
                    this.$bvToast.toast(
                        response.data?.message ||
                            "Failed to save Pro membership",
                        {
                            title: "Error",
                            variant: "danger",
                            solid: true,
                            autoHideDelay: 4000,
                            toaster: "b-toaster-top-right",
                        }
                    );
                }
            } catch (error) {
                this.$bvToast.toast(
                    error.response?.data?.message ||
                        "Failed to save Pro membership. Please try again.",
                    {
                        title: "Error",
                        variant: "danger",
                        solid: true,
                        autoHideDelay: 4000,
                        toaster: "b-toaster-top-right",
                    }
                );
            } finally {
                this.isSavingProMembership = false;
            }
        },

        /**
         * Format date for display (MM/DD/YYYY)
         */
        formatDate(dateString) {
            if (!dateString) return "";
            const date = new Date(dateString);
            if (isNaN(date.getTime())) {
                // Try parsing as YYYY-MM-DD
                const parts = dateString.split("-");
                if (parts.length === 3) {
                    return `${parts[1]}/${parts[2]}/${parts[0]}`;
                }
                return dateString;
            }
            const month = String(date.getMonth() + 1).padStart(2, "0");
            const day = String(date.getDate()).padStart(2, "0");
            const year = date.getFullYear();
            return `${month}/${day}/${year}`;
        },

        /**
         * Format date for input (YYYY-MM-DD)
         */
        formatDateForInput(dateString) {
            if (!dateString) return "";
            const date = new Date(dateString);
            if (isNaN(date.getTime())) {
                // Try parsing as MM/DD/YYYY
                const parts = dateString.split("/");
                if (parts.length === 3) {
                    return `${parts[2]}-${parts[0].padStart(
                        2,
                        "0"
                    )}-${parts[1].padStart(2, "0")}`;
                }
                return dateString;
            }
            return date.toISOString().split("T")[0];
        },

        /**
         * Focus on end date input when placeholder is clicked
         */
        focusEndDateInput() {
            if (this.$refs.endDateInput) {
                this.$refs.endDateInput.focus();
            }
        },

        /**
         * Fetch available tags from API
         */
        async fetchAvailableTags() {
            try {
                const response = await axios.get("members/tags/available");
                if (
                    response.data &&
                    response.data.success &&
                    response.data.tags
                ) {
                    // Extract tag names from the response
                    this.availableTags = response.data.tags.map(
                        (t) => t.name || t.value || t
                    );
                    // Sort alphabetically
                    this.availableTags.sort();
                } else {
                    this.availableTags = [];
                }
            } catch (error) {
                this.availableTags = [];
            }
        },

        /**
         * Filter tag suggestions based on search input
         */
        filterTagSuggestions() {
            const search = this.tagSearch.toLowerCase().trim();
            if (!search) {
                // Show first 10 existing tags when input is empty
                this.filteredTagSuggestions = this.availableTags.slice(0, 10);
            } else {
                // Filter tags that match the search
                this.filteredTagSuggestions = this.availableTags
                    .filter((tag) => tag.toLowerCase().includes(search))
                    .slice(0, 10);
            }
            this.showTagSuggestions = true;
            this.highlightedIndex = -1;
        },

        /**
         * Handle tag input focus
         */
        onTagInputFocus() {
            this.filterTagSuggestions();
            this.showTagSuggestions = true;
        },

        /**
         * Hide tag suggestions dropdown with delay
         */
        hideTagSuggestions() {
            // Delay hiding to allow click events on suggestions
            setTimeout(() => {
                this.showTagSuggestions = false;
                this.highlightedIndex = -1;
            }, 200);
        },

        /**
         * Handle Enter key in tag input
         */
        handleTagEnter() {
            if (
                this.filteredTagSuggestions.length > 0 &&
                this.highlightedIndex >= 0
            ) {
                // Add highlighted suggestion
                this.addTag(this.filteredTagSuggestions[this.highlightedIndex]);
            } else if (this.tagSearch.trim()) {
                // Add current search text as new tag
                this.addTag();
            }
        },

        /**
         * Add a new tag
         */
        addTag(tagName = null) {
            // Ensure member.tags is an array
            if (!this.member.tags) {
                this.member.tags = [];
            }

            const tagToAdd = tagName || this.tagSearch.trim();
            if (tagToAdd && !this.member.tags.includes(tagToAdd)) {
                this.member.tags.push(tagToAdd);
                this.tagSearch = "";
                this.showTagSuggestions = false;

                // If it's a new tag not in availableTags, add it for future suggestions
                if (!this.availableTags.includes(tagToAdd)) {
                    this.availableTags.push(tagToAdd);
                    this.availableTags.sort();
                }

                // Auto-save tags when in edit mode
                this.saveTags();
            }
        },

        /**
         * Remove a tag
         */
        removeTag(tag) {
            if (!this.member.tags) {
                this.member.tags = [];
                return;
            }

            const index = this.member.tags.indexOf(tag);
            if (index > -1) {
                this.member.tags.splice(index, 1);
                // Auto-save tags when in edit mode
                this.saveTags();
            }
        },

        /**
         * Save tags to backend
         */
        async saveTags() {
            if (!this.isEditing) return;

            try {
                const memberId = this.member.id || this.$route.params.id;
                const payload = {
                    tags: this.member.tags || [],
                };

                const resp = await axios.put(`members/${memberId}`, payload);

                if (resp && resp.data && resp.data.success) {
                    // Tags saved successfully (silent save)
                }
            } catch (e) {
                // Error saving tags - silently fail
            }
        },

