        /**
         * Initialize Progress Tracker with default date and load existing data
         */
        initializeProgressTracker() {
            // Set default date to today if not set
            if (!this.progressTrackerDate) {
                const today = new Date();
                const year = today.getFullYear();
                const month = String(today.getMonth() + 1).padStart(2, "0");
                const day = String(today.getDate()).padStart(2, "0");
                this.progressTrackerDate = `${year}-${month}-${day}`;
            }
            // Load existing progress data for the member
            this.loadProgressData();
            // Load graph data
            this.loadGraphData();
            // Initialize graph input dates
            if (!this.leftMetricInputDate) {
                const today = new Date();
                const year = today.getFullYear();
                const month = String(today.getMonth() + 1).padStart(2, "0");
                const day = String(today.getDate()).padStart(2, "0");
                this.leftMetricInputDate = `${year}-${month}-${day}`;
            }
            if (!this.rightMetricInputDate) {
                const today = new Date();
                const year = today.getFullYear();
                const month = String(today.getMonth() + 1).padStart(2, "0");
                const day = String(today.getDate()).padStart(2, "0");
                this.rightMetricInputDate = `${year}-${month}-${day}`;
            }
        },

        /**
         * Load progress data for the current member
         */
        async loadProgressData() {
            if (!this.member || !this.member.id) {
                return;
            }

            try {
                // Load start values from member profile
                if (this.member.weight) {
                    const weightMetric = this.progressMetrics.find(
                        (m) => m.type === "Weight"
                    );
                    if (weightMetric) {
                        weightMetric.startValue = parseFloat(
                            this.member.weight
                        );
                    }
                }

                // Load existing progress data for the selected date
                if (this.progressTrackerDate) {
                    const response = await axios.get(
                        `members/${this.member.id}/progress`,
                        {
                            params: {
                                date: this.progressTrackerDate,
                            },
                        }
                    );

                    if (response.data.success && response.data.progress) {
                        // Map the loaded data to progressMetrics
                        response.data.progress.forEach((progressItem) => {
                            const metric = this.progressMetrics.find(
                                (m) => m.type === progressItem.metric_type
                            );
                            if (metric) {
                                metric.value = progressItem.value
                                    ? progressItem.value.toString()
                                    : "";
                                metric.startValue = progressItem.start_value;
                                metric.change = progressItem.change;
                                // Calculate change if not already set
                                if (metric.value && metric.startValue) {
                                    this.calculateMetricChange(metric);
                                }
                            }
                        });
                    }
                }
            } catch (error) {
                // Error loading progress data - silently fail
            }
        },

        calculateMetricChange(metric) {
            if (!metric.value || metric.value === "" || !metric.startValue) {
                metric.change = null;
                return;
            }

            const currentValue = parseFloat(metric.value);
            const startValue = parseFloat(metric.startValue);

            if (isNaN(currentValue) || isNaN(startValue)) {
                metric.change = null;
                return;
            }

            metric.change = currentValue - startValue;
        },

        /**
         * Add a new metric to the progress tracker
         */
        addNewMetric() {
            this.progressMetrics.push({
                type: "New Metric",
                value: "",
                unit: "",
                startValue: null,
                change: null,
            });
        },

        getMetricLabel(key) {
            const metric = this.availableMetrics.find((m) => m.key === key);
            return metric ? metric.label : key;
        },

        /**
         * Get metric unit by key
         */
        getMetricUnit(key) {
            const units = {
                weight: "lbs",
                circumference: "inch",
                fat: "%",
                vo2max: "ml/kg/min",
                bmi: "",
            };
            return units[key] || "";
        },

        /**
         * Format date for display (MM/DD/YYYY)
         */
        formatDateForDisplay(dateString) {
            if (!dateString) return "";
            const date = new Date(dateString);
            const month = String(date.getMonth() + 1).padStart(2, "0");
            const day = String(date.getDate()).padStart(2, "0");
            const year = date.getFullYear();
            return `${month}/${day}/${year}`;
        },

        /**
         * Get left metric data sorted by date (newest first)
         */
        getLeftMetricData() {
            if (!this.selectedLeftMetric) return [];
            const data = this.progressGraphData[this.selectedLeftMetric] || [];
            return [...data].sort(
                (a, b) => new Date(b.date) - new Date(a.date)
            );
        },

        /**
         * Get right metric data sorted by date (newest first)
         */
        getRightMetricData() {
            if (!this.selectedRightMetric) return [];
            const data = this.progressGraphData[this.selectedRightMetric] || [];
            return [...data].sort(
                (a, b) => new Date(b.date) - new Date(a.date)
            );
        },

        /**
         * Toggle left metric visibility on graph
         */
        toggleLeftMetricVisibility() {
            this.leftMetricVisible = !this.leftMetricVisible;
        },

        /**
         * Toggle right metric visibility on graph
         */
        toggleRightMetricVisibility() {
            this.rightMetricVisible = !this.rightMetricVisible;
        },

        /**
         * Add value to left metric
         */
        addLeftMetricValue() {
            if (
                !this.selectedLeftMetric ||
                !this.leftMetricInputValue ||
                !this.leftMetricInputDate
            ) {
                this.showError("Please fill in all fields");
                return;
            }

            const value = parseFloat(this.leftMetricInputValue);
            if (isNaN(value)) {
                this.showError("Please enter a valid number");
                return;
            }

            if (!this.progressGraphData[this.selectedLeftMetric]) {
                this.progressGraphData[this.selectedLeftMetric] = [];
            }

            // Check if entry for this date already exists
            const existingIndex = this.progressGraphData[
                this.selectedLeftMetric
            ].findIndex((item) => item.date === this.leftMetricInputDate);

            if (existingIndex >= 0) {
                // Update existing entry
                this.progressGraphData[this.selectedLeftMetric][
                    existingIndex
                ].value = value;
            } else {
                // Add new entry
                this.progressGraphData[this.selectedLeftMetric].push({
                    date: this.leftMetricInputDate,
                    value: value,
                });
            }

            // Sort by date
            this.progressGraphData[this.selectedLeftMetric].sort(
                (a, b) => new Date(a.date) - new Date(b.date)
            );

            // Clear input
            this.leftMetricInputValue = "";
            this.leftMetricInputDate = null;

            // Save to backend
            this.saveGraphData();
        },

        /**
         * Add value to right metric
         */
        addRightMetricValue() {
            if (
                !this.selectedRightMetric ||
                !this.rightMetricInputValue ||
                !this.rightMetricInputDate
            ) {
                this.showError("Please fill in all fields");
                return;
            }

            const value = parseFloat(this.rightMetricInputValue);
            if (isNaN(value)) {
                this.showError("Please enter a valid number");
                return;
            }

            if (!this.progressGraphData[this.selectedRightMetric]) {
                this.progressGraphData[this.selectedRightMetric] = [];
            }

            // Check if entry for this date already exists
            const existingIndex = this.progressGraphData[
                this.selectedRightMetric
            ].findIndex((item) => item.date === this.rightMetricInputDate);

            if (existingIndex >= 0) {
                // Update existing entry
                this.progressGraphData[this.selectedRightMetric][
                    existingIndex
                ].value = value;
            } else {
                // Add new entry
                this.progressGraphData[this.selectedRightMetric].push({
                    date: this.rightMetricInputDate,
                    value: value,
                });
            }

            // Sort by date
            this.progressGraphData[this.selectedRightMetric].sort(
                (a, b) => new Date(a.date) - new Date(b.date)
            );

            // Clear input
            this.rightMetricInputValue = "";
            this.rightMetricInputDate = null;

            // Save to backend
            this.saveGraphData();
        },

        /**
         * Save graph data to backend
         */
        async saveGraphData() {
            if (!this.member || !this.member.id) {
                return;
            }

            try {
                // Save all graph data entries
                const allProgressData = [];

                Object.keys(this.progressGraphData).forEach((key) => {
                    const metricType = this.getMetricTypeFromKey(key);
                    if (
                        metricType &&
                        this.progressGraphData[key] &&
                        this.progressGraphData[key].length > 0
                    ) {
                        this.progressGraphData[key].forEach((entry) => {
                            allProgressData.push({
                                type: metricType,
                                value: entry.value,
                                unit: this.getMetricUnit(key),
                                date: entry.date,
                            });
                        });
                    }
                });

                // Group by date and save each date's metrics together
                const groupedByDate = {};
                allProgressData.forEach((entry) => {
                    if (!groupedByDate[entry.date]) {
                        groupedByDate[entry.date] = [];
                    }
                    groupedByDate[entry.date].push({
                        type: entry.type,
                        value: entry.value,
                        unit: entry.unit,
                    });
                });

                // Save each date's metrics
                for (const date in groupedByDate) {
                    const progressData = {
                        date: date,
                        metrics: groupedByDate[date],
                    };

                    await axios.post(
                        `members/${this.member.id}/progress`,
                        progressData
                    );
                }
            } catch (error) {
                // Error saving graph data - silently fail
            }
        },

        /**
         * Load graph data from backend
         */
        async loadGraphData() {
            if (!this.member || !this.member.id) {
                return;
            }

            try {
                // Initialize all metric types as empty arrays
                this.progressGraphData = {
                    weight: [],
                    circumference: [],
                    fat: [],
                    vo2max: [],
                    bmi: [],
                };

                const response = await axios.get(
                    `members/${this.member.id}/progress-graph`
                );

                if (response.data.success && response.data.data) {
                    // Map the response data to progressGraphData format
                    Object.keys(response.data.data).forEach((metricType) => {
                        const key = this.getMetricKeyFromType(metricType);
                        if (
                            key &&
                            response.data.data[metricType] &&
                            response.data.data[metricType].length > 0
                        ) {
                            this.progressGraphData[key] =
                                response.data.data[metricType];
                        }
                    });
                }
            } catch (error) {
                // Ensure arrays are initialized even on error
                this.progressGraphData = {
                    weight: [],
                    circumference: [],
                    fat: [],
                    vo2max: [],
                    bmi: [],
                };
            }
        },

        /**
         * Helper method to convert metric type to key
         */
        getMetricKeyFromType(type) {
            const typeMap = {
                Weight: "weight",
                "Circumference - waist navel": "circumference",
                "Fat percentage - total": "fat",
                VO2max: "vo2max",
                "Body Mass Index (BMI)": "bmi",
            };
            return typeMap[type] || null;
        },

        /**
         * Helper method to convert key to metric type
         */
        getMetricTypeFromKey(key) {
            const keyMap = {
                weight: "Weight",
                circumference: "Circumference - waist navel",
                fat: "Fat percentage - total",
                vo2max: "VO2max",
                bmi: "Body Mass Index (BMI)",
            };
            return keyMap[key] || null;
        },

        /**
         * Save progress values
         */
        async saveProgressValues() {
            if (!this.member || !this.member.id) {
                this.showError("Member ID is required");
                return;
            }

            if (!this.progressTrackerDate) {
                this.showError("Please select a date");
                return;
            }

            this.isSavingProgress = true;

            try {
                // Calculate changes for all metrics
                this.progressMetrics.forEach((metric) => {
                    this.calculateMetricChange(metric);
                });

                // Prepare data for API
                const progressData = {
                    date: this.progressTrackerDate,
                    metrics: this.progressMetrics.map((metric) => ({
                        type: metric.type,
                        value: metric.value ? parseFloat(metric.value) : null,
                        unit: metric.unit,
                        start_value: metric.startValue,
                        change: metric.change,
                    })),
                };

                const response = await axios.post(
                    `members/${this.member.id}/progress`,
                    progressData
                );

                if (response.data.success) {
                    this.$swal({
                        title: "Success!",
                        text: "Progress values saved successfully",
                        icon: "success",
                        confirmButtonText: "OK",
                        confirmButtonColor: "#dc3545",
                    });
                } else {
                    throw new Error(
                        response.data.message ||
                            "Failed to save progress values"
                    );
                }
            } catch (error) {
                this.showError(
                    "Failed to save progress values: " +
                        (error.response?.data?.message || error.message)
                );
            } finally {
                this.isSavingProgress = false;
            }
        },

