        /**
         * Save profile changes to the server
         * Updates member information via API call
         */
        async saveProfile() {
            try {
                this.isSaving = true;
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                // Prepare the data for update - match backend field names exactly
                // Get firstname and lastname from the form (they may be edited)
                const firstname =
                    this.member.firstname || this.member.first_name || "";
                const lastname =
                    this.member.lastname || this.member.last_name || "";

                const updateData = {
                    // Include both firstname/lastname and first_name/last_name for compatibility
                    firstname: firstname,
                    lastname: lastname,
                    first_name: firstname,
                    last_name: lastname,
                    membername:
                        this.member.membername ||
                        `${firstname} ${lastname}`.trim() ||
                        `${this.member.first_name || ""} ${
                            this.member.last_name || ""
                        }`.trim(),
                    email: this.member.email,
                    mobile_phone: this.member.mobile_phone,
                    landline_phone: this.member.landline_phone, // Fixed: was landline_number
                    language: this.member.language,
                    gender: this.member.gender || this.member.sex,
                    Statuses: this.member.Statuses || this.member.status,
                    subscription_plan_id:
                        this.member.subscription_plan_id !== null &&
                        this.member.subscription_plan_id !== undefined &&
                        this.member.subscription_plan_id !== ""
                            ? parseInt(this.member.subscription_plan_id)
                            : null,
                    Expires: this.member.Expires || this.member.end_date,
                    profile_image: this.member.profile_image,
                    address: this.member.address,
                    city: this.member.city,
                    zipcode: this.member.zipcode || this.member.zip,
                    date_of_birth:
                        this.member.date_of_birth ||
                        this.member.dob ||
                        this.member.birthday,
                    height: this.member.height,
                    weight: this.member.weight,
                    medical_condition:
                        this.member.medical_condition || this.member.medical,
                    contact_name: this.member.contact_name,
                    contact_phone: this.member.contact_phone,
                    start_date: this.member.start_date,
                    end_date: this.member.end_date,
                    // Additional fields
                    own_member_id:
                        this.member.own_member_id &&
                        this.member.own_member_id.trim()
                            ? this.member.own_member_id.trim()
                            : null,
                    custom_export_field:
                        this.member.custom_export_field &&
                        this.member.custom_export_field.trim()
                            ? this.member.custom_export_field.trim()
                            : null,
                    subscription_reason:
                        this.member.subscription_reason || "Unknown",
                    source: this.member.source || "Unknown",
                    is_business:
                        this.member.hasBusiness ||
                        this.member.is_business ||
                        "No",
                    hasBusiness:
                        this.member.hasBusiness ||
                        this.member.is_business ||
                        "No",
                    business_type: this.member.business_type || "",
                    mandate_id: this.member.mandate_id || "",
                    bank_account_type: this.member.bank_account_type || "",
                    bank_name: this.member.bank_name || "",
                    tags: this.member.tags || [],
                };

                // Filter out empty strings, null, and undefined values to prevent overwriting existing data
                // Only keep fields that have actual values (except for explicitly nullable fields)
                const filteredUpdateData = {};
                for (const [key, value] of Object.entries(updateData)) {
                    // Always include required fields (membername, email) even if empty
                    if (key === "membername" || key === "email") {
                        filteredUpdateData[key] =
                            value !== undefined ? value : "";
                        continue;
                    }

                    // Include firstname/lastname only if they have values (not empty strings)
                    if (
                        key === "firstname" ||
                        key === "lastname" ||
                        key === "first_name" ||
                        key === "last_name"
                    ) {
                        if (
                            value !== null &&
                            value !== undefined &&
                            value !== ""
                        ) {
                            filteredUpdateData[key] = value;
                        }
                        continue;
                    }

                    // For nullable fields, only include if they have a value (not empty string, null, or undefined)
                    // For arrays, include if array exists and has length > 0
                    if (Array.isArray(value)) {
                        if (value.length > 0) {
                            filteredUpdateData[key] = value;
                        }
                    } else if (
                        value !== null &&
                        value !== undefined &&
                        value !== ""
                    ) {
                        filteredUpdateData[key] = value;
                    }
                    // For numeric fields that might be 0, include them
                    else if (key === "height" || key === "weight") {
                        if (
                            value !== null &&
                            value !== undefined &&
                            value !== ""
                        ) {
                            filteredUpdateData[key] = value;
                        }
                    }
                    // For subscription_plan_id, include it even if it's 0 or empty string (to allow clearing the plan)
                    else if (key === "subscription_plan_id") {
                        if (value !== null && value !== undefined) {
                            filteredUpdateData[key] =
                                value === "" ? null : value;
                        }
                    }
                }

                // Send update request with filtered data
                const response = await axios.put(
                    `/members/${memberId}`,
                    filteredUpdateData
                );

                if (response.data.success) {
                    this.isEditing = false;
                    this.showSuccess("Profile updated successfully!");
                    // Ensure plans are loaded before refreshing member data
                    if (this.plans.length === 0) {
                        await this.loadPlans();
                    }
                    // Refresh the data
                    await this.fetchmemberData();
                } else {
                    this.showError("Failed to update profile");
                }
            } catch (error) {
                const errorMessage = this.parseErrorMessage(error);
                this.showError(errorMessage);
            } finally {
                this.isSaving = false;
            }
        },

        async saveNutrition() {
            try {
                this.isSaving = true;
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                // Validate required fields
                if (!this.nutritionData.nutrition_plan) {
                    this.showError("Please select a nutrition plan");
                    return;
                }

                if (!this.nutritionData.start_date) {
                    this.showError("Please select a start date");
                    return;
                }

                // Find the template_id from the selected plan name
                const selectedPlan = this.nutritionPlans.find(
                    (plan) => plan.name === this.nutritionData.nutrition_plan
                );

                if (!selectedPlan || !selectedPlan.id) {
                    this.showError("Please select a valid nutrition plan");
                    return;
                }

                if (!this.editingNutritionId) {
                    // Check for existing active assignments with the same template
                    const existingPlan = this.memberNutritionPlans.find(
                        (plan) =>
                            plan.template_id === selectedPlan.id &&
                            (plan.status === "active" ||
                                plan.status === "pending")
                    );

                    if (existingPlan) {
                        this.showError(
                            `This member already has an active nutrition plan "${this.nutritionData.nutrition_plan}". Please choose a different plan or update the existing one.`
                        );
                        return;
                    }
                }

                // Prepare the data for saving using the new assignment system
                const nutritionData = {
                    template_id: selectedPlan.id, // Use template_id instead of plan name
                    member_id: memberId,
                    start_date: this.nutritionData.start_date,
                    duration: this.nutritionData.duration || null,
                    description: this.nutritionData.description || null,
                };

                let response;
                if (this.editingNutritionId) {
                    // For updates, we need to check if it's from the new system or old system
                    // For now, show a message that editing needs to be done via delete and reassign
                    this.showError(
                        "Editing assigned plans is not yet supported. Please delete and reassign."
                    );
                    return;
                } else {
                    // Use the same assignment endpoint as Nutrition Hub
                    response = await axios.post(
                        `nutrition/assign`,
                        nutritionData
                    );
                }

                if (response.data.success) {
                    const action = this.editingNutritionId
                        ? "updated"
                        : "saved";
                    this.showSuccess(`Nutrition plan ${action} successfully!`);

                    // Reset form
                    this.nutritionData = {
                        nutrition_plan: "",
                        start_date: "",
                        duration: "",
                        description: "",
                        type: "",
                        status: "active",
                        price: "0",
                        paymentFrequency: "",
                        features: "No features",
                        notes: "No notes",
                    };
                    this.editingNutritionId = null;

                    // Close the nutrition action
                    this.activeAction = null;
                    // Reload member nutrition plans
                    await this.loadMemberNutritionPlans();
                    // Also reload meal plans to keep them in sync
                    await this.fetchMemberMealPlans();
                } else {
                    this.showError(
                        response.data.message || "Failed to save nutrition plan"
                    );
                }
            } catch (error) {
                // Show more specific error message
                if (
                    error.response &&
                    error.response.data &&
                    error.response.data.message
                ) {
                    this.showError(error.response.data.message);
                } else if (
                    error.response &&
                    error.response.data &&
                    error.response.data.errors
                ) {
                    // Handle validation errors
                    const errorMessages = Object.values(
                        error.response.data.errors
                    ).flat();
                    this.showError(errorMessages.join(", "));
                } else {
                    this.showError(
                        "Error saving nutrition plan. Please try again."
                    );
                }
            } finally {
                this.isSaving = false;
            }
        },

