        populateSettingsData() {
            // Ensure firstname and lastname are populated from first_name and last_name (and vice versa)
            // Sync firstname <-> first_name
            if (this.member.firstname && !this.member.first_name) {
                this.member.first_name = this.member.firstname;
            } else if (this.member.first_name && !this.member.firstname) {
                this.member.firstname = this.member.first_name;
            } else if (this.member.firstname && this.member.first_name) {
                // If both exist, prefer firstname (form field) but keep them in sync
                this.member.first_name = this.member.firstname;
            }

            // Sync lastname <-> last_name
            if (this.member.lastname && !this.member.last_name) {
                this.member.last_name = this.member.lastname;
            } else if (this.member.last_name && !this.member.lastname) {
                this.member.lastname = this.member.last_name;
            } else if (this.member.lastname && this.member.last_name) {
                // If both exist, prefer lastname (form field) but keep them in sync
                this.member.last_name = this.member.lastname;
            }

            // Populate birthday from member data
            if (this.member.date_of_birth) {
                const date = new Date(this.member.date_of_birth);
                this.birthday.month = date.toLocaleString("default", {
                    month: "long",
                });
                this.birthday.day = date.getDate();
                this.birthday.year = date.getFullYear();
            }

            // Load units preferences from backend
            if (this.member.preferred_length_unit) {
                this.units.length = this.member.preferred_length_unit;
            }
            if (this.member.preferred_weight_unit) {
                this.units.weight = this.member.preferred_weight_unit;
            }

            // Height: member.height is stored canonically as centimeters.
            // Convert centimeters to feet/inches for display, or fall back
            // to stored feet/inches if those fields are present.
            if (this.member.height) {
                const heightCm = parseFloat(this.member.height);
                if (!isNaN(heightCm)) {
                    const totalInches = heightCm / 2.54;
                    this.height.feet = Math.floor(totalInches / 12);
                    this.height.inches = Math.round(totalInches % 12);
                }
            } else if (
                this.member.height_feet !== null &&
                this.member.height_feet !== undefined
            ) {
                // If height is stored separately as feet and inches
                this.height.feet = parseInt(this.member.height_feet) || null;
                this.height.inches =
                    parseInt(this.member.height_inches) || null;
            }

            // Weight: member.weight is stored canonically as kilograms.
            // Convert to the appropriate display unit based on preference.
            if (this.member.weight) {
                const weightKg = parseFloat(this.member.weight);
                if (!isNaN(weightKg)) {
                    if (this.units.weight === "pounds") {
                        this.weight = parseFloat(
                            (weightKg * 2.20462262).toFixed(1)
                        );
                    } else {
                        this.weight = weightKg;
                    }
                }
            }
        },

        async savePersonalSettings() {
            try {
                this.isSaving = true;

                // Validate subscription_plan_id if provided
                if (this.member.subscription_plan_id) {
                    const planId = parseInt(this.member.subscription_plan_id);
                    if (this.plans.length > 0) {
                        const planExists = this.plans.find(
                            (p) => p.id === planId
                        );
                        if (!planExists) {
                            this.showError(
                                "The selected subscription plan is invalid. Please select a valid plan."
                            );
                            return;
                        }
                    }
                }

                // Compose date_of_birth from dropdowns if present
                let date_of_birth = this.member.date_of_birth;
                if (
                    this.birthday.year &&
                    this.birthday.month &&
                    this.birthday.day
                ) {
                    const monthIndex =
                        this.months.findIndex(
                            (m) => m.value === this.birthday.month
                        ) + 1;
                    const mm = String(monthIndex).padStart(2, "0");
                    const dd = String(this.birthday.day).padStart(2, "0");
                    date_of_birth = `${this.birthday.year}-${mm}-${dd}`;
                }

                // Convert height ft/in to centimeters for storage
                let heightVal = this.member.height;
                if (this.height.feet != null || this.height.inches != null) {
                    const feet = Number(this.height.feet || 0);
                    const inches = Number(this.height.inches || 0);
                    const totalInches = feet * 12 + inches;

                    // Always store canonical height in centimeters
                    heightVal =
                        totalInches > 0 ? totalInches * 2.54 : null;
                }

                // Weight - store canonical value in kilograms
                let weightVal = this.member.weight;
                if (this.weight != null) {
                    if (this.units.weight === "pounds") {
                        // Convert pounds to kilograms
                        weightVal = this.weight / 2.20462262;
                    } else {
                        weightVal = this.weight;
                    }
                }

                // Get firstname and lastname from the form (they may be edited)
                const firstname =
                    this.member.firstname || this.member.first_name || "";
                const lastname =
                    this.member.lastname || this.member.last_name || "";

                const payload = {
                    // Include both firstname/lastname and first_name/last_name for compatibility
                    firstname: firstname,
                    lastname: lastname,
                    first_name: firstname,
                    last_name: lastname,
                    membername:
                        this.member.membername ||
                        `${firstname} ${lastname}`.trim(),
                    email: this.member.email,
                    mobile_phone: this.member.mobile_phone,
                    landline_phone: this.member.landline_phone,
                    language: this.member.language,
                    date_of_birth,
                    gender: this.member.gender,
                    address: this.member.address,
                    city: this.member.city,
                    zipcode: this.member.zipcode || this.member.zip,
                    height: heightVal,
                    weight: weightVal,
                    preferred_length_unit: this.units.length,
                    preferred_weight_unit: this.units.weight,
                    height_feet: this.height.feet,
                    height_inches: this.height.inches,
                    tags: this.member.tags || [],
                    own_member_id: this.member.own_member_id || "",
                    custom_export_field: this.member.custom_export_field || "",
                    subscription_reason:
                        this.member.subscription_reason || "Unknown",
                    source: this.member.source || "Unknown",
                    is_business:
                        this.member.hasBusiness ||
                        this.member.is_business ||
                        "No",
                    hasBusiness:
                        this.member.hasBusiness ||
                        this.member.is_business ||
                        "No",
                    business_type:
                        this.member.hasBusiness === "Yes" ||
                        this.member.is_business === "Yes"
                            ? this.member.business_type || ""
                            : "",
                    mandate_id: this.member.mandate_id || "",
                    bank_account_type: this.member.bank_account_type || "",
                    bank_name: this.member.bank_name || "",
                    routing_number: this.member.routing_number || "",
                    subscription_plan_id:
                        this.member.subscription_plan_id || null,
                };

                const memberId = this.member.id || this.$route.params.id;
                const resp = await axios.put(`members/${memberId}`, payload);
                if (resp && resp.data && resp.data.success) {
                    this.showSuccess("Settings saved successfully");
                    // Sync local member
                    this.member = {
                        ...this.member,
                        date_of_birth,
                        height: heightVal,
                        weight: weightVal,
                        preferred_length_unit: this.units.length,
                        preferred_weight_unit: this.units.weight,
                        height_feet: this.height.feet,
                        height_inches: this.height.inches,
                    };
                } else {
                    this.showError(
                        "Failed to save settings. Please try again."
                    );
                }
            } catch (e) {
                const errorMessage = this.parseErrorMessage(e);
                this.showError(errorMessage);
            } finally {
                this.isSaving = false;
            }
        },

        /**
         * Start editing user profile email
         */
        startEditingUserProfileEmail() {
            this.editedUserProfileEmail = this.member.email || "";
            this.isEditingUserProfileEmail = true;
        },

        /**
         * Cancel editing user profile email
         */
        cancelEditingUserProfileEmail() {
            this.isEditingUserProfileEmail = false;
            this.editedUserProfileEmail = "";
        },

        /**
         * Save user profile email
         */
        async saveUserProfileEmail() {
            // Validate email
            if (
                !this.editedUserProfileEmail ||
                !this.editedUserProfileEmail.trim()
            ) {
                this.showError("Email address cannot be empty");
                return;
            }

            // Basic email validation
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(this.editedUserProfileEmail.trim())) {
                this.showError("Please enter a valid email address");
                return;
            }

            // Check if email has changed
            if (this.editedUserProfileEmail.trim() === this.member.email) {
                this.cancelEditingUserProfileEmail();
                return;
            }

            this.isSavingUserProfileEmail = true;
            try {
                const memberId = this.member.id || this.$route.params.id;
                const payload = {
                    membername:
                        this.member.membername ||
                        `${this.member.firstname || ""} ${
                            this.member.lastname || ""
                        }`.trim() ||
                        this.member.name ||
                        "Member",
                    email: this.editedUserProfileEmail.trim(),
                };

                const resp = await axios.put(`members/${memberId}`, payload);

                if (resp && resp.data && resp.data.success) {
                    // Update local member data
                    this.member.email = this.editedUserProfileEmail.trim();
                    this.showSuccess("Email address updated successfully");
                    this.isEditingUserProfileEmail = false;
                    this.editedUserProfileEmail = "";
                } else {
                    this.showError("Failed to update email address");
                }
            } catch (e) {
                const errorMessage = this.parseErrorMessage(e);
                this.showError(errorMessage);
            } finally {
                this.isSavingUserProfileEmail = false;
            }
        },

        /**
         * Format date for display (MM/DD/YYYY)
         */
        formatDisplayDate(date) {
            if (!date) return "-";
            const d = new Date(date);
            if (isNaN(d.getTime())) return date; // Return as-is if invalid date
            const month = String(d.getMonth() + 1).padStart(2, "0");
            const day = String(d.getDate()).padStart(2, "0");
            const year = d.getFullYear();
            return `${month}/${day}/${year}`;
        },

        /**
         * Start editing membership end date
         */
        startEditingMembershipEndDate() {
            // Use end_date or Expires, format for date input (YYYY-MM-DD)
            const endDate = this.member.end_date || this.member.Expires;
            if (endDate) {
                const d = new Date(endDate);
                if (!isNaN(d.getTime())) {
                    const year = d.getFullYear();
                    const month = String(d.getMonth() + 1).padStart(2, "0");
                    const day = String(d.getDate()).padStart(2, "0");
                    this.editedMembershipEndDate = `${year}-${month}-${day}`;
                } else {
                    this.editedMembershipEndDate = "";
                }
            } else {
                // If no end date, calculate based on plan interval
                this.calculateEndDateFromPlan();
            }
            this.isEditingMembershipEndDate = true;
        },

        /**
         * Calculate end date based on plan interval (month/year)
         */
        calculateEndDateFromPlan() {
            const plan = this.currentPlanDetails;
            if (!plan || !this.member.start_date) {
                this.editedMembershipEndDate = "";
                return;
            }

            const startDate = new Date(this.member.start_date);
            if (isNaN(startDate.getTime())) {
                this.editedMembershipEndDate = "";
                return;
            }

            let endDate = new Date(startDate);

            // Check plan interval
            if (plan.interval === "year" || plan.interval === "yearly") {
                endDate.setFullYear(endDate.getFullYear() + 1);
                // Set to last day of the year
                endDate.setMonth(11, 31);
            } else {
                // Default to monthly - set to last day of the month
                endDate.setMonth(endDate.getMonth() + 1, 0);
            }

            const year = endDate.getFullYear();
            const month = String(endDate.getMonth() + 1).padStart(2, "0");
            const day = String(endDate.getDate()).padStart(2, "0");
            this.editedMembershipEndDate = `${year}-${month}-${day}`;
        },

        /**
         * Cancel editing membership end date
         */
        cancelEditingMembershipEndDate() {
            this.isEditingMembershipEndDate = false;
            this.editedMembershipEndDate = "";
        },

        /**
         * Save membership end date
         */
        async saveMembershipEndDate() {
            if (
                !this.editedMembershipEndDate ||
                !this.editedMembershipEndDate.trim()
            ) {
                this.showError("End date cannot be empty");
                return;
            }

            // Validate date
            const dateObj = new Date(this.editedMembershipEndDate);
            if (isNaN(dateObj.getTime())) {
                this.showError("Please enter a valid date");
                return;
            }

            // Check if date has changed
            const currentEndDate = this.member.end_date || this.member.Expires;
            if (currentEndDate) {
                const currentDate = new Date(currentEndDate)
                    .toISOString()
                    .split("T")[0];
                if (currentDate === this.editedMembershipEndDate) {
                    this.cancelEditingMembershipEndDate();
                    return;
                }
            }

            this.isSavingMembershipEndDate = true;
            try {
                const memberId = this.member.id || this.$route.params.id;
                const payload = {
                    end_date: this.editedMembershipEndDate,
                    Expires: this.editedMembershipEndDate, // Also update Expires field
                };

                const resp = await axios.put(`members/${memberId}`, payload);

                if (resp && resp.data && resp.data.success) {
                    // Update local member data
                    this.member.end_date = this.editedMembershipEndDate;
                    this.member.Expires = this.editedMembershipEndDate;
                    this.showSuccess(
                        "Membership end date updated successfully"
                    );
                    this.isEditingMembershipEndDate = false;
                    this.editedMembershipEndDate = "";
                } else {
                    this.showError("Failed to update membership end date");
                }
            } catch (e) {
                const errorMessage = this.parseErrorMessage(e);
                this.showError(errorMessage);
            } finally {
                this.isSavingMembershipEndDate = false;
            }
        },

        /**
         * Get the icon class for a specific action
         * @param {string} action - The action key
         * @returns {string} FontAwesome icon class
         */
        getActionIcon(action) {
            const actionMap = {
                profile: "fa-user",
                goToProfile: "fa-user-edit",
                sendMessage: "fa-envelope",
                newTask: "fa-tasks",
                assignTrainer: "fa-dumbbell",
                nutrition: "fa-crown",
            };
            return actionMap[action] || "fa-cog";
        },

        /**
         * Get the display title for a specific action
         * @param {string} action - The action key
         * @returns {string} Display title
         */
        getActionTitle(action) {
            const titleMap = {
                profile: "Profile Information",
                goToProfile: "Edit Profile",
                sendMessage: "Send Message",
                newTask: "Create New Task",
                assignTrainer: "Assign Trainer",
                nutrition: "Nutrition Details",
            };
            return titleMap[action] || "Action";
        },

        handleProfileImageClick() {
            if (this.isEditing) {
                // Create a new file input element programmatically
                const fileInput = document.createElement("input");
                fileInput.type = "file";
                fileInput.accept = "image/*";
                fileInput.style.display = "none";

                // Add event listener
                fileInput.addEventListener("change", (event) => {
                    this.handleImageUpload(event);
                    // Remove the element after use
                    document.body.removeChild(fileInput);
                });

                // Add to DOM temporarily
                document.body.appendChild(fileInput);

                // Trigger the file selection
                fileInput.click();
            }
        },
        /**
         * Handle profile image upload
         * Creates a preview URL for the selected image
         * @param {Event} event - File input change event
         */
        handleImageUpload(event) {
            const file = event.target.files[0];
            if (file) {
                // Validate file type
                if (!file.type.startsWith("image/")) {
                    this.makeToast("warning", "Please select a valid image file.", "Warning");
                    return;
                }

                if (file.size > 5 * 1024 * 1024) {
                    this.makeToast("warning", "Image size should be less than 5MB.", "Warning");
                    return;
                }

                // Convert file to base64 for storage
                const reader = new FileReader();
                reader.onload = (e) => {
                    // Store the base64 data URL for the server
                    this.member.profile_image = e.target.result;
                };
                reader.readAsDataURL(file);

                // Show success message
                this.showSuccess("Profile image updated successfully!");
            }
        },

        async saveTask() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                // Validate required fields
                if (!this.newTask.task || !this.newTask.task.trim()) {
                    this.showError("Task title is required");
                    return;
                }
                if (!this.newTask.category) {
                    this.showError("Category is required");
                    return;
                }
                if (!this.newTask.priority) {
                    this.showError("Priority is required");
                    return;
                }
                if (!this.newTask.dueDate) {
                    this.showError("Due date is required");
                    return;
                }

                // Store editingTaskId in a local variable to prevent it from being reset
                // Check both editingTaskId and ensure it's a valid number
                let currentEditingTaskId = null;
                if (
                    this.editingTaskId !== null &&
                    this.editingTaskId !== undefined
                ) {
                    const parsed = parseInt(this.editingTaskId);
                    if (!isNaN(parsed) && parsed > 0) {
                        currentEditingTaskId = parsed;
                    }
                }

                // Determine if we're creating or updating
                const isUpdate =
                    currentEditingTaskId && !isNaN(currentEditingTaskId);

                // Clear previous validation errors
                this.taskFieldErrors = {};

                // Frontend validation before calling API
                let isValid = true;

                // Validate Task Title (Task Name)
                if (!this.newTask.task || !this.newTask.task.trim()) {
                    this.taskFieldErrors.task =
                        "Please enter a task name. This field cannot be empty.";
                    isValid = false;
                } else if (this.newTask.task.trim().length < 2) {
                    this.taskFieldErrors.task =
                        "Task name must be at least 2 characters long.";
                    isValid = false;
                } else if (this.newTask.task.trim().length > 255) {
                    this.taskFieldErrors.task =
                        "Task name is too long. Please keep it under 255 characters.";
                    isValid = false;
                }

                // Validate Category
                if (!this.newTask.category || this.newTask.category === "") {
                    this.taskFieldErrors.category =
                        "Please select a category for this task.";
                    isValid = false;
                }

                // Validate Priority
                if (!this.newTask.priority || this.newTask.priority === "") {
                    this.taskFieldErrors.priority =
                        "Please select a priority level for this task.";
                    isValid = false;
                }

                // Validate Due Date
                if (!this.newTask.dueDate || this.newTask.dueDate === "") {
                    this.taskFieldErrors.dueDate =
                        "Please select a due date for this task.";
                    isValid = false;
                } else {
                    // Validate date format
                    const selectedDate = new Date(this.newTask.dueDate);
                    if (isNaN(selectedDate.getTime())) {
                        this.taskFieldErrors.dueDate =
                            "Please enter a valid due date.";
                        isValid = false;
                    }
                    // Optional: Validate date is not too far in the past (more than 1 year)
                    const today = new Date();
                    today.setHours(0, 0, 0, 0);
                    const oneYearAgo = new Date(today);
                    oneYearAgo.setFullYear(today.getFullYear() - 1);
                    if (selectedDate < oneYearAgo) {
                        this.taskFieldErrors.dueDate =
                            "Due date cannot be more than 1 year in the past.";
                        isValid = false;
                    }
                }

                // If validation failed, show error and return
                if (!isValid) {
                    const errorCount = Object.keys(this.taskFieldErrors).length;
                    const errorFields = Object.keys(this.taskFieldErrors);

                    // Create a more helpful error message
                    let errorMessage = `Please complete the required fields before saving. `;
                    if (errorFields.includes("task")) {
                        errorMessage += `Task name is required. `;
                    }
                    if (errorFields.includes("category")) {
                        errorMessage += `Category is required. `;
                    }
                    if (errorFields.includes("priority")) {
                        errorMessage += `Priority is required. `;
                    }
                    if (errorFields.includes("dueDate")) {
                        errorMessage += `Due date is required.`;
                    }

                    this.showError(errorMessage.trim());

                    // Scroll to first error field
                    this.$nextTick(() => {
                        const firstError = document.querySelector(
                            ".task-field-error, .form-input.is-invalid, .form-select.is-invalid"
                        );
                        if (firstError) {
                            firstError.scrollIntoView({
                                behavior: "smooth",
                                block: "center",
                            });
                            const input =
                                firstError.querySelector("input, select") ||
                                firstError;
                            if (input && input.focus) {
                                input.focus();
                            }
                        }
                    });
                    return;
                }

                // Map newTask to the API format for tasks table
                // Backend expects camelCase for dueDate (not snake_case due_date)
                const taskData = {
                    title: this.newTask.task.trim(),
                    category: this.newTask.category,
                    priority: this.newTask.priority,
                    dueDate: this.newTask.dueDate, // Backend expects camelCase 'dueDate'
                    description: this.newTask.details || "",
                    assignedTo: this.newTask.assignedToUserId || null, // Backend expects camelCase 'assignedTo'
                    status: this.newTask.isComplete ? "completed" : "pending",
                    member_id: memberId, // Ensure member_id is set for member tasks
                    task_type: "member", // Set task type to 'member' for member tasks
                    due_hour: this.newTask.due_hour,
                    due_minute: this.newTask.due_minute,
                    duration: this.newTask.duration,
                };

                let response;
                if (isUpdate) {
                    // Update existing task
                    response = await axios.put(
                        `members/${memberId}/tasks/${currentEditingTaskId}`,
                        taskData
                    );
                } else {
                    // Create new task
                    response = await axios.post(
                        `members/${memberId}/create-task`,
                        taskData
                    );
                }

                if (response && response.data && response.data.success) {
                    const action = currentEditingTaskId ? "updated" : "created";
                    this.showSuccess(
                        response.data.message || `Task ${action} successfully!`
                    );

                    // Clear validation errors
                    this.taskFieldErrors = {};

                    // Reset form and editing state
                    this.newTask = {
                        task: "",
                        category: "",
                        priority: "",
                        details: "",
                        // concerns: "", // Commented out - not in database
                        assignedToUserId: null,
                        isComplete: false,
                        dueDate: "",
                        // time: "", // Commented out - not in database
                        // duration: "", // Commented out - not in database
                    };
                    this.editingTaskId = null;
                    this.showTaskDetails = false;

                    // Refresh the tasks table with a small delay to ensure database has committed
                    // This helps prevent fetching tasks before they're fully saved
                    await new Promise((resolve) => setTimeout(resolve, 300));
                    await this.fetchMemberTasks();

                    // Close the task form
                    this.activeAction = null;
                } else {
                    const errorMsg =
                        response?.data?.message || "Failed to save task";
                    this.showError(errorMsg);
                }
            } catch (error) {
                // Clear any previous field errors
                this.taskFieldErrors = {};

                if (error.response) {
                    // Handle validation errors (422)
                    if (
                        error.response.status === 422 &&
                        error.response.data &&
                        error.response.data.errors
                    ) {
                        const errors = error.response.data.errors;

                        // Map API field names to frontend field names
                        const fieldMapping = {
                            title: "task",
                            dueDate: "dueDate",
                            category: "category",
                            priority: "priority",
                            status: "status",
                            description: "details",
                            assignedTo: "assignedToUserId",
                        };

                        // Set field errors for display
                        Object.keys(errors).forEach((apiField) => {
                            const frontendField =
                                fieldMapping[apiField] || apiField;
                            const errorMessages = errors[apiField];

                            // Get user-friendly field name
                            const fieldLabels = {
                                task: "Task name",
                                dueDate: "Due date",
                                category: "Category",
                                priority: "Priority",
                                status: "Status",
                                details: "Description",
                                assignedToUserId: "Assigned to",
                            };

                            // Convert Laravel validation messages to user-friendly messages
                            let friendlyMessage = errorMessages[0];
                            if (friendlyMessage === "validation.required") {
                                friendlyMessage = `${
                                    fieldLabels[frontendField] || frontendField
                                } is required.`;
                            } else if (friendlyMessage === "validation.date") {
                                friendlyMessage = `Please enter a valid date.`;
                            } else if (
                                friendlyMessage === "validation.string"
                            ) {
                                friendlyMessage = `${
                                    fieldLabels[frontendField] || frontendField
                                } must be text.`;
                            } else if (
                                friendlyMessage.includes("validation.max")
                            ) {
                                friendlyMessage = `${
                                    fieldLabels[frontendField] || frontendField
                                } is too long.`;
                            } else if (
                                friendlyMessage.includes("validation.in")
                            ) {
                                friendlyMessage = `Invalid ${
                                    fieldLabels[frontendField] || frontendField
                                } value.`;
                            }

                            this.taskFieldErrors[frontendField] =
                                friendlyMessage;
                        });

                        // Show toast with summary
                        const errorCount = Object.keys(
                            this.taskFieldErrors
                        ).length;
                        const errorFields = Object.keys(this.taskFieldErrors);
                        let errorMessage = `Please fix ${errorCount} ${
                            errorCount === 1 ? "error" : "errors"
                        }: `;
                        errorMessage += errorFields
                            .map((field) => {
                                const labels = {
                                    task: "Task name",
                                    dueDate: "Due date",
                                    category: "Category",
                                    priority: "Priority",
                                };
                                return labels[field] || field;
                            })
                            .join(", ");

                        this.showError(errorMessage);

                        // Scroll to first error field
                        this.$nextTick(() => {
                            const firstError = document.querySelector(
                                ".task-field-error, .form-input.is-invalid, .form-select.is-invalid"
                            );
                            if (firstError) {
                                firstError.scrollIntoView({
                                    behavior: "smooth",
                                    block: "center",
                                });
                                const input =
                                    firstError.querySelector("input, select") ||
                                    firstError;
                                if (input && input.focus) {
                                    input.focus();
                                }
                            }
                        });
                    } else if (
                        error.response.data &&
                        error.response.data.message
                    ) {
                        // Handle other API error messages
                        this.showError(error.response.data.message);
                    } else if (error.response.status === 404) {
                        this.showError(
                            "Task not found. It may have been deleted."
                        );
                    } else if (error.response.status === 401) {
                        this.showError(
                            "You are not authorized to perform this action. Please log in again."
                        );
                    } else if (error.response.status === 403) {
                        this.showError(
                            "You don't have permission to perform this action."
                        );
                    } else if (error.response.status === 500) {
                        this.showError(
                            "Server error occurred. Please try again later or contact support."
                        );
                    } else {
                        this.showError(
                            `Error saving task: ${error.response.status} ${
                                error.response.statusText || "Unknown error"
                            }`
                        );
                    }
                } else if (error.request) {
                    // Network error
                    this.showError(
                        "Network error. Please check your internet connection and try again."
                    );
                } else {
                    // Other errors
                    this.showError(
                        "An unexpected error occurred. Please try again."
                    );
                }
            }
        },

        /**
         * Format date string for HTML date input fields
         * Converts date to YYYY-MM-DD format
         * @param {string} dateString - Date string to format
         * @returns {string} Formatted date string or empty string
         */
        formatDateForInput(dateString) {
            if (!dateString) return "";
            // Convert date string to YYYY-MM-DD format for input fields
            const date = new Date(dateString);
            if (isNaN(date.getTime())) return "";
            return date.toISOString().split("T")[0];
        },

        /**
         * Format all date fields for input display
         * Ensures all date fields are properly formatted for HTML date inputs
         */
        formatDateFieldsForInput() {
            // Format date fields for input display
            if (this.member.dob) {
                this.member.dob = this.formatDateForInput(this.member.dob);
            }
            if (this.member.birthday) {
                this.member.birthday = this.formatDateForInput(
                    this.member.birthday
                );
            }
            if (this.member.date_of_birth) {
                this.member.date_of_birth = this.formatDateForInput(
                    this.member.date_of_birth
                );
            }
            if (this.member.start_date) {
                this.member.start_date = this.formatDateForInput(
                    this.member.start_date
                );
            }
            if (this.member.end_date) {
                this.member.end_date = this.formatDateForInput(
                    this.member.end_date
                );
            }
        },

        async fetchAvailableTrainers() {
            try {
                this.isLoadingTrainers = true;
                const response = await axios.get("coaches");

                if (response.data && response.data.members) {
                    // Transform the data to match our expected format
                    this.availableTrainers = response.data.members.map(
                        (trainer) => ({
                            id: trainer.id,
                            name: trainer.name,
                            specialization:
                                trainer.specialization || "General Training",
                        })
                    );
                } else {
                    this.availableTrainers = [];
                }
            } catch (error) {
                this.showError("Failed to load trainers. Please try again.");
                this.availableTrainers = [];
            } finally {
                this.isLoadingTrainers = false;
            }
        },

        /**
         * Fetch existing trainer assignment for the member
         * Populates the trainer form with current assignment data
         */
        async fetchTrainerAssignment() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    return;
                }

                const response = await axios.get(
                    `members/${memberId}/coach-assignment`
                );

                if (response.data.success && response.data.assignment) {
                    // Populate form with existing data
                    this.trainerData = {
                        trainerId: response.data.assignment.trainerId,
                        assigned_date: this.formatDateForInput(
                            response.data.assignment.assigned_date
                        ),
                        sessionFrequency:
                            response.data.assignment.sessionFrequency,
                        sessionDuration:
                            response.data.assignment.sessionDuration,
                        goals: response.data.assignment.goals,
                        specialRequirements:
                            response.data.assignment.specialRequirements || "",
                        start_date: this.formatDateForInput(
                            response.data.assignment.start_date
                        ),
                        endDate: response.data.assignment.endDate
                            ? this.formatDateForInput(
                                  response.data.assignment.endDate
                              )
                            : "",
                    };
                    this.hasExistingTrainerAssignment = true;
                } else {
                    // Reset form for new assignment
                    this.trainerData = {
                        trainerId: "",
                        assigned_date: "",
                        sessionFrequency: "",
                        sessionDuration: "",
                        goals: "",
                        specialRequirements: "",
                        startDate: "",
                        endDate: "",
                    };
                    this.hasExistingTrainerAssignment = false;
                }
            } catch (error) {
                // Reset form on error
                this.trainerData = {
                    trainerId: "",
                    assigned_date: "",
                    sessionFrequency: "",
                    sessionDuration: "",
                    goals: "",
                    specialRequirements: "",
                    startDate: "",
                    endDate: "",
                };
                this.hasExistingTrainerAssignment = false;
            }
        },

        /**
         * Assign or update trainer for the member
         * Sends trainer assignment data to the server
         */
        async assignTrainer() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                const response = await axios.post(
                    `members/${memberId}/assign-trainer`,
                    this.trainerData
                );

                if (response.data.success) {
                    this.showSuccess(
                        response.data.message ||
                            "Trainer assigned successfully!"
                    );
                    // Update the flag after successful save/update
                    this.hasExistingTrainerAssignment = true;
                    // Refresh the form data to ensure consistency
                    await this.fetchTrainerAssignment();
                } else {
                    this.showError("Failed to assign trainer");
                }
            } catch (error) {
                this.showError("Error assigning trainer. Please try again.");
            }
        },

        // Coach Assignment Methods
        startEditingCoachAssignment() {
            this.isEditingCoachAssignment = true;
            this.fetchCoachAssignment();
        },

        cancelCoachAssignment() {
            this.isEditingCoachAssignment = false;
            // Reset form to current values
            this.fetchCoachAssignment();
        },

        async assignCoach() {
            try {
                // Validate required fields
                if (!this.trainerData.coachId) {
                    this.showError("Please select a coach");
                    return;
                }

                if (!this.trainerData.assigned_date) {
                    this.showError("Please select an assigned date");
                    return;
                }

                if (!this.trainerData.startDate) {
                    this.showError("Please select a start date");
                    return;
                }

                this.isSubmitting = true;
                const memberId = this.$route.params.id;

                const response = await axios.post(
                    `members/${memberId}/assign-coach`,
                    this.trainerData
                );

                if (response.data.success) {
                    this.showSuccess(
                        response.data.message || "Coach assigned successfully!"
                    );
                    this.hasExistingCoachAssignment = true;
                    this.isEditingCoachAssignment = false;
                    // Update current assignment with the new data
                    this.currentCoachAssignment = {
                        coach_id: this.trainerData.coachId,
                        coach_name: this.getCoachName(this.trainerData.coachId),
                        coach_type: this.getSelectedCoachInfo
                            ? this.getSelectedCoachInfo.coach_type
                            : "Unknown Type",
                        assigned_date: this.trainerData.assigned_date,
                        start_date: this.trainerData.startDate,
                        end_date: this.trainerData.endDate,
                        session_frequency: this.trainerData.sessionFrequency,
                        session_duration: this.trainerData.sessionDuration,
                        goals: this.trainerData.goals,
                        special_requirements:
                            this.trainerData.specialRequirements,
                        status: "active",
                    };
                } else {
                    this.showError("Failed to assign coach");
                }
            } catch (error) {
                this.showError("Error assigning coach. Please try again.");
            } finally {
                this.isSubmitting = false;
            }
        },

        async removeCoachAssignment() {
            const result = await this.$swal({
                title: 'Remove Coach Assignment',
                text: 'Are you sure you want to remove this coach assignment?',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#dc3545',
                cancelButtonColor: '#6c757d',
                confirmButtonText: 'Yes, remove it',
                cancelButtonText: 'Cancel'
            });

            if (!result.isConfirmed) {
                return;
            }

            try {
                const memberId = this.$route.params.id;
                const response = await axios.delete(
                    `members/${memberId}/remove-coach-assignment`
                );

                if (response.data.success) {
                    this.showSuccess("Coach assignment removed successfully!");
                    this.hasExistingCoachAssignment = false;
                    this.currentCoachAssignment = null;
                    this.trainerData = {
                        coachId: "",
                        assigned_date: "",
                        sessionFrequency: "",
                        sessionDuration: "",
                        goals: "",
                        specialRequirements: "",
                        startDate: "",
                        endDate: "",
                    };
                } else {
                    this.showError("Failed to remove coach assignment");
                }
            } catch (error) {
                this.showError(
                    "Error removing coach assignment. Please try again."
                );
            }
        },

        getCoachName(coachId) {
            const coach = this.availableCoaches.find((c) => c.id == coachId);
            return coach
                ? `${coach.first_name} ${coach.last_name}`
                : "Unknown Coach";
        },

        isCoachSelectionValid() {
            return (
                this.trainerData.coachId &&
                this.trainerData.coachId.trim() !== ""
            );
        },

        getSelectedCoachInfo() {
            if (!this.isCoachSelectionValid) return null;
            const coach = this.availableCoaches.find(
                (c) => c.id == this.trainerData.coachId
            );
            return coach;
        },

        async fetchCoachAssignment() {
            try {
                const memberId = this.$route.params.id || this.member.id;
                if (!memberId) {
                    this.assignedCoaches = [];
                    return;
                }

                const response = await axios.get(
                    `members/${memberId}/coach-assignment`
                );

                if (response.data.success && response.data.assignment) {
                    const assignment = response.data.assignment;
                    this.currentCoachAssignment = assignment; // Store the full assignment data
                    this.trainerData = {
                        coachId: assignment.coach_id,
                        assigned_date: assignment.assigned_date,
                        sessionFrequency: assignment.session_frequency,
                        sessionDuration: assignment.session_duration,
                        goals: assignment.goals,
                        specialRequirements:
                            assignment.special_requirements || "",
                        startDate: assignment.start_date,
                        endDate: assignment.end_date || "",
                    };
                    this.hasExistingCoachAssignment = true;

                    // Populate assignedCoaches array for the UI
                    if (assignment.coach_id && assignment.coach_name) {
                        this.assignedCoaches = [
                            {
                                id: assignment.coach_id,
                                name: assignment.coach_name,
                                specialization: assignment.coach_type || "",
                                assignment_id: assignment.id || null,
                            },
                        ];
                    } else if (assignment.coach) {
                        // If coach object is included in response
                        const coach = assignment.coach;
                        this.assignedCoaches = [
                            {
                                id: coach.id || assignment.coach_id,
                                name:
                                    coach.first_name && coach.last_name
                                        ? `${coach.first_name} ${coach.last_name}`
                                        : coach.name ||
                                          assignment.coach_name ||
                                          "Unknown Coach",
                                specialization:
                                    coach.coach_type ||
                                    coach.specialization ||
                                    "",
                                assignment_id: assignment.id || null,
                            },
                        ];
                    } else {
                        this.assignedCoaches = [];
                    }

                    // Set account manager if available
                    if (assignment.account_manager_id) {
                        this.selectedAccountManager =
                            assignment.account_manager_id;
                    }
                } else {
                    this.hasExistingCoachAssignment = false;
                    this.currentCoachAssignment = null;
                    this.assignedCoaches = [];
                }
            } catch (error) {
                this.hasExistingCoachAssignment = false;
                this.assignedCoaches = [];
            }
        },

        async loadAvailableCoaches() {
            try {
                this.isLoadingCoaches = true;

                // Try multiple API endpoints
                let response = null;
                let allCoaches = [];

                // Try approach 1: coaches endpoint
                try {
                    response = await axios.get("coaches");
                    if (
                        response.data &&
                        (response.data.coaches ||
                            response.data.clients ||
                            Array.isArray(response.data))
                    ) {
                        allCoaches =
                            response.data.coaches ||
                            response.data.clients ||
                            response.data;
                    }
                } catch (e) {}

                // Try approach 2: coach endpoint with pagination
                if (!allCoaches || allCoaches.length === 0) {
                    try {
                        response = await axios.get("coach?page=1&limit=all");
                        if (
                            response.data &&
                            (response.data.clients ||
                                Array.isArray(response.data))
                        ) {
                            allCoaches = response.data.clients || response.data;
                        }
                    } catch (e) {}
                }

                // Transform coaches to consistent format
                if (allCoaches && allCoaches.length > 0) {
                    this.availableCoaches = allCoaches.map((coach) => {
                        const firstName =
                            coach.first_name || coach.firstname || "";
                        const lastName =
                            coach.last_name || coach.lastname || "";
                        const name =
                            coach.name ||
                            (firstName && lastName
                                ? `${firstName} ${lastName}`
                                : firstName || lastName || "Unknown Coach");

                        return {
                            id: coach.id,
                            name: name,
                            first_name: firstName,
                            last_name: lastName,
                            specialization:
                                coach.specialization || coach.coach_type || "",
                            email: coach.email || "",
                            phone: coach.mobile_phone || coach.phone || "",
                        };
                    });
                } else {
                    this.availableCoaches = [];
                }

                this.loadAccountManagers();
            } catch (error) {
                this.showError("Error loading coaches. Please try again.");
                this.availableCoaches = [];
            } finally {
                this.isLoadingCoaches = false;
            }
        },

        async loadAccountManagers() {
            try {
                // Account managers are typically coaches or staff members
                // For now, use the same coaches list
                this.availableAccountManagers = this.availableCoaches.map(
                    (coach) => ({
                        id: coach.id,
                        name: coach.name,
                    })
                );

                if (
                    this.coachingProfile &&
                    this.coachingProfile.account_manager_id
                ) {
                    this.selectedAccountManager =
                        this.coachingProfile.account_manager_id;
                }
            } catch (error) {}
        },

        async assignCoach(coach) {
            if (!coach || !coach.id) {
                this.showError("Invalid coach selected");
                return;
            }

            // Check if coach is already assigned
            if (this.assignedCoaches.find((ac) => ac.id === coach.id)) {
                this.showError("This coach is already assigned");
                this.showCoachModal = false;
                return;
            }

            this.isSavingCoach = true;
            try {
                const memberId = this.$route.params.id || this.member.id;
                if (!memberId) {
                    this.showError("Member ID not available");
                    return;
                }

                // Prepare assignment data - match backend API format
                const assignmentData = {
                    coach_id: coach.id,
                    assigned_date: new Date().toISOString().split("T")[0],
                    start_date: new Date().toISOString().split("T")[0],
                    session_frequency: "Weekly",
                    session_duration: "60 minutes",
                    goals: "General fitness goals",
                    special_requirements: "",
                };

                const response = await axios.post(
                    `members/${memberId}/assign-coach`,
                    assignmentData
                );

                if (response.data && response.data.success) {
                    this.showSuccess("Coach assigned successfully!");
                    // Add to assigned coaches list
                    this.assignedCoaches.push({
                        id: coach.id,
                        name: coach.name,
                        specialization: coach.specialization || "",
                        assignment_id:
                            response.data.assignment?.id ||
                            response.data.data?.id,
                    });
                    this.showCoachModal = false;
                    this.coachSearchQuery = "";
                    await this.fetchCoachAssignment();
                    await this.loadCoachingProfile();
                } else {
                    this.showError(
                        response.data?.message || "Failed to assign coach"
                    );
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    error.response?.data?.error ||
                    "Failed to assign coach. Please try again.";
                this.showError(errorMessage);
            } finally {
                this.isSavingCoach = false;
            }
        },

        async removeCoach(coachId) {
            const result = await this.$swal({
                title: 'Remove Coach',
                text: 'Are you sure you want to remove this coach assignment?',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#dc3545',
                cancelButtonColor: '#6c757d',
                confirmButtonText: 'Yes, remove it',
                cancelButtonText: 'Cancel'
            });

            if (!result.isConfirmed) {
                return;
            }

            this.isRemovingCoach = coachId;
            try {
                const memberId = this.$route.params.id || this.member.id;
                if (!memberId) {
                    this.showError("Member ID not available");
                    return;
                }

                // Find the coach assignment to get the assignment ID
                const coach = this.assignedCoaches.find(
                    (ac) => ac.id === coachId
                );
                const assignmentId = coach?.assignment_id;

                // Use the correct API endpoint
                const response = await axios.delete(
                    `members/${memberId}/remove-coach-assignment`,
                    {
                        data: {
                            coach_id: coachId,
                            assignment_id: assignmentId,
                        },
                    }
                );

                if (response.data && response.data.success) {
                    this.showSuccess("Coach removed successfully!");
                    // Remove from assigned coaches list
                    this.assignedCoaches = this.assignedCoaches.filter(
                        (ac) => ac.id !== coachId
                    );
                    await this.fetchCoachAssignment();
                    await this.loadCoachingProfile();
                } else {
                    this.showError(
                        response.data?.message || "Failed to remove coach"
                    );
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    error.response?.data?.error ||
                    "Failed to remove coach. Please try again.";
                this.showError(errorMessage);
            } finally {
                this.isRemovingCoach = null;
            }
        },

        async updateAccountManager() {
            if (!this.selectedAccountManager) {
                return;
            }

            try {
                if (!this.coachingProfile) {
                    this.coachingProfile = {};
                }
                this.coachingProfile.account_manager_id =
                    this.selectedAccountManager;
                await this.saveCoachingField(
                    "account_manager_id",
                    this.selectedAccountManager
                );
                this.showSuccess("Account manager updated successfully!");
            } catch (error) {
                this.showError("Failed to update account manager");
            }
        },

        // Questionnaires Methods
        async fetchQuestionnaires() {
            if (!this.member || !this.member.id) {
                return;
            }

            this.isLoadingQuestionnaires = true;
            try {
                await this.loadCoachingProfile();
                const assigned =
                    this.coachingProfile.assigned_questionnaires || [];

                // Map assigned questionnaire IDs to full questionnaire objects
                this.questionnaires = assigned.map((qId) => {
                    const questionnaire = this.availableQuestionnaires.find(
                        (aq) => aq.id === qId
                    );
                    return (
                        questionnaire || {
                            id: qId,
                            name: `Questionnaire ${qId}`,
                            type: "unknown",
                        }
                    );
                });
            } catch (error) {
                this.questionnaires = [];
            } finally {
                this.isLoadingQuestionnaires = false;
            }
        },

        async assignQuestionnaire(questionnaire) {
            if (!questionnaire || !questionnaire.id) {
                this.showError("Invalid questionnaire selected");
                return;
            }

            // Check if questionnaire is already assigned
            if (this.questionnaires.find((q) => q.id === questionnaire.id)) {
                this.showError("This questionnaire is already assigned");
                this.showQuestionnaireModal = false;
                return;
            }

            this.isSavingQuestionnaire = true;
            try {
                const memberId = this.$route.params.id || this.member.id;
                if (!memberId) {
                    this.showError("Member ID not available");
                    return;
                }

                // Get current assigned questionnaires
                const currentQuestionnaires =
                    this.coachingProfile.assigned_questionnaires || [];

                // Add new questionnaire ID
                const updatedQuestionnaires = [
                    ...currentQuestionnaires,
                    questionnaire.id,
                ];

                // Update coaching profile
                const response = await axios.put(
                    `members/${memberId}/coaching`,
                    {
                        assigned_questionnaires: updatedQuestionnaires,
                    }
                );

                if (response.data && response.data.success) {
                    this.showSuccess("Questionnaire assigned successfully!");
                    // Update local state
                    this.coachingProfile.assigned_questionnaires =
                        updatedQuestionnaires;
                    this.questionnaires.push(questionnaire);
                    this.showQuestionnaireModal = false;
                } else {
                    this.showError("Failed to assign questionnaire");
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    "Failed to assign questionnaire. Please try again.";
                this.showError(errorMessage);
            } finally {
                this.isSavingQuestionnaire = false;
            }
        },

        async removeQuestionnaire(questionnaireId) {
            const result = await this.$swal({
                title: 'Remove Questionnaire',
                text: 'Are you sure you want to remove this questionnaire?',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#dc3545',
                cancelButtonColor: '#6c757d',
                confirmButtonText: 'Yes, remove it',
                cancelButtonText: 'Cancel'
            });

            if (!result.isConfirmed) {
                return;
            }

            try {
                const memberId = this.$route.params.id || this.member.id;
                if (!memberId) {
                    this.showError("Member ID not available");
                    return;
                }

                // Get current assigned questionnaires
                const currentQuestionnaires =
                    this.coachingProfile.assigned_questionnaires || [];

                // Remove questionnaire ID
                const updatedQuestionnaires = currentQuestionnaires.filter(
                    (qId) => qId !== questionnaireId
                );

                // Update coaching profile
                const response = await axios.put(
                    `members/${memberId}/coaching`,
                    {
                        assigned_questionnaires: updatedQuestionnaires,
                    }
                );

                if (response.data && response.data.success) {
                    this.showSuccess("Questionnaire removed successfully!");
                    // Update local state
                    this.coachingProfile.assigned_questionnaires =
                        updatedQuestionnaires;
                    this.questionnaires = this.questionnaires.filter(
                        (q) => q.id !== questionnaireId
                    );
                } else {
                    this.showError("Failed to remove questionnaire");
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    "Failed to remove questionnaire. Please try again.";
                this.showError(errorMessage);
            }
        },

        // Check-ins Methods
        async fetchCheckIns() {
            if (!this.member || !this.member.id) {
                return;
            }

            this.isLoadingCheckIns = true;
            try {
                const memberId = this.$route.params.id || this.member.id;
                const response = await axios.get(
                    `check-ins?member_id=${memberId}&limit=20`
                );

                if (response.data && response.data.success) {
                    this.checkIns = response.data.data || [];
                } else {
                    // Try alternative endpoint format
                    const altResponse = await axios.get(`check-ins`, {
                        params: { member_id: memberId, limit: 20 },
                    });
                    this.checkIns =
                        altResponse.data?.data || altResponse.data || [];
                }
            } catch (error) {
                this.checkIns = [];
            } finally {
                this.isLoadingCheckIns = false;
            }
        },

        formatCheckInTime(dateTime) {
            if (!dateTime) return "-";
            const date = new Date(dateTime);
            return date.toLocaleString("en-US", {
                month: "2-digit",
                day: "2-digit",
                year: "numeric",
                hour: "2-digit",
                minute: "2-digit",
                second: "2-digit",
                hour12: true,
            });
        },

        editCheckIn(checkIn) {
            this.editingCheckIn = checkIn.id;
            this.checkInEditData = {
                check_in_time: checkIn.check_in_time
                    ? new Date(checkIn.check_in_time).toISOString().slice(0, 16)
                    : "",
                check_out_time: checkIn.check_out_time
                    ? new Date(checkIn.check_out_time)
                          .toISOString()
                          .slice(0, 16)
                    : "",
                message: checkIn.message || "",
                membership_info: checkIn.membership_info || "",
            };
            this.showCheckInEditModal = true;
        },

        async saveCheckIn() {
            if (!this.editingCheckIn) {
                return;
            }

            try {
                const response = await axios.put(
                    `check-ins/${this.editingCheckIn}`,
                    {
                        check_in_time: this.checkInEditData.check_in_time,
                        check_out_time:
                            this.checkInEditData.check_out_time || null,
                        message: this.checkInEditData.message,
                        membership_info: this.checkInEditData.membership_info,
                    }
                );

                if (response.data && response.data.success) {
                    this.showSuccess("Check-in updated successfully!");
                    this.showCheckInEditModal = false;
                    this.editingCheckIn = null;
                    await this.fetchCheckIns();
                } else {
                    this.showError("Failed to update check-in");
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    "Failed to update check-in. Please try again.";
                this.showError(errorMessage);
            }
        },

        async deleteCheckIn(checkInId) {
            const result = await this.$swal({
                title: 'Delete Check-in',
                text: 'Are you sure you want to delete this check-in record?',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonColor: '#dc3545',
                cancelButtonColor: '#6c757d',
                confirmButtonText: 'Yes, delete it',
                cancelButtonText: 'Cancel'
            });

            if (!result.isConfirmed) {
                return;
            }

            try {
                const response = await axios.delete(`check-ins/${checkInId}`);

                if (response.data && response.data.success) {
                    this.showSuccess("Check-in deleted successfully!");
                    await this.fetchCheckIns();
                } else {
                    this.showError("Failed to delete check-in");
                }
            } catch (error) {
                const errorMessage =
                    error.response?.data?.message ||
                    "Failed to delete check-in. Please try again.";
                this.showError(errorMessage);
            }
        },

        cancelCheckInEdit() {
            this.showCheckInEditModal = false;
            this.editingCheckIn = null;
            this.checkInEditData = {
                check_in_time: "",
                check_out_time: "",
                message: "",
                membership_info: "",
            };
        },

        // Toast notification helper methods
        makeToast(variant, msg, title) {
            this.$root.$bvToast.toast(msg, {
                title: title,
                variant: variant,
                solid: true,
                toaster: 'b-toaster-top-right',
                autoHideDelay: 5000
            });
        },

        showSuccess(message) {
            this.makeToast("success", message, "Success");
        },

        showError(message) {
            this.makeToast("danger", message, "Error");
        },

        cancelTrainerAssignment() {
            this.activeAction = null;
            // Reset the form to original state
            this.fetchTrainerAssignment();
        },

        async fetchMemberTasks() {
            try {
                this.isLoadingTasks = true;
                const memberId = this.$route.params.id;
                if (!memberId) {
                    return;
                }

                const response = await axios.get(`members/${memberId}/tasks`);

                if (response.data.success) {
                    const allTasks = response.data.tasks || [];
                    // Filter out tasks with invalid IDs (0 or null/undefined)
                    this.memberTasks = allTasks.filter((task) => {
                        const taskId = this.extractTaskId(task);
                        if (taskId === null || taskId === undefined) {
                            return false;
                        }
                        return true;
                    });

                    // Warn if any tasks were filtered out
                    const invalidTasks =
                        allTasks.length - this.memberTasks.length;
                    if (invalidTasks > 0) {
                        this.showError(
                            `Warning: ${invalidTasks} task(s) have invalid IDs and were not displayed. Please refresh the page or contact support.`
                        );
                    }
                } else {
                    this.showError("Failed to fetch tasks");
                }
            } catch (error) {
                // Show user-friendly error message
                if (error.response) {
                    if (error.response.status === 401) {
                        this.showError(
                            "You are not authorized to view tasks. Please log in again."
                        );
                    } else if (error.response.status === 403) {
                        this.showError(
                            "You don't have permission to view tasks."
                        );
                    } else if (error.response.status === 404) {
                        this.showError(
                            "Member not found. Unable to fetch tasks."
                        );
                    } else if (
                        error.response.data &&
                        error.response.data.message
                    ) {
                        this.showError(
                            `Error fetching tasks: ${error.response.data.message}`
                        );
                    } else {
                        this.showError(
                            `Error fetching tasks: ${error.response.status} ${
                                error.response.statusText || "Unknown error"
                            }`
                        );
                    }
                } else if (error.request) {
                    this.showError(
                        "Network error. Please check your internet connection and try again."
                    );
                } else {
                    this.showError(
                        "An unexpected error occurred while fetching tasks. Please try again."
                    );
                }

                // Set empty array instead of mock data
                this.memberTasks = [];
            } finally {
                this.isLoadingTasks = false;
            }
        },

        async fetchWorkoutAssignments() {
            try {
                this.isLoadingWorkoutAssignments = true;
                const memberId = this.$route.params.id;
                if (!memberId) {
                    return;
                }

                const response = await axios.get(
                    `/workout/assignments/${memberId}`
                );

                if (response.data && response.data.success) {
                    const assignments = response.data.assignments || [];

                    // Fetch workout details for assignments where workout is null
                    const assignmentsWithWorkouts = await Promise.all(
                        assignments.map(async (assignment) => {
                            // If workout is null but workout_id exists, try to fetch workout details
                            if (!assignment.workout && assignment.workout_id) {
                                try {
                                    const workoutResponse = await axios.get(
                                        `/workout/${assignment.workout_id}?include=workoutDays.workoutActivityPlans`
                                    );
                                    // Handle different response formats
                                    if (workoutResponse.data) {
                                        if (workoutResponse.data.exercise) {
                                            assignment.workout =
                                                workoutResponse.data.exercise;
                                        } else if (
                                            workoutResponse.data.workout
                                        ) {
                                            assignment.workout =
                                                workoutResponse.data.workout;
                                        } else if (workoutResponse.data.data) {
                                            assignment.workout =
                                                workoutResponse.data.data;
                                        } else if (
                                            workoutResponse.data.success &&
                                            workoutResponse.data.exercise
                                        ) {
                                            assignment.workout =
                                                workoutResponse.data.exercise;
                                        } else if (
                                            Array.isArray(
                                                workoutResponse.data
                                            ) &&
                                            workoutResponse.data.length > 0
                                        ) {
                                            assignment.workout =
                                                workoutResponse.data.find(
                                                    (w) =>
                                                        w.id ===
                                                        assignment.workout_id
                                                ) || workoutResponse.data[0];
                                        }
                                    }
                                } catch (error) {
                                    // Keep assignment without workout details
                                }
                            }

                            // If workout exists but doesn't have workout_days, fetch them
                            if (
                                assignment.workout &&
                                assignment.workout.id &&
                                (!assignment.workout.workout_days ||
                                    assignment.workout.workout_days.length ===
                                        0)
                            ) {
                                try {
                                    const workoutResponse = await axios.get(
                                        `/workout/${assignment.workout.id}?include=workoutDays.workoutActivityPlans`
                                    );
                                    if (
                                        workoutResponse.data &&
                                        workoutResponse.data.exercise
                                    ) {
                                        assignment.workout.workout_days =
                                            workoutResponse.data.exercise
                                                .workout_days || [];
                                    }
                                } catch (error) {
                                    // Could not fetch workout days - silently fail
                                }
                            }

                            return assignment;
                        })
                    );

                    this.workoutAssignments = assignmentsWithWorkouts;
                } else {
                    this.workoutAssignments = [];
                    if (response.data && !response.data.success) {
                        this.showError(
                            response.data.message ||
                                "Failed to fetch workout assignments"
                        );
                    }
                }
            } catch (error) {
                this.workoutAssignments = [];
                this.showError(
                    "Error loading workout assignments: " +
                        (error.response?.data?.message || error.message)
                );
            } finally {
                this.isLoadingWorkoutAssignments = false;
            }
        },

        openWorkoutInEditor(workout) {
