        getDateClass(date) {
            if (!date) return "date-na";
            const invoiceDate = new Date(date);
            const today = new Date();
            const diffTime = Math.abs(today - invoiceDate);
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            if (diffDays <= 7) return "date-recent";
            if (diffDays <= 30) return "date-month";
            return "date-old";
        },

        getAmountClass(amount) {
            const numAmount = parseFloat(amount);
            if (numAmount > 100) return "amount-high";
            if (numAmount > 50) return "amount-medium";
            return "amount-low";
        },

        getStatusClass(status) {
            const statusLower = status.toLowerCase();
            if (statusLower === "paid") return "status-paid";
            if (statusLower === "pending") return "status-pending";
            if (statusLower === "cancelled") return "status-cancelled";
            if (statusLower === "overdue") return "status-overdue";
            return "status-unknown";
        },
        resetLoadingState() {
            this.isLoadingInvoices = false;
        },

