        getFileIcon(fileType) {
            const type = fileType.toLowerCase();
            if (type.includes("pdf")) return "fas fa-file-pdf text-danger";
            if (
                type.includes("image") ||
                type.includes("jpg") ||
                type.includes("jpeg") ||
                type.includes("png")
            )
                return "fas fa-file-image text-primary";
            if (type.includes("word") || type.includes("doc"))
                return "fas fa-file-word text-primary";
            if (type.includes("excel") || type.includes("xls"))
                return "fas fa-file-excel text-success";
            if (type.includes("powerpoint") || type.includes("ppt"))
                return "fas fa-file-powerpoint text-warning";
            if (type.includes("text") || type.includes("txt"))
                return "fas fa-file-alt text-secondary";
            return "fas fa-file text-muted";
        },

        formatFileSize(bytes) {
            if (bytes === 0) return "0 Bytes";
            const k = 1024;
            const sizes = ["Bytes", "KB", "MB", "GB"];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return (
                parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i]
            );
        },

        uploadFile() {
            if (!this.member.id) {
                this.showError(
                    "Please wait for member data to load before uploading files."
                );
                return;
            }

            // Create a file input element
            const input = document.createElement("input");
            input.type = "file";
            input.multiple = true;
            input.accept = "*/*";

            input.onchange = async (event) => {
                const files = event.target.files;
                if (files.length > 0) {
                    await this.handleFileUpload(files);
                }
            };

            // Trigger file selection
            input.click();
        },

        async handleFileUpload(files) {
            if (!this.member.id) {
                this.showError("No member ID available");
                return;
            }

            const uploadPromises = [];

            for (let i = 0; i < files.length; i++) {
                const file = files[i];

                if (file.size > 10 * 1024 * 1024) {
                    this.showError(
                        `File "${file.name}" is too large. Maximum size is 10MB.`
                    );
                    continue;
                }

                const formData = new FormData();
                formData.append("file", file);
                formData.append("description", "");
                formData.append("category", "general");

                uploadPromises.push(
                    axios
                        .post(
                            `/members/${this.member.id}/documents`,
                            formData,
                            {
                                headers: {
                                    "Content-Type": "multipart/form-data",
                                },
                            }
                        )
                        .then((response) => {
                            return response;
                        })
                        .catch((error) => {
                            return { error: error, fileName: file.name };
                        })
                );
            }

            if (uploadPromises.length === 0) {
                return;
            }

            // Show loading state
            this.isLoadingFiles = true;

            try {
                const results = await Promise.all(uploadPromises);

                let successCount = 0;
                let errorCount = 0;

                results.forEach((result) => {
                    if (result.error) {
                        errorCount++;
                    } else if (result.data && result.data.success) {
                        successCount++;
                    }
                });

                // Reload files to show uploaded files
                await this.loadMemberFiles();

                if (successCount > 0) {
                    this.showSuccess(
                        `${successCount} file(s) uploaded successfully!`
                    );
                }

                if (errorCount > 0) {
                    this.showError(`${errorCount} file(s) failed to upload.`);
                }
            } catch (error) {
                this.showError("Failed to upload files. Please try again.");
            } finally {
                this.isLoadingFiles = false;
            }
        },

        async downloadFile(file) {
            try {
                // Show preparing message
                this.$swal({
                    title: "Preparing Download...",
                    text: `Getting ${file.original_name} ready for download`,
                    icon: "info",
                    allowOutsideClick: false,
                    showConfirmButton: false,
                    timer: 1500,
                });

                const response = await axios.get(
                    `/members/${this.member.id}/documents/${file.id}/download`,
                    {
                        responseType: "blob",
                    }
                );

                // Create blob link to download
                const url = window.URL.createObjectURL(
                    new Blob([response.data])
                );
                const link = document.createElement("a");
                link.href = url;
                link.setAttribute("download", file.original_name);
                document.body.appendChild(link);
                link.click();
                link.remove();
                window.URL.revokeObjectURL(url);

                // Show success message after download link is triggered
                setTimeout(() => {
                    this.showSuccess(
                        `Download initiated for "${file.original_name}". Please check your browser's download area.`
                    );
                }, 500);
            } catch (error) {
                this.showError("Failed to download file. Please try again.");
            }
        },

        async deleteFile(file) {
            try {
                const result = await this.$swal({
                    title: "Delete File",
                    text: `Are you sure you want to delete "${file.original_name}"?`,
                    icon: "warning",
                    showCancelButton: true,
                    confirmButtonColor: "#d33",
                    cancelButtonColor: "#3085d6",
                    confirmButtonText: "Yes, delete it!",
                    cancelButtonText: "Cancel",
                });

                if (result.isConfirmed) {
                    await axios.delete(
                        `/members/${this.member.id}/documents/${file.id}`
                    );

                    // Reload files to update the list
                    await this.loadMemberFiles();

                    this.showSuccess(
                        `File "${file.original_name}" deleted successfully!`
                    );
                }
            } catch (error) {
                this.showError("Failed to delete file. Please try again.");
            }
        },

