         */
        async loadMemberNutritionPlans() {
            this.isLoadingMemberNutritionPlans = true;
            try {
                // Add check for member existence and use route params as fallback
                const memberId =
                    (this.member && this.member.id) || this.$route.params.id;
                if (!memberId) {
