                            duration:
                                plan.duration ||
                                this.calculateDuration(
                                    plan.start_date,
                                    plan.end_date
                                ),
                            description: plan.description || "",
                            status: this.getPlanStatus(
                                plan.start_date,
                                plan.end_date
                            ),
