        /**
         * Calculate duration from start and end dates
         */
        calculateDuration(startDate, endDate) {
            if (!startDate || !endDate) return "ongoing";

            const start = new Date(startDate);
            const end = new Date(endDate);
            const diffTime = Math.abs(end - start);
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            if (diffDays <= 7) return "1_week";
            if (diffDays <= 14) return "2_weeks";
            if (diffDays <= 30) return "1_month";
            if (diffDays <= 60) return "2_months";
            if (diffDays <= 90) return "3_months";
            if (diffDays <= 180) return "6_months";
            if (diffDays <= 365) return "1_year";
            return "ongoing";
        },

        /**
         * Get plan status based on dates
         */
        getPlanStatus(startDate, endDate) {
            if (!startDate) return "pending";

            const start = new Date(startDate);
            const end = endDate ? new Date(endDate) : null;
            const now = new Date();

            if (start > now) return "pending";
            if (end && end < now) return "completed";
            return "active";
        },

        /**
         * Get CSS class for nutrition plan status
         */
        getNutritionStatusClass(status) {
            const statusLower = (status || "active").toLowerCase();
            if (statusLower === "active") return "status-active";
            if (statusLower === "completed") return "status-completed";
            if (statusLower === "cancelled") return "status-cancelled";
            if (statusLower === "expired") return "status-expired";
            return "status-unknown";
        },

