                }
            });
        },

        /**
         * Delete nutrition plan
         */
        async deleteNutritionPlan(planId, planIndex) {
            try {
                // Find the plan using index (most reliable) or fallback to ID
                let planToDelete;
                if (
                    planIndex !== null &&
                    planIndex >= 0 &&
                    planIndex < this.memberNutritionPlans.length
                ) {
                    planToDelete = this.memberNutritionPlans[planIndex];
                } else {
                    planToDelete = this.memberNutritionPlans.find(
                        (plan) => plan.id === planId
                    );
                }

                if (!planToDelete) {
                    this.$swal({
                        title: "Error!",
                        text: "Nutrition plan not found.",
                        icon: "error",
                        confirmButtonText: "OK",
                    });
                    return;
                }

                const result = await this.$swal({
                    title: "Delete Nutrition Plan",
                    text: `Are you sure you want to delete the nutrition plan "${
                        planToDelete.nutrition_plan || planToDelete.plan_name
                    }"?`,
                    icon: "warning",
                    showCancelButton: true,
                    confirmButtonText: "Yes, delete it!",
                    cancelButtonText: "Cancel",
                });

                if (result.isConfirmed) {
                    // Handle the case where multiple plans have the same ID
                    if (planToDelete.id === 0 || planToDelete.id === null) {
                        // If the plan has ID 0, we need to handle this differently
                        // Since both plans have ID 0, we'll delete by removing from local array first
                        // and then make the API call

                        // Remove the plan from local array immediately
                        if (
                            planIndex !== null &&
                            planIndex >= 0 &&
                            planIndex < this.memberNutritionPlans.length
                        ) {
                            this.memberNutritionPlans.splice(planIndex, 1);
                        }

                        // Try to delete via API, but don't worry if it fails since we already removed it locally
                        try {
                            const response = await axios.delete(
                                `/nutrition_plans/${planToDelete.id}`
                            );

                            if (response.data.success) {
                                this.$swal({
                                    title: "Deleted!",
                                    text: "Nutrition plan has been deleted successfully.",
                                    icon: "success",
                                    confirmButtonText: "OK",
                                });
                            } else {
                                // Check if the error is because the record was already deleted
                                const responseMessage =
                                    response.data.message || "";
                                const isResponseAlreadyDeleted =
                                    responseMessage.includes(
                                        "No query results"
                                    ) ||
                                    responseMessage.includes("not found") ||
                                    responseMessage.includes(
                                        "does not exist"
                                    ) ||
                                    responseMessage.includes("already deleted");

                                if (
                                    response.data.message &&
                                    isResponseAlreadyDeleted
                                ) {
                                    // This means the record was already deleted, which is actually success
                                    this.$swal({
                                        title: "Deleted!",
                                        text: "Nutrition plan has been deleted successfully.",
                                        icon: "success",
                                        confirmButtonText: "OK",
                                    });
                                } else {
                                    // Other API errors - but we've already removed it locally
                                    this.$swal({
                                        title: "Deleted!",
                                        text: "Nutrition plan has been removed.",
                                        icon: "success",
                                        confirmButtonText: "OK",
                                    });
                                }
                            }
                        } catch (apiError) {
                            // Check if the error is because the record was already deleted
                            const apiErrorMessage =
                                apiError.response?.data?.message || "";
                            const isApiAlreadyDeleted =
                                apiErrorMessage.includes("No query results") ||
                                apiErrorMessage.includes("not found") ||
                                apiErrorMessage.includes("does not exist") ||
                                apiErrorMessage.includes("already deleted");

                            if (
                                apiError.response &&
                                apiError.response.data &&
                                isApiAlreadyDeleted
                            ) {
                                // This means the record was already deleted, which is actually success
                                this.$swal({
                                    title: "Deleted!",
                                    text: "Nutrition plan has been deleted successfully.",
                                    icon: "success",
                                    confirmButtonText: "OK",
                                });
                            } else {
                                // Other API errors - but we've already removed it locally
                                this.$swal({
                                    title: "Deleted!",
                                    text: "Nutrition plan has been removed.",
                                    icon: "success",
                                    confirmButtonText: "OK",
                                });
                            }
                        }

                        // Reload to ensure consistency
                        await this.loadNutritionPlans();
                    } else {
                        // Normal deletion for plans with unique IDs
                        try {
                            const response = await axios.delete(
                                `/nutrition_plans/${planToDelete.id}`
