                if (error.response && error.response.data && isAlreadyDeleted) {
                    // This means the record was already deleted, which is actually success
                    this.$swal({
                        title: "Deleted!",
                        text: "Nutrition plan has been deleted successfully.",
                        icon: "success",
                        confirmButtonText: "OK",
                    });

                    // Remove from local array since it's already deleted
                    if (
                        planIndex !== null &&
                        planIndex >= 0 &&
                        planIndex < this.memberNutritionPlans.length
                    ) {
                        this.memberNutritionPlans.splice(planIndex, 1);
                    }
                    await this.loadNutritionPlans();
                } else {
                    this.$swal({
                        title: "Error!",
                        text: "An error occurred while deleting the nutrition plan.",
                        icon: "error",
                        confirmButtonText: "OK",
                    });
                }
            }
        },

        formatDuration(duration) {
            if (!duration) return "N/A";
            const durationMap = {
                "1_week": "1 Week",
                "2_weeks": "2 Weeks",
                "1_month": "1 Month",
                "2_months": "2 Months",
                "3_months": "3 Months",
                "6_months": "6 Months",
                "1_year": "1 Year",
                ongoing: "Ongoing",
            };
            return durationMap[duration] || duration;
        },

        formatCurrency(amount) {
            return parseFloat(amount).toFixed(2);
        },

        /**
         * Get CSS class for task table row based on status and due date
         * @param {Object} task - Task object
         * @returns {string} CSS class name
         */
        getTaskRowClass(task) {
            if (task.status === "completed") {
                return "table-success-light";
            } else if (task.status === "in-progress") {
                return "table-warning-light";
            } else if (
                new Date(task.due_date) < new Date() &&
                task.status !== "completed"
            ) {
                return "table-danger-light";
            }
            return "";
        },

        /**
         * Get CSS class for task category badge
         * @param {string} category - Task category
         * @returns {string} Bootstrap badge class
         */
        getCategoryClass(category) {
            const classes = {
                coaching: "bg-primary",
                personal: "bg-success",
                organization: "bg-info",
                sales: "bg-warning",
            };
            return classes[category] || "bg-secondary";
        },

        /**
         * Get CSS class for task priority badge
         * @param {string} priority - Task priority
         * @returns {string} Bootstrap badge class
         */
        getPriorityClass(priority) {
            const classes = {
                urgent: "bg-danger",
                high: "bg-warning",
                medium: "bg-info",
                low: "bg-success",
            };
            return classes[priority] || "bg-secondary";
        },

        /**
         * Get CSS class for task status badge
         * @param {string} status - Task status
         * @returns {string} Bootstrap badge class
         */
        getStatusClass(status) {
            const classes = {
                pending: "bg-secondary",
                "in-progress": "bg-warning",
                completed: "bg-success",
                cancelled: "bg-danger",
            };
            return classes[status] || "bg-secondary";
        },

        /**
         * Get CSS class for due date based on proximity to current date
         * @param {string} dueDate - Task due date
         * @returns {string} CSS class for text styling
         */
        getDueDateClass(dueDate) {
            const today = new Date();
            const due = new Date(dueDate);
            const diffTime = due - today;
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            if (diffDays < 0) {
                return "text-danger font-weight-bold";
            } else if (diffDays <= 3) {
                return "text-warning font-weight-bold";
            } else if (diffDays <= 7) {
                return "text-info";
            }
            return "";
        },

        /**
         * Format date string for display
         * @param {string} dateString - Date string to format
         * @returns {string} Formatted date string
         */
        formatDate(dateString) {
            if (!dateString) return "N/A";
            const date = new Date(dateString);
            return date.toLocaleDateString();
        },

        /**
         * Format task date for display in table
         * @param {string} dateString - Date string to format
         * @returns {string} Formatted date string
         */
        formatTaskDate(dateString) {
            if (!dateString) return "N/A";
            const date = new Date(dateString);
            if (isNaN(date.getTime())) return "N/A";
            return date.toLocaleDateString("en-US", {
                year: "numeric",
                month: "short",
                day: "numeric",
            });
        },

        /**
         * Edit an existing task
         * Populates the task form with existing data
         * @param {Object} task - Task object to edit
         */
        editTask(task) {
            // Check if task exists
            if (!task) {
                this.showError("Invalid task data: Task object is missing");
                return;
            }

            // Use helper function to extract task ID (already validated and converted to number)
            const taskId = this.extractTaskId(task);

            // Check if taskId is valid (extractTaskId returns null if invalid)
            if (taskId === null || taskId === undefined) {

                // Check if the task has ID 0 specifically
                if (task.id === 0 || task.task_id === 0 || task.ID === 0) {
                    this.showError(
                        "This task has an invalid ID (0). This indicates a database issue. Please refresh the page or contact support. The task may need to be recreated."
                    );
                } else {
                    this.showError(
                        "Invalid task data: Task ID is missing or invalid. Please refresh the page and try again."
                    );
                }
                return;
            }

            // Populate the newTask form with task data for editing
            // Parse time if it exists (format: "HH:mm" or separate hour/minute)
            let due_hour = null;
            let due_minute = null;
            if (task.due_time) {
                const timeParts = task.due_time.split(":");
                if (timeParts.length === 2) {
                    due_hour = parseInt(timeParts[0]);
                    due_minute = parseInt(timeParts[1]);
                }
            } else if (task.due_hour !== undefined && task.due_hour !== null) {
                due_hour = task.due_hour;
                due_minute = task.due_minute || null;
            }

            this.newTask = {
                task: task.title || "",
                category: task.category || "",
                priority: task.priority || "",
                dueDate: this.formatDateForInput(task.due_date || task.dueDate),
                details: task.description || "",
                // concerns: "", // Commented out - not in database
                assignedToUserId: task.assigned_to || task.assignedTo || null, // User ID for backend
                isComplete:
                    task.status === "completed" ||
                    task.is_complete === true ||
                    task.isComplete === true,
                due_hour: due_hour,
                due_minute: due_minute,
                duration: task.duration || null,
            };

            // taskId is already validated and converted to number in extractTaskId
            this.editingTaskId = taskId;

            // Switch to the task form view and scroll to top
            this.activeAction = "newTask";
            this.$nextTick(() => {
                const modal = document.querySelector(".new-task-modal");
                if (modal) {
                    modal.scrollTop = 0;
                }
            });
        },

        /**
         * Cancel task editing and reset form
         */
        cancelTaskEdit() {
            this.task = {
                title: "",
                category: "",
                priority: "",
                dueDate: "",
                description: "",
                status: "pending",
            };
            this.editingTaskId = null;
            this.activeAction = null;
        },

        /**
         * Cancel nutrition plan editing and reset form
         */
        cancelNutritionEdit() {
