                nutrition_plan: "",
                start_date: "",
                duration: "",
                description: "",
                type: "",
                status: "active",
                price: "0",
                paymentFrequency: "",
                features: "No features",
                notes: "No notes",
            };
            this.editingNutritionId = null;
            this.activeAction = null;
        },

        /**
