        /**
         * Toggle nutrition plan details expansion
         * @param {number} planId - ID of the nutrition plan
         */
        async toggleNutritionPlanDetails(planId) {
            // If clicking the same plan, collapse it
            if (this.expandedNutritionPlanId === planId) {
                this.expandedNutritionPlanId = null;
                return;
            }

            // Expand the clicked plan
            this.expandedNutritionPlanId = planId;

            // If details are not cached, fetch them
            if (!this.nutritionPlanDetails[planId]) {
                await this.fetchNutritionPlanDetails(planId);
            }
        },

        /**
         * Fetch detailed nutrition plan information with foods
         * @param {number} planId - ID of the nutrition plan
         */
        async fetchNutritionPlanDetails(planId) {
            try {
                const response = await axios.get(`/nutrition_plans/${planId}`);

                if (response.data.success) {
                    this.$set(
                        this.nutritionPlanDetails,
                        planId,
                        response.data.data
                    );
                } else {
                    this.showError(
                        response.data.message || "Failed to load plan details"
                    );
                }
            } catch (error) {
                this.showError("Error loading plan details. Please try again.");
            }
        },

        /**
         * Get meal items filtered by nutrition type
         * @param {Array} details - Array of nutrition plan details
         * @param {string} mealType - Type of meal (breakfast, lunch, dinner, snack)
         * @returns {Array} Filtered meal items
         */
        getMealItems(details, mealType) {
            if (!details || !Array.isArray(details)) {
                return [];
            }
            return details.filter((item) => item.nutrition_type === mealType);
        },

        /**
         * Navigate to Nutrition Hub with member context
         */
        navigateToNutritionHub() {
            this.$router.push({
                name: "Nutrition",
                query: { memberId: this.member.id },
            });
        },

        /**
         * Helper function to extract task ID from task object
         * Handles multiple possible ID field names
         * @param {Object} task - Task object
         * @returns {number|null} - Task ID or null if not found
         */
        extractTaskId(task) {
            if (!task) {
                return null;
            }

            // Try multiple possible ID field names
            // Also check that the ID is not 0 (which is invalid)
            let taskId = null;

            if (
                "id" in task &&
                task.id !== null &&
                task.id !== undefined &&
                task.id !== 0
            ) {
                taskId = task.id;
            } else if (
                "task_id" in task &&
                task.task_id !== null &&
                task.task_id !== undefined &&
                task.task_id !== 0
            ) {
                taskId = task.task_id;
            } else if (
                "ID" in task &&
                task.ID !== null &&
                task.ID !== undefined &&
                task.ID !== 0
            ) {
                taskId = task.ID;
            }

            // Additional validation: ensure it's a valid number
            if (taskId !== null) {
                const numId = parseInt(taskId);
                if (isNaN(numId) || numId <= 0) {
                    return null;
                }
                return numId;
            }

            return null;
        },

        /**
         * Delete a task directly without confirmation
         * @param {Object} task - Task object to delete
         */
        async deleteTaskDirectly(task) {
            if (!task) {
                this.showError("Invalid task data: Task object is missing");
                return;
            }

            const taskId = this.extractTaskId(task);

            if (taskId === null || taskId === undefined) {
                this.showError(
                    "Invalid task data: Task ID is missing or invalid. Please refresh the page and try again."
                );
                return;
            }

            await this.deleteTask(taskId);
        },

        /**
         * Confirm and delete a task
         * @param {Object} task - Task object to delete
         * @deprecated - Use deleteTaskDirectly instead
         */
        confirmDeleteTask(task) {
            if (!task) {
                this.showError("Invalid task data: Task object is missing");
                return;
            }

            // Try to find the task ID - same logic as editTask
            let taskId = null;
            if ("id" in task && task.id !== null && task.id !== undefined) {
                taskId = task.id;
            } else if (
                "task_id" in task &&
                task.task_id !== null &&
                task.task_id !== undefined
            ) {
                taskId = task.task_id;
            } else if (
                "ID" in task &&
                task.ID !== null &&
                task.ID !== undefined
            ) {
                taskId = task.ID;
            }

            if (taskId === null || taskId === undefined) {
                this.showError(
                    "Invalid task data: Task ID is missing. Please check the console for details."
                );
                return;
            }

            // This method is kept for backward compatibility but is no longer used
            this.deleteTaskDirectly(task);
        },

        /**
         * Delete a task directly from the table
         * @param {number|string} taskId - ID of the task to delete
         */
        async deleteTask(taskId) {
            try {
                if (!taskId) {
                    this.showError("Task ID is required");
                    return;
                }

                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("Member ID is required");
                    return;
                }

                // Ensure taskId is a number
                const taskIdNum = parseInt(taskId);
                if (isNaN(taskIdNum) || taskIdNum <= 0) {
                    this.showError(`Invalid task ID: ${taskId}`);
                    return;
                }

                const response = await axios.delete(
                    `members/${memberId}/tasks/${taskIdNum}`
                );

                if (response && response.data && response.data.success) {
                    this.showSuccess("Task deleted successfully!");
                    await this.fetchMemberTasks();
                } else {
                    const errorMsg =
                        response?.data?.message || "Failed to delete task";
                    this.showError(errorMsg);
                }
            } catch (error) {
                if (error.response) {
                    if (error.response.data && error.response.data.message) {
                        this.showError(error.response.data.message);
                    } else if (error.response.status === 404) {
                        this.showError(
                            "Task not found. It may have already been deleted."
                        );
                    } else if (error.response.status === 403) {
                        this.showError(
                            "You don't have permission to delete this task."
                        );
                    } else if (error.response.status === 401) {
                        this.showError(
                            "You are not authorized. Please log in again."
                        );
                    } else if (error.response.status === 500) {
                        this.showError(
                            "Server error occurred. Please try again later."
                        );
                    } else {
                        this.showError(
                            `Error deleting task: ${error.response.status} ${
                                error.response.statusText || "Unknown error"
                            }`
                        );
                    }
                } else if (error.request) {
                    this.showError(
                        "Network error. Please check your internet connection and try again."
                    );
                } else {
                    this.showError(
                        "An unexpected error occurred. Please try again."
                    );
                }
            }
        },

        /**
         * Mark a task as complete directly from the table
         * @param {object} task - Task object to mark as complete
         */
        async markTaskComplete(task) {
            try {
                if (!task) {
                    this.showError("Invalid task data: Task object is missing");
                    return;
                }

                const taskId = this.extractTaskId(task);

                if (taskId === null || taskId === undefined) {
                    // Check if the task has ID 0 specifically
                    if (task.id === 0 || task.task_id === 0 || task.ID === 0) {
                        this.showError(
                            "This task has an invalid ID (0). This indicates a database issue. Please refresh the page or contact support. The task may need to be recreated."
                        );
                    } else {
                        this.showError(
                            "Invalid task data: Task ID is missing or invalid. Please refresh the page and try again."
                        );
                    }
                    return;
                }

                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("Member ID is required");
                    return;
                }

                // taskId is already validated and converted to number in extractTaskId
                const taskIdNum = taskId;

                // Get current task data to preserve all fields
                const currentTask = this.memberTasks.find((t) => {
                    const tId = this.extractTaskId(t);
                    return tId === taskIdNum;
                });

                if (!currentTask) {
                    this.showError("Task not found in current list");
                    return;
                }

                // Prepare update data - preserve all existing fields, only change status
                // Backend expects camelCase for dueDate and assignedTo
                // Helper function to safely get field values with fallbacks
                const getFieldValue = (obj, field, snakeCaseField = null) => {
                    if (!obj) return null;
                    return (
                        obj[field] ||
                        (snakeCaseField ? obj[snakeCaseField] : null)
                    );
                };

                // Get values with proper fallbacks - try currentTask first, then task
                const getValue = (
                    field,
                    snakeCaseField = null,
                    defaultValue = null
                ) => {
                    const value =
                        getFieldValue(currentTask, field, snakeCaseField) ||
                        getFieldValue(task, field, snakeCaseField);
                    return value != null ? value : defaultValue;
                };

                // Ensure all required fields have valid values
                // Title is required
                let title = getValue("title", null, "Untitled Task");
                if (typeof title !== "string")
                    title = String(title || "Untitled Task");
                title = title.trim() || "Untitled Task";

                // Category is required
                let category = getValue("category", null, "Other");
                if (typeof category !== "string")
                    category = String(category || "Other");
                category = category.trim() || "Other";

                // Priority is required - normalize to proper case
                let priority = getValue("priority", null, "Medium");
                if (typeof priority !== "string")
                    priority = String(priority || "Medium");
                priority = priority.trim() || "Medium";
                // Normalize to match backend expectations (capitalize first letter)
                priority =
                    priority.charAt(0).toUpperCase() +
                    priority.slice(1).toLowerCase();

                // DueDate is required - try both camelCase and snake_case
                let dueDate = getValue("dueDate", "due_date", null);

                // If dueDate is missing, use today's date as default
                if (!dueDate) {
                    const today = new Date();
                    dueDate = today.toISOString().split("T")[0];
                } else {
                    // Format dueDate to ensure it's in YYYY-MM-DD format
                    const date = new Date(dueDate);
                    if (!isNaN(date.getTime())) {
                        dueDate = date.toISOString().split("T")[0];
                    } else {
                        // If date parsing fails, use today's date
                        const today = new Date();
                        dueDate = today.toISOString().split("T")[0];
                    }
                }

                // Description is optional
                let description = getValue("description", null, "");
                if (description != null && typeof description !== "string") {
                    description = String(description);
                }
                description = description || "";

                // AssignedTo is optional
                const assignedTo = getValue("assignedTo", "assigned_to", null);

                const taskData = {
                    title: title,
                    category: category,
                    priority: priority,
                    dueDate: dueDate,
                    description: description,
                    assignedTo: assignedTo,
                    status: "completed",
                    member_id: memberId, // Ensure member_id is set
                    task_type: "member", // Ensure task_type is set to 'member'
                };

                const response = await axios.put(
                    `members/${memberId}/tasks/${taskIdNum}`,
                    taskData
                );

                if (response && response.data && response.data.success) {
                    this.showSuccess("Task marked as complete!");
                    await this.fetchMemberTasks();
                } else {
                    const errorMsg =
                        response?.data?.message ||
                        "Failed to mark task as complete";
                    this.showError(errorMsg);
                }
            } catch (error) {
                if (error.response) {
                    // Handle validation errors
                    if (
                        error.response.status === 422 &&
                        error.response.data &&
                        error.response.data.errors
                    ) {
                        const errors = error.response.data.errors;
                        const errorMessages = Object.keys(errors)
                            .map((key) => {
                                const messages = Array.isArray(errors[key])
                                    ? errors[key]
                                    : [errors[key]];
                                return `${key}: ${messages.join(", ")}`;
                            })
                            .join(". ");
                        this.showError(`Validation failed: ${errorMessages}`);
                    } else if (
                        error.response.data &&
                        error.response.data.message
                    ) {
                        this.showError(error.response.data.message);
                    } else if (error.response.status === 404) {
                        this.showError(
                            "Task not found. It may have been deleted."
                        );
                    } else if (error.response.status === 403) {
                        this.showError(
                            "You don't have permission to update this task."
                        );
                    } else if (error.response.status === 401) {
                        this.showError(
                            "You are not authorized. Please log in again."
                        );
                    } else if (error.response.status === 500) {
                        this.showError(
                            "Server error occurred. Please try again later."
                        );
                    } else {
                        this.showError(
                            `Error marking task as complete: ${
                                error.response.status
                            } ${error.response.statusText || "Unknown error"}`
                        );
                    }
                } else if (error.request) {
                    this.showError(
                        "Network error. Please check your internet connection and try again."
                    );
                } else {
                    this.showError(
                        "An unexpected error occurred. Please try again."
                    );
                }
            }
        },

        /**
         * Fetch unsubscribe history for the member
         * Loads existing unsubscribe data if member is unsubscribed
         */
        async fetchUnsubscribeHistory() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    return;
                }

                const response = await axios.get(
                    `members/${memberId}/unsubscribe-history`
                );

                if (response.data.success && response.data.history) {
                    this.unsubscribeHistory = response.data.history;
                    this.isUnsubscribed = true;

                    // Pre-populate form with existing data
                    this.unsubscribeData = {
                        type: this.unsubscribeHistory.type,
                        effectiveDate: this.formatDateForInput(
                            this.unsubscribeHistory.effectiveDate
                        ),
                        reason: this.unsubscribeHistory.reason,
                        comments: this.unsubscribeHistory.comments || "",
                        refundOption: this.unsubscribeHistory.refundOption,
                    };
                } else {
                    this.isUnsubscribed = false;
                    this.unsubscribeHistory = null;
                    // Reset form for new unsubscribe
                    this.unsubscribeData = {
                        type: "",
                        effectiveDate: "",
                        reason: "",
                        comments: "",
                        refundOption: "",
                    };
                }
            } catch (error) {
                // If no history found, member is not unsubscribed
                this.isUnsubscribed = false;
                this.unsubscribeHistory = null;
                // Reset form for new unsubscribe
                this.unsubscribeData = {
                    type: "",
                    effectiveDate: "",
                    reason: "",
                    comments: "",
                    refundOption: "",
                };
            }
        },

        /**
         * Toggle unsubscribe edit mode
         * Allows editing of unsubscribe data or resubscribing
         */
        toggleUnsubscribeEdit() {
            this.isEditingUnsubscribe = !this.isEditingUnsubscribe;

            if (this.isEditingUnsubscribe && this.unsubscribeHistory) {
                // Pre-populate form with existing data for editing
                this.unsubscribeData = {
                    type: this.unsubscribeHistory.type,
                    effectiveDate: this.formatDateForInput(
                        this.unsubscribeHistory.effectiveDate
                    ),
                    reason: this.unsubscribeHistory.reason,
                    comments: this.unsubscribeHistory.comments || "",
                    refundOption: this.unsubscribeHistory.refundOption,
                };
            }
        },

        /**
         * Cancel unsubscribe edit mode
         */
        cancelUnsubscribeEdit() {
            this.isEditingUnsubscribe = false;
            // Reset form to original values
            if (this.unsubscribeHistory) {
                this.unsubscribeData = {
                    type: this.unsubscribeHistory.type,
                    effectiveDate: this.formatDateForInput(
                        this.unsubscribeHistory.effectiveDate
                    ),
                    reason: this.unsubscribeHistory.reason,
                    comments: this.unsubscribeHistory.comments || "",
                    refundOption: this.unsubscribeHistory.refundOption,
                };
            }
        },

        /**
         * Close unsubscribe modal
         */
        closeUnsubscribeModal() {
            this.activeAction = null;
            this.isEditingUnsubscribe = false;
        },

        /**
         * Process member unsubscribe request
         * Sends unsubscribe data to the server
         */
        async processUnsubscribe() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                const response = await axios.post(
                    `members/${memberId}/unsubscribe`,
                    this.unsubscribeData
                );

                if (response.data.success) {
                    this.showSuccess(
                        response.data.message ||
                            "Member unsubscribed successfully!"
                    );
                    this.isUnsubscribed = true;
                    this.isEditingUnsubscribe = false;

                    // Store the unsubscribe data as history
                    this.unsubscribeHistory = { ...this.unsubscribeData };

                    // Refresh member data to show updated status
                    await this.fetchmemberData();

                    // Close modal after successful unsubscribe
                    this.closeUnsubscribeModal();
                } else {
                    this.showError("Failed to unsubscribe member");
                }
            } catch (error) {
                this.showError("Error unsubscribing member. Please try again.");
            }
        },

        /**
         * Update unsubscribe data or resubscribe member
         * Handles both editing unsubscribe details and resubscribing
         */
        async updateUnsubscribe() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                const isResubscribing =
                    !this.unsubscribeData.type ||
                    !this.unsubscribeData.reason ||
                    !this.unsubscribeData.refundOption;

                const endpoint = isResubscribing
                    ? "resubscribe"
                    : "update-unsubscribe";
                const response = await axios.post(
                    `members/${memberId}/${endpoint}`,
                    this.unsubscribeData
                );

                if (response.data.success) {
                    if (isResubscribing) {
                        this.showSuccess("Member resubscribed successfully!");
                        this.isUnsubscribed = false;
                        this.unsubscribeHistory = null;
                        this.isEditingUnsubscribe = false;

                        // Reset form
                        this.unsubscribeData = {
                            type: "",
                            effectiveDate: "",
                            reason: "",
                            comments: "",
                            refundOption: "",
                        };
                    } else {
                        this.showSuccess(
                            "Unsubscribe details updated successfully!"
                        );
                        this.isEditingUnsubscribe = false;

                        // Update history with new data
                        this.unsubscribeHistory = { ...this.unsubscribeData };
                    }

                    // Refresh member data to show updated status
                    await this.fetchmemberData();

                    // Close modal after successful update
                    if (!isResubscribing) {
                        this.closeUnsubscribeModal();
                    }
                } else {
                    this.showError("Failed to update member status");
                }
            } catch (error) {
                this.showError(
                    "Error updating member status. Please try again."
                );
            }
        },

        /**
         * Resubscribe member
         * Cancels the unsubscribe and restores member to active status
         */
        async resubscribeMember() {
            try {
                const memberId = this.$route.params.id;
                if (!memberId) {
                    this.showError("No member ID found");
                    return;
                }

                const result = await this.$swal({
                    title: "Resubscribe Member?",
                    text: "Are you sure you want to resubscribe this member? This will cancel their unsubscribe status.",
                    icon: "question",
                    showCancelButton: true,
                    confirmButtonColor: "#28a745",
                    cancelButtonColor: "#6c757d",
                    confirmButtonText: "Yes, resubscribe",
                    cancelButtonText: "Cancel",
                });

                if (!result.isConfirmed) {
                    return;
                }

                const response = await axios.post(
                    `members/${memberId}/resubscribe`
                );

                if (response.data.success) {
                    this.showSuccess("Member resubscribed successfully!");
                    this.isUnsubscribed = false;
                    this.unsubscribeHistory = null;
                    this.isEditingUnsubscribe = false;

                    // Reset form
                    this.unsubscribeData = {
                        type: "",
                        effectiveDate: "",
                        reason: "",
                        comments: "",
                        refundOption: "",
                    };

                    // Refresh member data to show updated status
                    await this.fetchmemberData();

                    // Close modal after successful resubscribe
                    this.closeUnsubscribeModal();
                } else {
                    this.showError(
                        response.data.message || "Failed to resubscribe member"
                    );
                }
            } catch (error) {
                this.showError(
                    error.response?.data?.message ||
                        "Error resubscribing member. Please try again."
                );
            }
        },

        /**
         * Show success notification using SweetAlert
         * @param {string} message - Success message to display
         */
        showSuccess(message) {
            const bvToast = this.$root?.$bvToast || this.$bvToast;
            if (bvToast && typeof bvToast.toast === "function") {
                bvToast.toast(message, {
                    title: "Success",
                    variant: "success",
                    solid: true,
                    toaster: "b-toaster-top-right",
                    autoHideDelay: 1000,
                });
            } else {
                // Fallback to SweetAlert if toast is not available
                this.$swal({
                    icon: "success",
                    title: "Success!",
                    text: message,
                    timer: 1000,
                    showConfirmButton: false,
                });
            }
        },

        /**
         * Show error notification using BootstrapVue Toast
         * @param {string} message - Error message to display
         */
        showError(message) {
            const bvToast = this.$root?.$bvToast || this.$bvToast;
            if (bvToast && typeof bvToast.toast === "function") {
                bvToast.toast(message, {
                    title: "Error",
                    variant: "danger",
                    solid: true,
                    toaster: "b-toaster-top-right",
                    autoHideDelay: 1000,
                });
            } else {
                // Fallback to SweetAlert if toast is not available
                this.$swal({
                    icon: "error",
                    title: "Error!",
                    text: message,
                    timer: 1000,
                    showConfirmButton: false,
                });
            }
        },

        /**
         * Parse error messages from API responses into user-friendly messages
         * @param {Error} error - Error object from axios
         * @returns {string} - User-friendly error message
         */
        parseErrorMessage(error) {
            // Check if error has response data
            if (error && error.response && error.response.data) {
                const data = error.response.data;

                // Check for validation errors
                if (data.errors && typeof data.errors === "object") {
                    const errorMessages = Object.values(data.errors).flat();
                    return (
                        errorMessages.join(", ") ||
                        "Validation failed. Please check your input."
                    );
                }

                // Check for custom message
                if (data.message) {
                    const message = data.message;

                    // Parse SQL foreign key constraint errors
                    if (message.includes("foreign key constraint fails")) {
                        if (message.includes("subscription_plan_id")) {
                            return "The selected subscription plan is invalid or no longer exists. Please select a different plan.";
                        }
                        if (message.includes("FOREIGN KEY")) {
                            return "Invalid reference. One of the selected values is no longer available.";
                        }
                        return "Invalid data reference. Please check your selections and try again.";
                    }

                    // Parse SQL constraint violations
                    if (message.includes("Integrity constraint violation")) {
                        if (message.includes("1452")) {
                            return "Invalid reference. The selected value is no longer available in the system.";
                        }
                        if (message.includes("1062")) {
                            return "Duplicate entry. This value already exists.";
                        }
                        return "Data validation failed. Please check your input and try again.";
                    }

                    // Parse SQL syntax errors (shouldn't happen, but handle gracefully)
                    if (
                        message.includes("SQLSTATE") ||
                        message.includes("SQL:")
                    ) {
                        return "An error occurred while saving. Please try again or contact support if the problem persists.";
                    }

                    // Return the message as-is if it's already user-friendly
                    return message;
                }
            }

            // Fallback to generic error message
            if (error && error.message) {
                return error.message;
            }

            return "An unexpected error occurred. Please try again.";
        },

        /**
         * Show info notification using SweetAlert
         * @param {string} message - Info message to display
         */
        showInfo(message) {
            this.$swal({
                icon: "info",
                title: "Information",
                text: message,
                timer: 3000,
                showConfirmButton: false,
            });
        },

