        /**
         * Fetch member data from the server
         * Loads member information based on route parameter
         */
        async fetchmemberData() {
            try {
                const memberId = this.$route.params.id;

                if (!memberId) {
                    this.isLoading = false;
                    this.$swal({
                        title: "Error",
                        text: "No member ID provided. Please select a valid member.",
                        type: "error",
                    }).then(() => {
                        this.$router.push("/app/members/viewallmembers");
                    });
                    return;
                }

                // Validate member ID format
                if (isNaN(memberId) || memberId <= 0) {
                    this.isLoading = false;
                    this.$swal({
                        title: "Error",
                        text: "Invalid member ID format. Please select a valid member.",
                        type: "error",
                    }).then(() => {
                        this.$router.push("/app/members/viewallmembers");
                    });
                    return;
                }

                // Try the full-details endpoint first
                let response;
                try {
                    response = await axios.get(
                        `members/${memberId}/full-details`
                    );
                } catch (error) {
                    // Check if it's a 404 error
                    if (error.response && error.response.status === 404) {
                        throw new Error(`Member with ID ${memberId} not found`);
                    }
                    // Check if it's an authentication error
                    if (error.response && error.response.status === 401) {
                        throw new Error(
                            "Authentication failed. Please log in again."
                        );
                    }
                    // Check if it's a permission error
                    if (error.response && error.response.status === 403) {
                        throw new Error(
                            "You don't have permission to view this member."
                        );
                    }
                    // Check if it's a server error
                    if (error.response && error.response.status >= 500) {
                        throw new Error(
                            "Server error. Please try again later."
                        );
                    }
                    // Fallback to standard member endpoint
                    try {
                        response = await axios.get(`members/${memberId}`);
                    } catch (fallbackError) {
                        // Re-throw the original error with more context
                        throw new Error(
                            `Failed to load member data: ${
                                error.message || "Unknown error"
                            }`
                        );
                    }
                }

                if (!response || !response.data) {
                    this.isLoading = false;
                    return;
                }

                if (response.data.success) {
                    // Handle different response formats
                    let backendData;
                    if (response.data.client) {
                        backendData = response.data.client;
                    } else if (response.data.member) {
                        backendData = response.data.member;
                    } else if (response.data.data) {
                        backendData = response.data.data;
                    } else {
                        // If response.data is the member object directly
                        backendData = response.data;
                    }

                    if (!backendData) {
                        // No member data found in API response
                        this.isLoading = false;
                        return;
                    }

                    // Create a new member object with all the data
                    const newmember = {
                        id: backendData.id || "",
                        member_id: backendData.member_id || "",
                        first_name: backendData.first_name || "",
                        last_name: backendData.last_name || "",
                        firstname:
                            backendData.firstname ||
                            backendData.first_name ||
                            "",
                        lastname:
                            backendData.lastname || backendData.last_name || "",
                        name: backendData.membername || backendData.name || "",
                        sex: backendData.sex || backendData.gender || "",
                        birthday:
                            backendData.birthday ||
                            backendData.date_of_birth ||
                            "",
                        dob: backendData.dob || backendData.date_of_birth || "",
                        email: backendData.email || "",
                        mobile_phone:
                            backendData.mobile_phone || backendData.phone || "",
                        landline_phone:
                            backendData.landline_number ||
                            backendData.landline_phone ||
                            "",
                        status:
                            backendData.status ||
                            backendData.Statuses ||
                            "active",
                        address: backendData.address || "",
                        zip: backendData.zip || backendData.zipcode || "",
                        zipcode: backendData.zipcode || "",
                        city: backendData.city || "",
                        plan: backendData.plan || "",
                        subscription_plan_id: backendData.subscription_plan_id
                            ? parseInt(backendData.subscription_plan_id)
                            : backendData.plan
                            ? parseInt(backendData.plan)
                            : null,
                        start_date: backendData.start_date || "",
                        end_date:
                            backendData.end_date || backendData.Expires || "",
                        profile_image: backendData.profile_image || "",
                        height: backendData.height || "",
                        weight: backendData.weight || "",
                        preferred_length_unit:
                            backendData.preferred_length_unit || "inches",
                        preferred_weight_unit:
                            backendData.preferred_weight_unit || "pounds",
                        height_feet: backendData.height_feet || null,
                        height_inches: backendData.height_inches || null,
                        medical_condition:
                            backendData.medical_condition ||
                            backendData.medical ||
                            "",
                        medical:
                            backendData.medical ||
                            backendData.medical_condition ||
                            "",
                        contact_name: backendData.contact_name || "",
                        contact_phone: backendData.contact_phone || "",
                        emergency_name:
                            backendData.emergency_name ||
                            backendData.contact_name ||
                            "",
                        emergency_phone:
                            backendData.emergency_phone ||
                            backendData.contact_phone ||
                            "",
                        // Additional backend fields
                        membername: backendData.membername || "",
                        gender: backendData.gender || "",
                        date_of_birth: backendData.date_of_birth || "",
                        Expires: backendData.Expires || "",
                        Statuses: backendData.Statuses || "",
                        gym_id: backendData.gym_id || "",
                        created_at: backendData.created_at || "",
                        member_since: backendData.member_since || "",
                        tags: Array.isArray(backendData.tags)
                            ? backendData.tags
                            : backendData.tags
                            ? [backendData.tags]
                            : [],
                        language: backendData.language || "English",
                        own_member_id:
                            backendData.own_member_id !== null &&
                            backendData.own_member_id !== undefined
                                ? String(backendData.own_member_id)
                                : "",
                        custom_export_field:
                            backendData.custom_export_field !== null &&
                            backendData.custom_export_field !== undefined
                                ? String(backendData.custom_export_field)
                                : "",
                        subscription_reason:
                            backendData.subscription_reason || "Unknown",
                        source: backendData.source || "Unknown",
                        hasBusiness:
                            backendData.hasBusiness ||
                            backendData.is_business ||
                            (backendData.business_type &&
                            backendData.business_type !== "No"
                                ? "Yes"
                                : "No"),
                        is_business:
                            backendData.is_business ||
                            backendData.hasBusiness ||
                            (backendData.business_type &&
                            backendData.business_type !== "No"
                                ? "Yes"
                                : "No"),
                        business_type: backendData.business_type || "",
                        // Bank details
                        bank_account_number:
                            backendData.bank_account_number || "",
                        bank_account_type: backendData.bank_account_type || "",
                        bank_account_holder_name:
                            backendData.bank_account_holder_name || "",
                        bank_name: backendData.bank_name || "",
                        routing_number: backendData.routing_number || "",
                        mandate_id: backendData.mandate_id || "",
                        exclude_from_online_payments:
                            backendData.exclude_from_online_payments || false,
                        // Pro membership fields
                        pro_membership: backendData.pro_membership || false,
                        pro_start_date: backendData.pro_start_date || null,
                        pro_end_date: backendData.pro_end_date || null,
                    };

                    // Directly assign the new member object
                    this.member = { ...newmember };

                    // Format date fields for input display
                    this.formatDateFieldsForInput();

                    // Reload plans to ensure proper selection
                    if (this.plans.length === 0) {
                        this.loadPlans();
                    }

                    if (this.member.plan && !this.member.subscription_plan_id) {
                        this.member.subscription_plan_id = parseInt(
                            this.member.plan
                        );
                    }

                    // Populate settings form fields with member data
                    this.populateSettingsData();

                    this.isLoading = false;

                    // Load member notes after member data is successfully loaded
                    this.$nextTick(() => {
                        if (
                            this.loadMemberNotes &&
                            typeof this.loadMemberNotes === "function"
                        ) {
                            this.loadMemberNotes();
                        }
                    });
                } else {
                    this.isLoading = false;
                }
            } catch (error) {
                this.isLoading = false;

                // Show error message instead of redirecting
                this.$swal({
                    title: "Error Loading Member",
                    text: `Failed to load member data. Error: ${
                        error.message || "Unknown error"
                    }`,
                    type: "error",
                    showCancelButton: true,
                    confirmButtonText: "Retry",
                    cancelButtonText: "Go Back",
                }).then((result) => {
                    if (result.value) {
                        // Retry loading member data
                        this.fetchmemberData();
                    } else {
                        // Go back to members list
                        this.$router.push("/app/members/viewallmembers");
                    }
                });
            }
        },

        getmemberFromQueryParams() {
            const query = this.$route.query;

            // Try to get memberId from route params if not in query
            const memberId = query.memberId || this.$route.params.id;

            // Check if we have member data passed from ViewAllMembers
            if (query.memberData) {
                try {
                    const memberData = JSON.parse(query.memberData);

                    // Map the member data to our expected format
                    const newmember = {
                        id: memberData.id || memberId,
                        member_id: memberData.member_id || `M-${memberId}`,
                        firstname:
                            memberData.firstname || memberData.first_name || "",
                        lastname:
                            memberData.lastname || memberData.last_name || "",
                        first_name:
                            memberData.first_name || memberData.firstname || "",
                        last_name:
