    /**
     * Component lifecycle hook - called when component is created
     * Fetches initial member data
     */
    created() {
        // Store the initial route data immediately when component is created
        this.initialRouteData = {
            params: { ...this.$route.params },
            query: { ...this.$route.query },
        };

        // Cleaned: no global window hooks exposed

        // Check if activeAction is specified in query parameters
        if (this.$route.query.activeAction) {
            this.activeAction = this.$route.query.activeAction;
        } else if (
            this.$route.query.activeAction === null ||
            this.$route.query.activeAction === undefined
        ) {
            // Clear activeAction if explicitly set to null
            this.activeAction = null;
        }

        // Check if edit mode is requested via query parameter
        if (this.$route.query.editMode === "true") {
            this.isEditing = true;
        }

        // Check if a specific tab is requested via query parameter
        if (this.$route.query.tab) {
            this.activeTab = this.$route.query.tab;

            // If files tab is requested, ensure it's valid
            if (this.activeTab === "files") {
            }
        }

        // Use the stored data to fetch member data
        this.fetchmemberDataFromStoredData();
        // Load member tasks
        this.fetchMemberTasks();
        // Load plans
        this.loadPlans();
        // Load nutrition plans
        this.loadNutritionPlans();
        // Load available coaches for potential assignment
        this.loadAvailableCoaches();
        // Load existing coach assignment if any
        // Load available tags
        this.fetchAvailableTags();
        this.fetchCoachAssignment();
        // Load member files
        this.loadMemberFiles();
        // Load coaching profile
        this.loadCoachingProfile();
        // Load member notes - but only after member data is loaded
        // this.loadMemberNotes(); // Moved to be called after member data is loaded

        // Debug the initial state

        // Additional fallback: if no data is loaded after a delay, try query params
        setTimeout(() => {
            if (
                !this.member ||
                !this.member.id ||
                Object.keys(this.member).length === 0
            ) {
                this.getmemberFromQueryParams();
            }
        }, 500);

        // Add keyboard event listener for escape key
        document.addEventListener("keydown", this.handleEscapeKey);
    },
    beforeDestroy() {
        // Remove keyboard event listener
        document.removeEventListener("keydown", this.handleEscapeKey);
        // Restore body scroll in case modal was open
        document.body.style.overflow = "";
    },

    /**
     * Vue watchers for reactive data changes
     */
    watch: {
        /**
         * Watch for activeTab changes to load related data
         * @param {string} newTab - New active tab
         * @param {string} oldTab - Previous active tab
         */
        activeTab(newTab, oldTab) {
            console.log('activeTab changed from', oldTab, 'to', newTab);
            if (newTab === "notes") {
                console.log('Notes tab activated, loading notes...');
                console.log('Member data:', this.member);
                console.log('loadMemberNotes function:', typeof this.loadMemberNotes);
                // Call loadMemberNotes directly - it's defined in methods
                this.$nextTick(() => {
                    if (this.member && this.member.id) {
                        // Call the method directly
                        this.loadMemberNotes();
                    } else {
                        console.warn('Member data not available yet, will load notes when member data is ready');
                    }
                });
            }
        },
        /**
         * Watch for route parameter changes to reload member data
         * @param {string} newId - New member ID
         */
        "$route.params.id"(newId) {
            if (newId) {
                this.fetchmemberData();
            }
        },
        /**
         * Watch for active action changes to load related data
         * @param {string} newAction - New active action
         * @param {string} oldAction - Previous active action
         */
        activeAction(newAction, oldAction) {
            if (newAction === "assignTrainer") {
                this.fetchAvailableTrainers();
                this.fetchTrainerAssignment();
            } else if (oldAction === "assignTrainer") {
                // Reset trainer assignment flag when switching away
                this.hasExistingTrainerAssignment = false;
            } else if (newAction === "newTask") {
                this.fetchMemberTasks();
                // Prevent body scroll when modal is open
                document.body.style.overflow = "hidden";
            } else if (oldAction === "newTask" && newAction !== "newTask") {
                // Restore body scroll when modal is closed
                document.body.style.overflow = "";
            } else if (newAction === "unSubscribe") {
                this.fetchUnsubscribeHistory();
            } else if (newAction === "notes") {
                // Load notes when notes action is selected
                if (
                    this.loadMemberNotes &&
                    typeof this.loadMemberNotes === "function"
                ) {
                    this.loadMemberNotes();
                }
            }
            // Pre-fill nutrition form fields from member when opening Nutrition
            if (newAction === "nutrition" && this.member) {
                this.nutritionData.nutrition_plan =
                    this.member.nutrition_plan || "";
                this.nutritionData.start_date = this.member.start_date || "";
                this.nutritionData.end_date = this.member.end_date || "";
                // Load nutrition plans if not already loaded
                if (this.nutritionPlans.length === 0) {
                    this.loadNutritionPlans();
                }
                // Load member nutrition plans
                this.loadMemberNutritionPlans();
            }
        },

        /**
         * Watch for appointment modal state to prevent body scrolling
         * @param {boolean} isOpen - Whether the modal is open
         */
        showAppointmentModal(isOpen) {
            if (isOpen) {
                // Prevent body scroll when modal is open
                document.body.style.overflow = "hidden";
            } else {
                // Restore body scroll when modal is closed
                document.body.style.overflow = "";
            }
        },

        /**
         * Watch for active tab changes to load related data
         * @param {string} newTab - New active tab
         */
        activeTab(newTab) {
            if (newTab === "invoices") {
                this.loadMemberInvoices();
            } else if (newTab === "files") {
            } else if (newTab === "nutrition") {
                // Load nutrition plans if not already loaded
                if (this.nutritionPlans.length === 0) {
                    this.loadNutritionPlans();
                }
                // Load member nutrition plans
                this.loadMemberNutritionPlans();
            } else if (newTab === "Meal Plan") {
                // Load meal plans when tab is opened
                this.fetchMemberMealPlans();
            } else if (newTab === "settings") {
                // Load available coaches and existing assignment when settings tab is opened
                this.loadAvailableCoaches();
                this.fetchCoachAssignment();
                // Populate height and weight fields from member data
                this.populateSettingsData();
            } else if (newTab === "notes") {
                console.log('Notes tab activated, loading notes...');
                console.log('Member data:', this.member);
                if (
                    this.loadMemberNotes &&
                    typeof this.loadMemberNotes === "function"
                ) {
                    // Use nextTick to ensure DOM is updated
                    this.$nextTick(() => {
                        this.loadMemberNotes();
                    });
                } else {
                    console.error('loadMemberNotes function not found');
                }
            }
        },

        /**
         * Watch for newNote.description changes to debug
         */
        "newNote.description"(newText) {},

        /**
         * Watch for member data changes to load invoices when available
         */
        "member.id"(newId) {
            if (newId && this.activeTab === "invoices") {
                this.loadMemberInvoices();
            }
            if (newId && this.activeTab === "files") {
            }
            if (newId && this.activeTab === "notes") {
                if (
                    this.loadMemberNotes &&
                    typeof this.loadMemberNotes === "function"
                ) {
                    this.loadMemberNotes();
                }
            }
            // Load member nutrition plans when member ID becomes available
            if (newId) {
                this.loadMemberNutritionPlans();
            }
        },

        /**
         * Watch for progress metrics changes to calculate differences
         */
        progressMetrics: {
            handler(newMetrics) {
                newMetrics.forEach((metric) => {
                    this.calculateMetricChange(metric);
                });
            },
            deep: true,
        },

