        /**
         * Watch for subscription_plan_id changes to ensure proper selection
         */
        "member.subscription_plan_id"(newPlanId) {
            if (newPlanId && this.plans.length > 0) {
                const plan = this.plans.find(
                    (p) => p.id === parseInt(newPlanId)
                );
            }
            // Ensure plans are loaded if not already
            if (this.plans.length === 0) {
