        async loadMemberNutritionPlans() {
            this.isLoadingMemberNutritionPlans = true;
            try {
                // Add check for member existence and use route params as fallback
                const memberId =
                    (this.member && this.member.id) || this.$route.params.id;
                if (!memberId) {
                    this.memberNutritionPlans = [];
                    return;
                }

                // Use the same endpoint as Meal Plan tab to get all assigned plans
                const response = await axios.get(
                    `members/${memberId}/assigned-meal-plans`
                );

                if (response.data.success) {
                    // Transform the data to match the expected structure for Nutrition tab
                    this.memberNutritionPlans = (response.data.data || []).map(
                        (plan) => ({
                            id: plan.id,
                            nutrition_plan:
                                plan.template_name || plan.plan_name,
                            plan_name: plan.template_name || plan.plan_name,
                            start_date: plan.start_date,
                            end_date: plan.end_date,
                            duration:
                                plan.duration ||
                                this.calculateDuration(
                                    plan.start_date,
                                    plan.end_date
                                ),
                            description: plan.description || "",
                            status: this.getPlanStatus(
                                plan.start_date,
                                plan.end_date
                            ),
                            template_id: plan.template_id,
                        })
                    );
                } else {
                    this.memberNutritionPlans = [];
                }
            } catch (error) {
                this.memberNutritionPlans = [];
            } finally {
                this.isLoadingMemberNutritionPlans = false;
            }
        },

        /**
         * Get CSS class for nutrition plan status
         */
        getNutritionStatusClass(status) {
            const statusLower = (status || "active").toLowerCase();
            if (statusLower === "active") return "status-active";
            if (statusLower === "completed") return "status-completed";
            if (statusLower === "cancelled") return "status-cancelled";
            if (statusLower === "expired") return "status-expired";
            return "status-unknown";
        },

        /**
         * Edit nutrition plan
         */
        editNutritionPlan(plan) {
            this.nutritionData = {
                nutrition_plan: plan.nutrition_plan || plan.plan_name,
                start_date: plan.start_date,
                duration: plan.duration || "",
                description: plan.description || "",
                type: plan.type || "",
                status: plan.status || "active",
                price: plan.price || "0",
                paymentFrequency: plan.payment_frequency || "",
                features: plan.features || "No features",
                notes: plan.notes || "No notes",
            };

            // Scroll to nutrition form
            this.$nextTick(() => {
                const nutritionForm = document.querySelector(".nutrition-form");
                if (nutritionForm) {
                    nutritionForm.scrollIntoView({ behavior: "smooth" });
                }
            });
        },

        async deleteNote(noteId) {
            try {
                // Simulate API call - replace with actual API endpoint
                const noteIndex = this.notes.findIndex(
                    (note) => note.id === noteId
                );
                if (noteIndex !== -1) {
                    this.notes.splice(noteIndex, 1);
                    this.showSuccess("Note deleted successfully");
                }
            } catch (error) {
                this.showError("Failed to delete note");
            }
        },

        async loadMemberNotes() {
            // Don't load notes if member data is not available yet
            if (!this.member || !this.member.id) {
                console.warn('loadMemberNotes: Member data not available yet', {
                    hasMember: !!this.member,
                    memberId: this.member?.id,
                    routeParams: this.$route.params
                });
                this.isLoadingNotes = false;
                return;
            }

            this.isLoadingNotes = true;
            try {
                const memberId = this.member.id || this.$route.params.id;
                if (!memberId) {
                    console.error('loadMemberNotes: No member ID found');
                    this.notes = [];
                    this.isLoadingNotes = false;
                    return;
                }

                console.log('Loading notes for member ID:', memberId);
                console.log('Request URL:', `/notes/member/${memberId}`);
                console.log('Full URL will be:', window.location.origin + `/notes/member/${memberId}`);
                
                try {
                    // Use web route (same as coachdetails.vue) - override baseURL to use web routes
                    const response = await axios.get(`/notes/member/${memberId}`, {
                        baseURL: '', // Override axios default baseURL to use web routes instead of API routes
                        headers: {
                            'Accept': 'application/json',
                            'Content-Type': 'application/json',
                        }
                    });
                    console.log('Notes API response status:', response.status);
                    console.log('Notes API response:', response);
                    console.log('Notes API response data:', response.data);
                    const data = response.data;

                // Handle various response shapes
                const success =
                    data &&
                    (data.success === true ||
                        data.status === "success" ||
                        Array.isArray(data));

                const items = Array.isArray(data)
                    ? data
                    : data.data || data.notes || [];

                if (success && items) {
                    // Normalize notes structure
                    this.notes = items.map((note) => {
                        if (!note) return note;

                        const normalized = {
                            id: note.id,
                            description:
                                note.description ||
                                note.text ||
                                note.content ||
                                "",
                            category: note.category || "General",
                            created_at:
                                note.created_at ||
                                note.createdAt ||
                                new Date().toISOString(),
                            coach: note.coach || null,
                            creator: note.creator || null,
                            creator_name: null,
                        };

                        // Normalize creator_name for display
                        if (note.creator_name) {
                            normalized.creator_name = note.creator_name;
                        } else if (note.created_by_name) {
                            normalized.creator_name = note.created_by_name;
                        } else if (
                            normalized.coach &&
                            (normalized.coach.first_name ||
                                normalized.coach.last_name)
                        ) {
                            const first = normalized.coach.first_name || "";
                            const last = normalized.coach.last_name || "";
                            normalized.creator_name = `${first} ${last}`.trim();
                        }

                        return normalized;
                    });
                } else {
                    this.notes = [];
                }
                } catch (axiosError) {
                    // Re-throw to be caught by outer catch block
                    throw axiosError;
                }
            } catch (error) {
                console.error('Error loading notes:', error);
                console.error('Error response:', error.response);
                console.error('Error status:', error.response?.status);
                console.error('Error data:', error.response?.data);
                this.notes = [];
                const errorMessage =
                    error.response?.data?.message ||
                    error.message ||
                    "Failed to load notes";
                console.error('Error message:', errorMessage);
                
                // Show more detailed error
                if (error.response?.status === 404) {
                    this.showError('Notes endpoint not found. Please check the route configuration.');
                } else if (error.response?.status === 401) {
                    this.showError('Authentication required. Please log in again.');
                } else if (error.response?.status === 500) {
                    this.showError('Server error: ' + errorMessage);
                } else {
                    this.showError(errorMessage);
                }
            } finally {
                this.isLoadingNotes = false;
            }
        },

        formatNoteDate(dateString) {
            const date = new Date(dateString);
            return date.toLocaleDateString("en-US", {
                year: "numeric",
                month: "2-digit",
                day: "2-digit",
            });
        },

        formatNoteTime(dateString) {
            const date = new Date(dateString);
            return date.toLocaleTimeString("en-US", {
                hour: "2-digit",
                minute: "2-digit",
                hour12: false,
            });
        },

