                    concerns: this.taskModalData.concerns.trim(),
                    assign_to: this.taskModalData.assignTo,
                    is_complete: this.taskModalData.isComplete,
                    due_date: this.taskModalData.dueDate,
                    time: this.taskModalData.time,
                    duration: this.taskModalData.duration,
                    created_at: new Date().toISOString(),
                };

                this.memberTasks.unshift({
                    id: Date.now(), // Temporary ID
                    ...taskData,
                    created_by: "Current User", // Replace with actual user
                    updated_at: taskData.created_at,
                });

                this.showSuccess("Task created successfully");
                this.closeTaskModal();
            } catch (error) {
                this.showError("Failed to save task");
            } finally {
                this.isSavingTask = false;
            }
        },

        /**
         * Get filtered employees for assignment dropdown
         */
        getFilteredEmployees() {
            if (!this.taskModalData.assignTo) return this.availableEmployees;
            return this.availableEmployees.filter((employee) =>
                employee.name
                    .toLowerCase()
                    .includes(this.taskModalData.assignTo.toLowerCase())
            );
        },

        /**
         * Handle escape key to close modal
         */
        handleEscapeKey(event) {
            if (event.key === "Escape" && this.showTaskModal) {
                this.closeTaskModal();
            }
        },

        /**
         * Format date for display
         */
        formatDate(dateString) {
            if (!dateString) return "";
            const date = new Date(dateString);
            return date.toLocaleDateString("en-US", {
                weekday: "long",
                year: "numeric",
                month: "long",
                day: "numeric",
            });
        },
    },
};
</script>

